    function escapeHtml(value) {
      if (value === null || value === undefined) return '';
      return String(value)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#39;');
    }

    function buildWorkspaceEmptyState(options = {}) {
      const icon = String(options.icon || 'inbox').trim() || 'inbox';
      const title = String(options.title || 'Aucun element').trim() || 'Aucun element';
      const text = String(options.text || '').trim();
      const ctaLabel = String(options.ctaLabel || '').trim();
      const ctaOnclick = String(options.ctaOnclick || '').trim();
      const ctaId = String(options.ctaId || '').trim();
      const compactClass = options.compact ? ' workspace-empty-state-compact' : '';
      const ctaHtml = ctaLabel
        ? `<button type="button" class="workspace-empty-cta" ${ctaId ? `id="${escapeHtml(ctaId)}"` : ''} ${ctaOnclick ? `onclick="${escapeHtml(ctaOnclick)}"` : ''}>${escapeHtml(ctaLabel)}</button>`
        : '';
      return `
        <div class="workspace-empty-state${compactClass}" role="status" aria-live="polite">
          <span class="workspace-empty-icon material-symbols-outlined" aria-hidden="true">${escapeHtml(icon)}</span>
          <p class="workspace-empty-title">${escapeHtml(title)}</p>
          ${text ? `<p class="workspace-empty-text">${escapeHtml(text)}</p>` : ''}
          ${ctaHtml}
        </div>
      `;
    }

    function renderProjectMembersSummary(state, maxVisible = 3) {
      const members = Array.isArray(state?.members) ? state.members : [];
      const normalized = [];
      const seen = new Set();
      members.forEach((member) => {
        const uid = String(member?.userId || '').trim();
        if (!uid || seen.has(uid)) return;
        seen.add(uid);
        normalized.push(resolveKnownUserIdentity(uid, String(member?.displayName || '').trim()));
      });
      if (normalized.length === 0 && state?.project?.createdBy) {
        normalized.push(resolveKnownUserIdentity(state.project.createdBy, 'Utilisateur'));
      }
      const count = normalized.length;
      const countLabel = `${count} membre${count > 1 ? 's' : ''}`;
      if (count === 0) {
        return `<span class="project-members-summary"><span class="project-members-summary-count">${escapeHtml(countLabel)}</span></span>`;
      }
      const visible = normalized.slice(0, Math.max(1, maxVisible));
      const names = normalized.map((p) => p.name).filter(Boolean);
      const nameLabel = names.slice(0, 2).join(', ') + (names.length > 2 ? ` +${names.length - 2}` : '');
      const chipsHtml = visible.map((p, idx) => {
        const style = safeAvatarInlineStyle(
          p.avatarDataUrl,
          stringToColor(p.userId || p.name || String(idx))
        );
        return `<span class="participant-chip" style="${style}" aria-label="${escapeHtml(p.name)}">${escapeHtml(getInitials(p.name))}</span>`;
      }).join('');
      return `
        <span class="project-members-summary" title="${escapeHtml(names.join(', '))}">
          <span class="participants-stack">${chipsHtml}</span>
          <span class="project-members-summary-names">${escapeHtml(nameLabel)}</span>
          <span class="project-members-summary-count">(${escapeHtml(countLabel)})</span>
        </span>
      `;
    }

    function getProfanityFilterMode() {
      const raw = String(localStorage.getItem(PROFANITY_FILTER_MODE_STORAGE_KEY) || '').trim().toLowerCase();
      return PROFANITY_FILTER_MODES.has(raw) ? raw : PROFANITY_FILTER_DEFAULT_MODE;
    }

    function toBase64Utf8(value) {
      try {
        const utf8 = encodeURIComponent(String(value || '')).replace(/%([0-9A-F]{2})/g, (_m, h) => String.fromCharCode(parseInt(h, 16)));
        return btoa(utf8);
      } catch {
        return '';
      }
    }

    function applyProfanityAction(match, replacement, mode) {
      if (!match) return '';
      if (mode === 'remove') return '';
      if (mode === 'encrypt') {
        const encoded = toBase64Utf8(match);
        return encoded ? `[crypte:${encoded}]` : '[crypte]';
      }
      return replacement;
    }

    function applyProfanityFilterToText(value, modeOverride = '', options = {}) {
      const mode = String(modeOverride || getProfanityFilterMode()).trim().toLowerCase();
      const preserveSpacing = options?.preserveSpacing === true;
      let output = String(value || '');
      if (!output || mode === 'off') return output;
      PROFANITY_RULES.forEach((rule) => {
        if (!(rule?.regex instanceof RegExp)) return;
        output = output.replace(rule.regex, (match) => applyProfanityAction(match, String(rule.replacement || ''), mode));
      });
      if (preserveSpacing) return output;
      return output
        .replace(/[ \t]{2,}/g, ' ')
        .replace(/\s+([,.;:!?])/g, '$1')
        .trim();
    }

    function applyProfanityFilterToHtml(htmlInput, modeOverride = '') {
      const rawHtml = String(htmlInput || '');
      if (!rawHtml) return '';
      const mode = String(modeOverride || getProfanityFilterMode()).trim().toLowerCase();
      if (mode === 'off') return rawHtml;
      const doc = new DOMParser().parseFromString(`<div>${rawHtml}</div>`, 'text/html');
      const root = doc.body.firstElementChild;
      if (!root) return '';
      const walker = doc.createTreeWalker(root, NodeFilter.SHOW_TEXT);
      const toPatch = [];
      while (walker.nextNode()) {
        const node = walker.currentNode;
        const parentTag = String(node?.parentElement?.tagName || '').toLowerCase();
        if (parentTag === 'code' || parentTag === 'pre') continue;
        const before = String(node?.textContent || '');
        const after = applyProfanityFilterToText(before, mode, { preserveSpacing: true });
        if (after !== before) {
          toPatch.push({ node, text: after });
        }
      }
      toPatch.forEach((entry) => {
        entry.node.textContent = entry.text;
      });
      return root.innerHTML;
    }

    async function rerenderAfterProfanityModeChange() {
      if (workspaceMode === 'global') {
        if (globalWorkspaceView === 'messages') await renderGlobalMessages({ keepThreadAnchor: true });
        if (globalWorkspaceView === 'feed') await renderGlobalFeed();
        if (globalWorkspaceView === 'settings') await renderGlobalSettings();
      }
      if (workspaceMode === 'project' && currentProjectState?.project) {
        renderProjectDescription(currentProjectState.project.description || '');
        renderMessages(currentProjectState.messages || []);
        if (activeProjectView === 'list') {
          renderTasks(currentProjectState.tasks || []);
        }
      }
    }

    function setProfanityFilterMode(mode) {
      const next = String(mode || '').trim().toLowerCase();
      if (!PROFANITY_FILTER_MODES.has(next)) {
        showToast('Mode de filtre inconnu. Utilisez: off, remove, convert, encrypt.');
        return;
      }
      localStorage.setItem(PROFANITY_FILTER_MODE_STORAGE_KEY, next);
      const selectEl = document.getElementById('profanity-filter-mode-select');
      const currentEl = document.getElementById('profanity-filter-mode-current');
      if (selectEl) selectEl.value = next;
      if (currentEl) currentEl.textContent = `Mode actuel: ${next}`;
      showToast(`Filtre de vulgarites: ${next}`);
      rerenderAfterProfanityModeChange();
    }
    window.setProfanityFilterMode = setProfanityFilterMode;
    window.getProfanityFilterMode = getProfanityFilterMode;

    function extractDataUrlMimeType(url) {
      const raw = String(url || '').trim();
      if (!raw.toLowerCase().startsWith('data:')) return '';
      const withoutPrefix = raw.slice(5);
      const sepIdx = withoutPrefix.search(/[;,]/);
      const mime = (sepIdx >= 0 ? withoutPrefix.slice(0, sepIdx) : withoutPrefix).trim().toLowerCase();
      return mime;
    }

    function isDangerousUrlScheme(url) {
      const lower = String(url || '').trim().toLowerCase();
      return lower.startsWith('javascript:') || lower.startsWith('vbscript:');
    }

    function sanitizeUrlForDom(url, options = {}) {
      const raw = String(url || '').trim();
      if (!raw) return '';
      if (isDangerousUrlScheme(raw)) return '';
      const lower = raw.toLowerCase();
      const allowHttp = options.allowHttp !== false;
      const allowBlob = options.allowBlob !== false;
      const allowData = options.allowData !== false;
      const allowDataMimePrefixes = Array.isArray(options.allowDataMimePrefixes)
        ? options.allowDataMimePrefixes.map((v) => String(v || '').toLowerCase()).filter(Boolean)
        : [];

      if (lower.startsWith('https://') || lower.startsWith('http://')) {
        return allowHttp ? raw : '';
      }
      if (lower.startsWith('blob:')) {
        return allowBlob ? raw : '';
      }
      if (lower.startsWith('data:')) {
        if (!allowData) return '';
        const mime = extractDataUrlMimeType(raw);
        if (!mime) return '';
        if (allowDataMimePrefixes.length === 0) return raw;
        const ok = allowDataMimePrefixes.some((prefix) => mime.startsWith(prefix));
        return ok ? raw : '';
      }
      return '';
    }

    function sanitizeAvatarDataUrl(url) {
      return sanitizeUrlForDom(url, {
        allowHttp: true,
        allowBlob: true,
        allowData: true,
        allowDataMimePrefixes: ['image/']
      });
    }

    function safeAvatarInlineStyle(url, fallbackColor) {
      const safeUrl = sanitizeAvatarDataUrl(url);
      if (safeUrl) {
        const escapedUrl = safeUrl.replace(/'/g, '%27').replace(/"/g, '%22');
        return `background-image:url('${escapedUrl}'); background-size:cover; background-position:center; color:transparent;`;
      }
      return `background:${fallbackColor};`;
    }

    function sanitizeDownloadHref(url, mimeHint = '') {
      const hints = [String(mimeHint || '').toLowerCase()];
      return sanitizeUrlForDom(url, {
        allowHttp: true,
        allowBlob: true,
        allowData: true,
        allowDataMimePrefixes: [
          ...hints.filter(Boolean),
          'application/octet-stream',
          'application/pdf',
          'image/',
          'text/',
          'application/msword',
          'application/vnd',
          'application/rtf',
          'application/zip'
        ]
      });
    }

    const LOCK_SCOPE_TASK = 'task';
    const LOCK_SCOPE_PROJECT = 'project';
    const LOCK_SCOPE_CALENDAR = 'calendar-item';
    const CALENDAR_LOCKS_SETTINGS_KEY = 'calendar_resource_locks';
    let activeTaskEditLock = null;
    let activeProjectEditLock = null;
    let activeCalendarEditLock = null;

    function buildResourceLockKey(resourceType, resourceId) {
      return `${String(resourceType || '').trim()}:${String(resourceId || '').trim()}`;
    }

    function getCurrentUserLockDisplayName() {
      return String(currentUser?.name || fallbackDirectoryName(currentUser?.userId || '') || 'Utilisateur').trim();
    }

    function normalizeResourceLockRow(lock, now = Date.now()) {
      if (!lock || typeof lock !== 'object') return null;
      const resourceType = String(lock.resourceType || '').trim();
      const resourceId = String(lock.resourceId || '').trim();
      const ownerUserId = String(lock.ownerUserId || '').trim();
      const expiresAt = Number(lock.expiresAt || 0);
      if (!resourceType || !resourceId || !ownerUserId) return null;
      if (!Number.isFinite(expiresAt) || expiresAt <= now) return null;
      return {
        resourceType,
        resourceId,
        lockId: String(lock.lockId || '').trim(),
        ownerUserId,
        ownerName: String(lock.ownerName || '').trim(),
        scope: String(lock.scope || '').trim(),
        updatedAt: Number(lock.updatedAt || now) || now,
        expiresAt
      };
    }

    function getProjectResourceLock(state, resourceType, resourceId, options = {}) {
      const lockKey = buildResourceLockKey(resourceType, resourceId);
      const source = (state?.resourceLocks && typeof state.resourceLocks === 'object') ? state.resourceLocks : {};
      const normalized = normalizeResourceLockRow(source[lockKey], Number(options.now || Date.now()));
      return normalized;
    }

    function isProjectResourceLockedByOther(state, resourceType, resourceId, userId = currentUser?.userId) {
      const lock = getProjectResourceLock(state, resourceType, resourceId);
      if (!lock) return false;
      return String(lock.ownerUserId || '') !== String(userId || '');
    }

    function formatLockOwner(lock) {
      if (!lock) return 'Un autre utilisateur';
      const name = String(lock.ownerName || '').trim();
      if (name) return name;
      return fallbackDirectoryName(lock.ownerUserId || '') || 'Un autre utilisateur';
    }

    function buildProjectLockHintHtml(state, resourceType, resourceId, compact = false) {
      const lock = getProjectResourceLock(state, resourceType, resourceId);
      if (!lock || String(lock.ownerUserId || '') === String(currentUser?.userId || '')) return '';
      const owner = escapeHtml(formatLockOwner(lock));
      const minutesLeft = Math.max(1, Math.ceil((Number(lock.expiresAt || 0) - Date.now()) / 60000));
      if (compact) {
        return `<span class="text-[10px] px-2 py-0.5 rounded-full bg-amber-100 text-amber-800 font-semibold" title="${owner} modifie en ce moment">${owner} modifie…</span>`;
      }
      return `<div class="text-xs mt-2 px-2 py-1 rounded-lg bg-amber-50 text-amber-800 border border-amber-200">${owner} modifie en ce moment (${minutesLeft} min max).</div>`;
    }

    async function publishProjectLockEvent(projectId, type, payload) {
      if (!projectId) return;
      const event = createEvent(type, projectId, currentUser.userId, payload);
      await publishEvent(event);
      if (sharedFolderHandle) { void syncProjectEventsToSharedSpace(projectId, [event]); }
    }

    async function acquireProjectResourceLock(projectId, resourceType, resourceId, options = {}) {
      const pid = String(projectId || '').trim();
      const rid = String(resourceId || '').trim();
      const rtype = String(resourceType || '').trim();
      if (!pid || !rid || !rtype) return { ok: false, reason: 'invalid' };
      const state = await getProjectState(pid, { ignoreAccessCheck: true });
      const existing = getProjectResourceLock(state, rtype, rid);
      if (existing && String(existing.ownerUserId || '') !== String(currentUser?.userId || '')) {
        return { ok: false, reason: 'locked-by-other', lock: existing };
      }
      const lockId = String(options.lockId || '').trim() || uuidv4();
      const ttlMs = Math.max(60 * 1000, Math.min(30 * 60 * 1000, Number(options.ttlMs || DEFAULT_LOCK_TTL_MS) || DEFAULT_LOCK_TTL_MS));
      await publishProjectLockEvent(pid, EventTypes.LOCK_RESOURCE, {
        resourceType: rtype,
        resourceId: rid,
        lockId,
        scope: String(options.scope || '').trim(),
        ownerUserId: currentUser.userId,
        ownerName: getCurrentUserLockDisplayName(),
        ttlMs
      });
      return { ok: true, lockId };
    }

    async function releaseProjectResourceLock(projectId, resourceType, resourceId, lockId = '') {
      const pid = String(projectId || '').trim();
      const rid = String(resourceId || '').trim();
      const rtype = String(resourceType || '').trim();
      if (!pid || !rid || !rtype) return false;
      await publishProjectLockEvent(pid, EventTypes.UNLOCK_RESOURCE, {
        resourceType: rtype,
        resourceId: rid,
        lockId: String(lockId || '').trim(),
        ownerUserId: currentUser.userId
      });
      return true;
    }

    function buildLockBlockedMessage(lock, fallback = "Ressource en cours d'édition") {
      const owner = formatLockOwner(lock);
      return `${owner} modifie en ce moment. Réessayez dans un instant.`;
    }

    function ensureProjectResourceUnlockedForAction(state, resourceType, resourceId, actionLabel = 'action') {
      const lock = getProjectResourceLock(state, resourceType, resourceId);
      if (!lock) return { ok: true, lock: null };
      if (String(lock.ownerUserId || '') === String(currentUser?.userId || '')) {
        return { ok: true, lock };
      }
      showToast(`${formatLockOwner(lock)} modifie en ce moment. ${actionLabel} temporairement bloquée.`);
      return { ok: false, lock };
    }

    async function getCalendarLocksMap() {
      const row = await getDecrypted('appSettings', CALENDAR_LOCKS_SETTINGS_KEY, 'key');
      const map = (row && typeof row.value === 'object' && row.value) ? row.value : {};
      return pruneResourceLocksMap(map);
    }

    async function saveCalendarLocksMap(lockMap) {
      const cleaned = pruneResourceLocksMap(lockMap);
      await putEncrypted('appSettings', {
        key: CALENDAR_LOCKS_SETTINGS_KEY,
        value: cleaned,
        updatedAt: Date.now()
      }, 'key');
    }

    async function acquireCalendarItemLock(itemId) {
      const id = String(itemId || '').trim();
      if (!id) return { ok: false, reason: 'invalid' };
      const lockKey = buildResourceLockKey(LOCK_SCOPE_CALENDAR, id);
      const locks = await getCalendarLocksMap();
      const existing = normalizeResourceLockRow(locks[lockKey]);
      if (existing && String(existing.ownerUserId || '') !== String(currentUser?.userId || '')) {
        return { ok: false, reason: 'locked-by-other', lock: existing };
      }
      const lockId = uuidv4();
      locks[lockKey] = {
        resourceType: LOCK_SCOPE_CALENDAR,
        resourceId: id,
        lockId,
        ownerUserId: currentUser.userId,
        ownerName: getCurrentUserLockDisplayName(),
        scope: 'calendar',
        updatedAt: Date.now(),
        expiresAt: Date.now() + DEFAULT_LOCK_TTL_MS
      };
      await saveCalendarLocksMap(locks);
      return { ok: true, lockId };
    }

    async function releaseCalendarItemLock(itemId, lockId = '') {
      const id = String(itemId || '').trim();
      if (!id) return false;
      const lockKey = buildResourceLockKey(LOCK_SCOPE_CALENDAR, id);
      const locks = await getCalendarLocksMap();
      const existing = normalizeResourceLockRow(locks[lockKey]);
      if (!existing) return false;
      if (String(existing.ownerUserId || '') !== String(currentUser?.userId || '')) return false;
      if (lockId && String(existing.lockId || '') !== String(lockId || '')) return false;
      delete locks[lockKey];
      await saveCalendarLocksMap(locks);
      return true;
    }

    async function ensureCalendarItemUnlockedForAction(itemId, actionLabel = 'Action') {
      const id = String(itemId || '').trim();
      if (!id) return { ok: true };
      const locks = await getCalendarLocksMap();
      const lock = normalizeResourceLockRow(locks[buildResourceLockKey(LOCK_SCOPE_CALENDAR, id)]);
      if (!lock || String(lock.ownerUserId || '') === String(currentUser?.userId || '')) {
        return { ok: true, lock };
      }
      showToast(`${formatLockOwner(lock)} modifie cette information. ${actionLabel} temporairement bloquée.`);
      return { ok: false, lock };
    }

    function formatDate(dateValue) {
      if (!dateValue) return 'Non définie';
      const date = new Date(dateValue);
      if (Number.isNaN(date.getTime())) return 'Non définie';
      return date.toLocaleDateString('fr-FR');
    }

    function normalizeDeadlineMode(value, fallback = 'date') {
      const raw = String(value || '').trim().toLowerCase();
      if (raw === 'date' || raw === 'month' || raw === 'year' || raw === 'period') return raw;
      return fallback;
    }

    function normalizeDeadlineMonth(rawValue) {
      const raw = String(rawValue || '').trim();
      return /^\d{4}-\d{2}$/.test(raw) ? raw : '';
    }

    function normalizeDeadlineYear(rawValue) {
      const raw = String(rawValue || '').trim();
      if (!/^\d{4}$/.test(raw)) return '';
      const num = Number(raw);
      if (!Number.isFinite(num) || num < 1900 || num > 2200) return '';
      return String(num);
    }

    function normalizeTaskOrProjectDeadline(rawValue, fallbackDueDate = '') {
      const raw = rawValue && typeof rawValue === 'object' ? rawValue : {};
      const modeFromRaw = raw.deadlineMode || raw.mode || '';
      const inferredMode = modeFromRaw
        || (raw.deadlineMonth ? 'month' : '')
        || (raw.deadlineYear ? 'year' : '')
        || ((raw.deadlineStart || raw.deadlineEnd) ? 'period' : '')
        || 'date';
      const mode = normalizeDeadlineMode(inferredMode, 'date');
      const date = normalizeCalendarYmd(raw.deadlineDate || raw.date || raw.deadlineAt || '');
      const month = normalizeDeadlineMonth(raw.deadlineMonth || raw.month || '');
      const year = normalizeDeadlineYear(raw.deadlineYear || raw.year || '');
      const start = normalizeCalendarYmd(raw.deadlineStart || raw.periodStart || raw.start || '');
      const end = normalizeCalendarYmd(raw.deadlineEnd || raw.periodEnd || raw.end || '');
      const fallbackDate = normalizeCalendarYmd(fallbackDueDate || raw.dueDate || '');
      let dueDate = '';
      if (mode === 'date') {
        dueDate = date || fallbackDate;
      } else if (mode === 'month') {
        if (month) {
          const [yy, mm] = month.split('-').map((v) => Number(v));
          const lastDay = new Date(yy, mm, 0).getDate();
          dueDate = `${month}-${String(lastDay).padStart(2, '0')}`;
        }
      } else if (mode === 'year') {
        if (year) dueDate = `${year}-12-31`;
      } else if (mode === 'period') {
        dueDate = end || start || fallbackDate;
      }
      if (!dueDate) dueDate = fallbackDate || '';
      const orderedStart = start && end && end < start ? end : start;
      const orderedEnd = start && end && end < start ? start : end;
      return {
        mode,
        date,
        month,
        year,
        start: orderedStart || '',
        end: orderedEnd || '',
        dueDate: normalizeCalendarYmd(dueDate)
      };
    }

    function formatDeadlineLabel(deadlineLike, fallbackDueDate = '') {
      const normalized = normalizeTaskOrProjectDeadline(deadlineLike, fallbackDueDate);
      if (normalized.mode === 'month' && normalized.month) {
        const d = new Date(`${normalized.month}-01T00:00:00`);
        if (!Number.isNaN(d.getTime())) {
          return d.toLocaleDateString('fr-FR', { month: 'long', year: 'numeric' });
        }
      }
      if (normalized.mode === 'year' && normalized.year) {
        return normalized.year;
      }
      if (normalized.mode === 'period' && (normalized.start || normalized.end)) {
        if (normalized.start && normalized.end) return `${formatDate(normalized.start)} → ${formatDate(normalized.end)}`;
        if (normalized.start) return `À partir du ${formatDate(normalized.start)}`;
        if (normalized.end) return `Jusqu'au ${formatDate(normalized.end)}`;
      }
      if (normalized.date) return formatDate(normalized.date);
      if (normalized.dueDate) return formatDate(normalized.dueDate);
      return 'Non définie';
    }

    function formatTaskDeadline(task) {
      return formatDeadlineLabel(task, task?.dueDate || '');
    }

    function formatProjectDeadline(project) {
      return formatDeadlineLabel(project, project?.deadlineAt || '');
    }

    function setTaskDeadlineModeUi(modeValue = 'date') {
      const mode = normalizeDeadlineMode(modeValue, 'date');
      const dateWrap = document.getElementById('task-deadline-date-wrap');
      const monthWrap = document.getElementById('task-deadline-month-wrap');
      const yearWrap = document.getElementById('task-deadline-year-wrap');
      const periodWrap = document.getElementById('task-deadline-period-wrap');
      if (dateWrap) dateWrap.classList.toggle('hidden', mode !== 'date');
      if (monthWrap) monthWrap.classList.toggle('hidden', mode !== 'month');
      if (yearWrap) yearWrap.classList.toggle('hidden', mode !== 'year');
      if (periodWrap) periodWrap.classList.toggle('hidden', mode !== 'period');
    }

    function setProjectDeadlineModeUi(prefix = 'project', modeValue = 'date') {
      const base = String(prefix || 'project').trim() === 'edit-project' ? 'edit-project' : 'project';
      const mode = normalizeDeadlineMode(modeValue, 'date');
      const dateWrap = document.getElementById(`${base}-deadline-date-wrap`);
      const monthWrap = document.getElementById(`${base}-deadline-month-wrap`);
      const yearWrap = document.getElementById(`${base}-deadline-year-wrap`);
      const periodWrap = document.getElementById(`${base}-deadline-period-wrap`);
      if (dateWrap) dateWrap.classList.toggle('hidden', mode !== 'date');
      if (monthWrap) monthWrap.classList.toggle('hidden', mode !== 'month');
      if (yearWrap) yearWrap.classList.toggle('hidden', mode !== 'year');
      if (periodWrap) periodWrap.classList.toggle('hidden', mode !== 'period');
    }

    function readTaskDeadlineFromForm() {
      const mode = normalizeDeadlineMode(document.getElementById('task-deadline-mode')?.value || 'date', 'date');
      const date = normalizeCalendarYmd(document.getElementById('task-due-date')?.value || '');
      const month = normalizeDeadlineMonth(document.getElementById('task-deadline-month')?.value || '');
      const year = normalizeDeadlineYear(document.getElementById('task-deadline-year')?.value || '');
      const start = normalizeCalendarYmd(document.getElementById('task-deadline-period-start')?.value || '');
      const end = normalizeCalendarYmd(document.getElementById('task-deadline-period-end')?.value || '');
      const normalized = normalizeTaskOrProjectDeadline({
        deadlineMode: mode,
        deadlineDate: date,
        deadlineMonth: month,
        deadlineYear: year,
        deadlineStart: start,
        deadlineEnd: end
      });
      return {
        deadlineMode: normalized.mode,
        deadlineDate: normalized.date || null,
        deadlineMonth: normalized.month || null,
        deadlineYear: normalized.year || null,
        deadlineStart: normalized.start || null,
        deadlineEnd: normalized.end || null,
        dueDate: normalized.dueDate || null
      };
    }

    function populateTaskDeadlineForm(task = null) {
      const normalized = normalizeTaskOrProjectDeadline(task, task?.dueDate || '');
      const modeInput = document.getElementById('task-deadline-mode');
      const dateInput = document.getElementById('task-due-date');
      const monthInput = document.getElementById('task-deadline-month');
      const yearInput = document.getElementById('task-deadline-year');
      const startInput = document.getElementById('task-deadline-period-start');
      const endInput = document.getElementById('task-deadline-period-end');
      if (modeInput) modeInput.value = normalized.mode;
      if (dateInput) dateInput.value = normalized.date || normalized.dueDate || '';
      if (monthInput) monthInput.value = normalized.month || '';
      if (yearInput) yearInput.value = normalized.year || '';
      if (startInput) startInput.value = normalized.start || '';
      if (endInput) endInput.value = normalized.end || '';
      setTaskDeadlineModeUi(normalized.mode);
    }

    function readProjectDeadlineFromForm(prefix = 'project') {
      const base = String(prefix || 'project').trim() === 'edit-project' ? 'edit-project' : 'project';
      const mode = normalizeDeadlineMode(document.getElementById(`${base}-deadline-mode`)?.value || 'date', 'date');
      const date = normalizeCalendarYmd(document.getElementById(`${base}-deadline-date`)?.value || '');
      const month = normalizeDeadlineMonth(document.getElementById(`${base}-deadline-month`)?.value || '');
      const year = normalizeDeadlineYear(document.getElementById(`${base}-deadline-year`)?.value || '');
      const start = normalizeCalendarYmd(document.getElementById(`${base}-deadline-period-start`)?.value || '');
      const end = normalizeCalendarYmd(document.getElementById(`${base}-deadline-period-end`)?.value || '');
      const normalized = normalizeTaskOrProjectDeadline({
        deadlineMode: mode,
        deadlineDate: date,
        deadlineMonth: month,
        deadlineYear: year,
        deadlineStart: start,
        deadlineEnd: end
      });
      return {
        deadlineMode: normalized.mode,
        deadlineDate: normalized.date || null,
        deadlineMonth: normalized.month || null,
        deadlineYear: normalized.year || null,
        deadlineStart: normalized.start || null,
        deadlineEnd: normalized.end || null,
        deadlineAt: normalized.dueDate || null
      };
    }

    function populateProjectDeadlineForm(prefix = 'project', project = null) {
      const base = String(prefix || 'project').trim() === 'edit-project' ? 'edit-project' : 'project';
      const normalized = normalizeTaskOrProjectDeadline(project, project?.deadlineAt || '');
      const modeInput = document.getElementById(`${base}-deadline-mode`);
      const dateInput = document.getElementById(`${base}-deadline-date`);
      const monthInput = document.getElementById(`${base}-deadline-month`);
      const yearInput = document.getElementById(`${base}-deadline-year`);
      const startInput = document.getElementById(`${base}-deadline-period-start`);
      const endInput = document.getElementById(`${base}-deadline-period-end`);
      if (modeInput) modeInput.value = normalized.mode;
      if (dateInput) dateInput.value = normalized.date || normalized.dueDate || '';
      if (monthInput) monthInput.value = normalized.month || '';
      if (yearInput) yearInput.value = normalized.year || '';
      if (startInput) startInput.value = normalized.start || '';
      if (endInput) endInput.value = normalized.end || '';
      setProjectDeadlineModeUi(base, normalized.mode);
    }

    function normalizeCalendarYmd(rawValue) {
      const raw = String(rawValue || '').trim();
      return /^\d{4}-\d{2}-\d{2}$/.test(raw) ? raw : '';
    }

    function normalizeCalendarHm(rawValue) {
      const raw = String(rawValue || '').trim();
      return /^\d{2}:\d{2}$/.test(raw) ? raw : '';
    }

    function parseCalendarYmdToDate(rawYmd) {
      const ymd = normalizeCalendarYmd(rawYmd);
      if (!ymd) return null;
      const [year, month, day] = ymd.split('-').map((part) => Number(part));
      if (!Number.isFinite(year) || !Number.isFinite(month) || !Number.isFinite(day)) return null;
      const date = new Date(year, month - 1, day);
      return Number.isNaN(date.getTime()) ? null : date;
    }

    function getCalendarItemStartDate(item) {
      return normalizeCalendarYmd(item?.startDate) || normalizeCalendarYmd(item?.date);
    }

    function getCalendarItemEndDate(item) {
      const startDate = getCalendarItemStartDate(item);
      const endDate = normalizeCalendarYmd(item?.endDate) || startDate;
      if (!startDate) return endDate;
      return endDate >= startDate ? endDate : startDate;
    }

    function getCalendarItemStartTime(item) {
      return normalizeCalendarHm(item?.startTime);
    }

    function getCalendarItemEndTime(item) {
      return normalizeCalendarHm(item?.endTime);
    }

    function buildCalendarItemDateLabel(item) {
      const startDate = getCalendarItemStartDate(item);
      const endDate = getCalendarItemEndDate(item) || startDate;
      if (!startDate) return 'Non définie';
      const periodLabel = startDate === endDate
        ? formatDate(startDate)
        : `${formatDate(startDate)} → ${formatDate(endDate)}`;
      const startTime = getCalendarItemStartTime(item);
      const endTime = getCalendarItemEndTime(item);
      if (startTime && endTime) return `${periodLabel} • ${startTime}–${endTime}`;
      if (startTime) return `${periodLabel} • à partir de ${startTime}`;
      if (endTime) return `${periodLabel} • jusqu'à ${endTime}`;
      return periodLabel;
    }

    function doesCalendarRangeOverlapMonth(startDateRaw, endDateRaw, monthValue) {
      const month = String(monthValue || '');
      if (!/^\d{4}-\d{2}$/.test(month)) return false;
      const monthStart = `${month}-01`;
      const [yearStr, monthStr] = month.split('-');
      const lastDay = new Date(Number(yearStr), Number(monthStr), 0).getDate();
      const monthEnd = `${month}-${String(lastDay).padStart(2, '0')}`;
      const startDate = normalizeCalendarYmd(startDateRaw);
      const endDate = normalizeCalendarYmd(endDateRaw) || startDate;
      if (!startDate) return false;
      const safeEnd = endDate && endDate >= startDate ? endDate : startDate;
      return startDate <= monthEnd && safeEnd >= monthStart;
    }

    function doesCalendarRangeOverlapYear(startDateRaw, endDateRaw, yearValue) {
      const year = Number(yearValue);
      if (!Number.isFinite(year)) return false;
      const yearStart = `${year}-01-01`;
      const yearEnd = `${year}-12-31`;
      const startDate = normalizeCalendarYmd(startDateRaw);
      const endDate = normalizeCalendarYmd(endDateRaw) || startDate;
      if (!startDate) return false;
      const safeEnd = endDate && endDate >= startDate ? endDate : startDate;
      return startDate <= yearEnd && safeEnd >= yearStart;
    }

    function getCalendarRangeDayKeysInMonth(startDateRaw, endDateRaw, monthValue) {
      if (!doesCalendarRangeOverlapMonth(startDateRaw, endDateRaw, monthValue)) return [];
      const month = String(monthValue || '');
      const monthStart = `${month}-01`;
      const [yearStr, monthStr] = month.split('-');
      const lastDay = new Date(Number(yearStr), Number(monthStr), 0).getDate();
      const monthEnd = `${month}-${String(lastDay).padStart(2, '0')}`;
      const startDate = normalizeCalendarYmd(startDateRaw);
      const endDate = normalizeCalendarYmd(endDateRaw) || startDate;
      if (!startDate) return [];
      const rangeStart = startDate < monthStart ? monthStart : startDate;
      const rangeEnd = endDate > monthEnd ? monthEnd : endDate;
      const start = parseCalendarYmdToDate(rangeStart);
      const end = parseCalendarYmdToDate(rangeEnd);
      if (!start || !end) return [];
      const keys = [];
      let cursor = new Date(start);
      while (cursor.getTime() <= end.getTime()) {
        keys.push(toYmd(cursor));
        cursor.setDate(cursor.getDate() + 1);
      }
      return keys;
    }

    const GLOBAL_CALENDAR_PINNED_THEMES_KEY = 'taskmda_global_calendar_pinned_themes';
    const GLOBAL_CALENDAR_PINNED_THEME_CHECKS_KEY = 'taskmda_global_calendar_pinned_theme_checks';
    const GLOBAL_CALENDAR_CONTROLS_EXPANDED_KEY = 'taskmda_global_calendar_controls_expanded';

    function readLocalArray(key) {
      try {
        const raw = localStorage.getItem(key);
        if (!raw) return [];
        const parsed = JSON.parse(raw);
        if (!Array.isArray(parsed)) return [];
        return parsed.map((v) => String(v || '').trim()).filter(Boolean);
      } catch {
        return [];
      }
    }

    function writeLocalArray(key, values) {
      try {
        localStorage.setItem(key, JSON.stringify(Array.from(new Set((values || []).map((v) => String(v || '').trim()).filter(Boolean)))));
      } catch {
        // Ignore storage write failures
      }
    }

    function normalizeCalendarThemeName(rawTheme) {
      const name = String(rawTheme || '').trim();
      return name || 'Général';
    }

    function normalizeCalendarThemeKey(rawTheme) {
      return normalizeCatalogKey(normalizeCalendarThemeName(rawTheme));
    }

    function syncPinnedCalendarThemeState() {
      const pinnedKeys = new Set(globalCalendarPinnedThemes.map(normalizeCalendarThemeKey));
      globalCalendarPinnedThemes = globalCalendarPinnedThemes.filter((theme, idx, arr) => {
        const key = normalizeCalendarThemeKey(theme);
        return key && arr.findIndex((other) => normalizeCalendarThemeKey(other) === key) === idx;
      });
      globalCalendarPinnedThemeChecks = globalCalendarPinnedThemeChecks.filter((theme) => pinnedKeys.has(normalizeCalendarThemeKey(theme)));
      writeLocalArray(GLOBAL_CALENDAR_PINNED_THEMES_KEY, globalCalendarPinnedThemes);
      writeLocalArray(GLOBAL_CALENDAR_PINNED_THEME_CHECKS_KEY, globalCalendarPinnedThemeChecks);
    }

    function isPinnedCalendarThemeChecked(themeName) {
      const key = normalizeCalendarThemeKey(themeName);
      return globalCalendarPinnedThemeChecks.some((theme) => normalizeCalendarThemeKey(theme) === key);
    }

    function renderGlobalCalendarThemePins(availableThemes = []) {
      const pinsWrap = document.getElementById('global-calendar-theme-pins');
      const select = document.getElementById('global-calendar-theme-pin-select');
      const counter = document.getElementById('global-calendar-theme-pin-counter');
      if (!pinsWrap || !select) return;

      const normalizedAvailable = Array.from(new Set((availableThemes || []).map(normalizeCalendarThemeName)));
      const allKnown = Array.from(new Set([...normalizedAvailable, ...globalCalendarPinnedThemes.map(normalizeCalendarThemeName)]))
        .sort((a, b) => a.localeCompare(b, 'fr', { sensitivity: 'base' }));

      select.innerHTML = `
        <option value="">Choisir une thématique à épingler...</option>
        ${allKnown
          .filter((theme) => !globalCalendarPinnedThemes.some((pinned) => normalizeCalendarThemeKey(pinned) === normalizeCalendarThemeKey(theme)))
          .map((theme) => `<option value="${escapeHtml(theme)}">${escapeHtml(theme)}</option>`)
          .join('')}
      `;

      if (globalCalendarPinnedThemes.length === 0) {
        pinsWrap.innerHTML = '<p class="text-xs text-slate-500">Aucune thématique épinglée.</p>';
        if (counter) counter.textContent = '(0/0 actives)';
        return;
      }
      if (counter) {
        counter.textContent = `(${globalCalendarPinnedThemeChecks.length}/${globalCalendarPinnedThemes.length} actives)`;
      }

      pinsWrap.innerHTML = globalCalendarPinnedThemes.map((theme) => `
        <label class="calendar-theme-pin-chip">
          <input type="checkbox" data-calendar-theme-check="${escapeHtml(theme)}" ${isPinnedCalendarThemeChecked(theme) ? 'checked' : ''}>
          <span>${escapeHtml(theme)}</span>
          <button type="button" class="calendar-theme-pin-unpin" data-calendar-theme-unpin="${escapeHtml(theme)}" aria-label="Désépingler ${escapeHtml(theme)}">×</button>
        </label>
      `).join('');
    }

    function initGlobalCalendarPinnedThemesState() {
      if (globalCalendarPinsInitialized) return;
      globalCalendarPinnedThemes = readLocalArray(GLOBAL_CALENDAR_PINNED_THEMES_KEY).map(normalizeCalendarThemeName);
      globalCalendarPinnedThemeChecks = readLocalArray(GLOBAL_CALENDAR_PINNED_THEME_CHECKS_KEY).map(normalizeCalendarThemeName);
      globalCalendarControlsExpanded = localStorage.getItem(GLOBAL_CALENDAR_CONTROLS_EXPANDED_KEY) !== '0';
      syncPinnedCalendarThemeState();
      globalCalendarPinsInitialized = true;
    }

    function setGlobalCalendarControlsExpanded(expanded, options = {}) {
      const next = !!expanded;
      globalCalendarControlsExpanded = next;
      const panel = document.getElementById('global-calendar-controls-panel');
      const top = document.querySelector('#global-calendar-section .calendar-toolbar-top');
      const toggleBtn = document.getElementById('global-calendar-toggle-controls');
      const toggleIcon = document.getElementById('global-calendar-toggle-controls-icon');
      const toggleLabel = document.getElementById('global-calendar-toggle-controls-label');
      if (panel) panel.classList.toggle('is-collapsed', !next);
      if (top) top.classList.toggle('mb-3', next);
      if (toggleBtn) {
        toggleBtn.setAttribute('aria-expanded', next ? 'true' : 'false');
        toggleBtn.setAttribute('title', next ? 'Masquer les filtres et outils' : 'Afficher les filtres et outils');
      }
      if (toggleIcon) toggleIcon.textContent = next ? 'expand_less' : 'expand_more';
      if (toggleLabel) toggleLabel.textContent = next ? 'Masquer les filtres' : 'Afficher les filtres';
      if (!options.skipPersist) {
        try {
          localStorage.setItem(GLOBAL_CALENDAR_CONTROLS_EXPANDED_KEY, next ? '1' : '0');
        } catch {
          // Ignore storage failures
        }
      }
    }

    function toggleGlobalCalendarThemeActionsMenu(forceOpen = null) {
      const menu = document.getElementById('global-calendar-theme-actions-menu');
      if (!menu) return;
      const shouldOpen = typeof forceOpen === 'boolean' ? forceOpen : menu.classList.contains('hidden');
      menu.classList.toggle('hidden', !shouldOpen);
    }

    function parseYmdLocalToDate(dateKey) {
      const raw = String(dateKey || '').trim();
      if (!/^\d{4}-\d{2}-\d{2}$/.test(raw)) return null;
      const [y, m, d] = raw.split('-').map((v) => Number.parseInt(v, 10));
      const date = new Date(y, m - 1, d);
      if (Number.isNaN(date.getTime())) return null;
      if (date.getFullYear() !== y || date.getMonth() !== (m - 1) || date.getDate() !== d) return null;
      date.setHours(0, 0, 0, 0);
      return date;
    }

    function getTaskRecurringNextDueDateKey(task) {
      if (!task?.recurring?.enabled) return null;
      const persistedDue = taskDueDateKey(task);
      if (persistedDue) return persistedDue;
      const recurrenceApi = window.TaskMDARecurrence;
      if (!recurrenceApi) return null;
      const normalized = normalizeTaskRecurringConfig(task.recurring);
      if (!normalized?.enabled) return null;

      const today = startOfDay(new Date());
      const fromKey = toYmd(addDays(today, -1));
      if (typeof recurrenceApi.getNextOccurrence === 'function') {
        const next = String(recurrenceApi.getNextOccurrence(fromKey, normalized) || '').trim();
        if (/^\d{4}-\d{2}-\d{2}$/.test(next)) return next;
      }

      if (typeof recurrenceApi.generateOccurrenceDates === 'function') {
        const occurrences = recurrenceApi.generateOccurrenceDates(normalized);
        if (Array.isArray(occurrences)) {
          const todayKey = toYmd(today);
          const next = occurrences.find((dateKey) => String(dateKey || '').trim() >= todayKey);
          if (next && /^\d{4}-\d{2}-\d{2}$/.test(String(next))) return String(next);
        }
      }

      return null;
    }

    function computeTaskRecurringNextDueDateAfterCompletion(task, options = {}) {
      const normalized = normalizeTaskRecurringConfig(task?.recurring);
      if (!normalized?.enabled) return null;
      const recurrenceApi = window.TaskMDARecurrence;
      if (!recurrenceApi) return null;
      const referenceTs = Number(options.referenceTs || Date.now()) || Date.now();
      const referenceDate = startOfDay(new Date(referenceTs));
      const referenceKey = toYmd(referenceDate);
      const fromKey = taskDueDateKey(task) || referenceKey;

      if (typeof recurrenceApi.getNextOccurrence === 'function') {
        const next = String(recurrenceApi.getNextOccurrence(fromKey, normalized) || '').trim();
        if (/^\d{4}-\d{2}-\d{2}$/.test(next)) return next;
      }

      if (typeof recurrenceApi.generateOccurrenceDates === 'function') {
        const occurrences = recurrenceApi.generateOccurrenceDates(normalized);
        if (Array.isArray(occurrences)) {
          const next = occurrences.find((dateKey) => String(dateKey || '').trim() > fromKey);
          if (next && /^\d{4}-\d{2}-\d{2}$/.test(String(next))) return String(next);
        }
      }

      return null;
    }

    function buildTaskStatusTransitionChanges(task, targetStatus, options = {}) {
      const prevStatus = normalizeTaskStatusValue(task?.status || 'todo');
      const normalizedTarget = normalizeTaskStatusValue(targetStatus || 'todo');
      const nowTs = Number(options.nowTs || Date.now()) || Date.now();
      const shouldSetCompletedAt = normalizedTarget === 'termine';
      const isArchiveTransition = Number(options.archivedAt || 0) > 0;
      const didCompleteOccurrence = prevStatus !== 'termine' && normalizedTarget === 'termine';
      const allowRecurringRollover = options.allowRecurringRollover !== false;

      const changes = {
        status: normalizedTarget,
        completedAt: shouldSetCompletedAt ? Number(task?.completedAt || nowTs) || nowTs : null
      };

      if (didCompleteOccurrence && allowRecurringRollover && !isArchiveTransition && task?.recurring?.enabled) {
        const nextDueDate = computeTaskRecurringNextDueDateAfterCompletion(task, { referenceTs: nowTs });
        if (nextDueDate) {
          return {
            changes: {
              ...changes,
              status: 'todo',
              completedAt: null,
              dueDate: nextDueDate
            },
            recurringRolloverApplied: true,
            nextDueDate,
            didCompleteOccurrence
          };
        }
      }

      return {
        changes,
        recurringRolloverApplied: false,
        nextDueDate: null,
        didCompleteOccurrence
      };
    }

    function getTaskEffectiveDueDateKey(task) {
      if (task?.recurring?.enabled) {
        return getTaskRecurringNextDueDateKey(task);
      }
      return taskDueDateKey(task);
    }

    function getTaskEffectiveDueTimestamp(task) {
      const dueKey = getTaskEffectiveDueDateKey(task);
      const dueDate = parseYmdLocalToDate(dueKey);
      return dueDate ? dueDate.getTime() : Number.POSITIVE_INFINITY;
    }

    function isTaskDeadlineIgnored(task) {
      return String(task?.status || '').trim().toLowerCase() === 'suspendu';
    }

    function getTaskDueStatus(task) {
      if (isTaskDeadlineIgnored(task)) {
        return { isDueToday: false, isOverdue: false, daysUntilDue: null };
      }
      const dueKey = getTaskEffectiveDueDateKey(task);
      if (!dueKey) return { isDueToday: false, isOverdue: false, daysUntilDue: null };
      const dueDate = parseYmdLocalToDate(dueKey);
      if (!dueDate) return { isDueToday: false, isOverdue: false, daysUntilDue: null };
      const today = new Date();
      const todayStart = new Date(today.getFullYear(), today.getMonth(), today.getDate());
      const dueStart = new Date(dueDate.getFullYear(), dueDate.getMonth(), dueDate.getDate());
      const diffTime = dueStart.getTime() - todayStart.getTime();
      const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24));
      return {
        isDueToday: diffDays === 0 && task.status !== 'termine',
        isOverdue: diffDays < 0 && task.status !== 'termine',
        daysUntilDue: diffDays
      };
    }

    /**
     * Calcule le score de priorité "Focus Today" pour une tâche.
     * Plus le score est élevé, plus la tâche doit être en haut du tableau de bord.
     */
    function getTaskFocusPriority(task, precomputedDueStatus = null) {
      if (task.status === 'termine') return 0;
      
      const dueStatus = precomputedDueStatus || getTaskDueStatus(task);
      let score = 0;
      
      // 1. État d'urgence critique (En retard > Aujourd'hui)
      if (dueStatus.isOverdue) score += 1000;
      if (dueStatus.isDueToday) score += 500;
      
      // 2. Niveau d'urgence défini (High > Medium > Low)
      const urgencyScores = { 'high': 100, 'medium': 50, 'low': 10, 'normal': 50 };
      score += (urgencyScores[task.urgency] || 50);
      
      // 3. Statut d'avancement (En cours > Suspendu > A faire)
      const statusScores = { 'en-cours': 20, 'suspendu': 10, 'todo': 5 };
      score += (statusScores[task.status] || 0);
      
      // 4. Proximité de l'échéance (si pas déjà en retard ou aujourd'hui)
      if (dueStatus.daysUntilDue > 0 && dueStatus.daysUntilDue <= 3) {
        score += (4 - dueStatus.daysUntilDue) * 25; // Bonus pour J+1, J+2, J+3
      }
      
      return score;
    }

    function resetWorkspaceScrollTop() {
      if (typeof window.scrollTo === 'function') {
        window.scrollTo({ top: 0, left: 0, behavior: 'auto' });
      }
      const candidates = [
        document.scrollingElement,
        document.documentElement,
        document.body,
        document.querySelector('.content'),
        document.querySelector('.workspace')
      ];
      candidates.forEach((node) => {
        if (node && typeof node.scrollTop === 'number') {
          node.scrollTop = 0;
        }
      });
    }

    function updateTopbarHeightVar() {
      const topbar = document.querySelector('.topbar');
      const root = document.documentElement;
      if (!topbar || !root) return;
      const measured = Math.max(56, Math.round(topbar.getBoundingClientRect().height || 0));
      root.style.setProperty('--topbar-height', `${measured}px`);
      root.style.setProperty('--project-sticky-top', `${Math.max(60, measured + 8)}px`);
    }

