    // ========================================
    // EXPORT DOCX - CONVERTISSEUR HTML→WORDML
    // ========================================

    /**
     * Extrait les images d'un contenu HTML
     * @param {string} htmlContent - Contenu HTML
     * @returns {Array} Liste des images {index, rId, filename, mimeType, base64, width, height}
     */
    function extractImagesFromHtml(htmlContent) {
      const parser = new DOMParser();
      const doc = parser.parseFromString(`<div>${htmlContent}</div>`, 'text/html');
      const images = [];

      doc.querySelectorAll('img').forEach((img, index) => {
        const src = img.getAttribute('src');
        if (!src) return;

        if (src.startsWith('data:')) {
          const match = src.match(/^data:([^;]+);base64,(.+)$/);
          if (match) {
            const mimeType = match[1];
            const base64Data = match[2];
            const extension = getMimeExtension(src);

            images.push({
              index,
              rId: `rId${index + 5}`,
              filename: `image${index + 1}.${extension}`,
              mimeType,
              base64: base64Data,
              width: img.width || 400,
              height: img.height || 300,
              element: img
            });

            // Marquer l'élément pour la conversion
            img.setAttribute('data-docx-rid', `rId${index + 5}`);
          }
        }
      });

      return images;
    }

    /**
     * Génère le WordML pour une image
     * @param {object} image - Métadonnées image
     * @returns {string} WordML de l'image
     */
    function generateImageWordML(image) {
      // Redimensionner proportionnellement si trop grand
      const maxWidthPx = 600;
      const maxHeightPx = 800;

      let width = image.width;
      let height = image.height;

      if (width > maxWidthPx) {
        height = Math.round(height * maxWidthPx / width);
        width = maxWidthPx;
      }
      if (height > maxHeightPx) {
        width = Math.round(width * maxHeightPx / height);
        height = maxHeightPx;
      }

      // Conversion en EMU (914400 EMU = 1 pouce, 96 DPI)
      const widthEmu = Math.round(width * 9525);
      const heightEmu = Math.round(height * 9525);

      return `
<w:p>
  <w:r>
    <w:drawing>
      <wp:inline>
        <wp:extent cx="${widthEmu}" cy="${heightEmu}"/>
        <wp:docPr id="${image.index + 1}" name="${escapeXml(image.filename)}"/>
        <a:graphic>
          <a:graphicData uri="http://schemas.openxmlformats.org/drawingml/2006/picture">
            <pic:pic>
              <pic:nvPicPr>
                <pic:cNvPr id="${image.index + 1}" name="${escapeXml(image.filename)}"/>
                <pic:cNvPicPr/>
              </pic:nvPicPr>
              <pic:blipFill>
                <a:blip r:embed="${image.rId}"/>
                <a:stretch><a:fillRect/></a:stretch>
              </pic:blipFill>
              <pic:spPr>
                <a:xfrm>
                  <a:off x="0" y="0"/>
                  <a:ext cx="${widthEmu}" cy="${heightEmu}"/>
                </a:xfrm>
                <a:prstGeom prst="rect"><a:avLst/></a:prstGeom>
              </pic:spPr>
            </pic:pic>
          </a:graphicData>
        </a:graphic>
      </wp:inline>
    </w:drawing>
  </w:r>
</w:p>`;
    }

    /**
     * Convertit du HTML en WordML (WordProcessingML)
     * @param {string} htmlContent - Contenu HTML Quill
     * @returns {object} {wordML, images, relationships}
     */
    function convertHtmlToWordML(htmlContent) {
      const parser = new DOMParser();
      const doc = parser.parseFromString(`<div>${htmlContent}</div>`, 'text/html');
      const root = doc.body.firstElementChild;

      // Extraire les images
      const images = extractImagesFromHtml(htmlContent);
      const relationships = images.map(img => ({
        id: img.rId,
        type: 'http://schemas.openxmlformats.org/officeDocument/2006/relationships/image',
        target: `media/${img.filename}`
      }));

      const wordMLParagraphs = [];

      // Fonction récursive de conversion
      function processNode(node, context = {}) {
        if (!node) return [];

        const nodeName = node.nodeName ? node.nodeName.toLowerCase() : '';

        // Texte brut
        if (node.nodeType === Node.TEXT_NODE) {
          const text = node.textContent || '';
          if (!text.trim()) return [];
          return [`<w:r>${context.format || ''}<w:t xml:space="preserve">${escapeXml(text)}</w:t></w:r>`];
        }

        // Éléments inline avec formatage
        if (nodeName === 'strong' || nodeName === 'b') {
          const newFormat = (context.format || '') + '<w:rPr><w:b/></w:rPr>';
          return Array.from(node.childNodes).flatMap(child => processNode(child, { ...context, format: newFormat }));
        }

        if (nodeName === 'em' || nodeName === 'i') {
          const newFormat = (context.format || '') + '<w:rPr><w:i/></w:rPr>';
          return Array.from(node.childNodes).flatMap(child => processNode(child, { ...context, format: newFormat }));
        }

        if (nodeName === 'u') {
          const newFormat = (context.format || '') + '<w:rPr><w:u w:val="single"/></w:rPr>';
          return Array.from(node.childNodes).flatMap(child => processNode(child, { ...context, format: newFormat }));
        }

        if (nodeName === 's' || nodeName === 'strike') {
          const newFormat = (context.format || '') + '<w:rPr><w:strike/></w:rPr>';
          return Array.from(node.childNodes).flatMap(child => processNode(child, { ...context, format: newFormat }));
        }

        // Image
        if (nodeName === 'img') {
          const rId = node.getAttribute('data-docx-rid');
          if (rId) {
            const img = images.find(i => i.rId === rId);
            if (img) {
              return [generateImageWordML(img)];
            }
          }
          return [];
        }

        // Paragraphe
        if (nodeName === 'p') {
          const runs = Array.from(node.childNodes).flatMap(child => processNode(child, context));
          if (runs.length === 0) return ['<w:p><w:r><w:t> </w:t></w:r></w:p>'];
          return [`<w:p>${runs.join('')}</w:p>`];
        }

        // Titres
        if (nodeName === 'h1') {
          const runs = Array.from(node.childNodes).flatMap(child => processNode(child, context));
          return [`<w:p><w:pPr><w:pStyle w:val="Heading1"/></w:pPr>${runs.join('')}</w:p>`];
        }

        if (nodeName === 'h2') {
          const runs = Array.from(node.childNodes).flatMap(child => processNode(child, context));
          return [`<w:p><w:pPr><w:pStyle w:val="Heading2"/></w:pPr>${runs.join('')}</w:p>`];
        }

        if (nodeName === 'h3') {
          const runs = Array.from(node.childNodes).flatMap(child => processNode(child, context));
          return [`<w:p><w:pPr><w:pStyle w:val="Heading3"/></w:pPr>${runs.join('')}</w:p>`];
        }

        // Listes non ordonnées
        if (nodeName === 'ul') {
          return Array.from(node.children).flatMap((li, idx) => {
            if (li.nodeName.toLowerCase() === 'li') {
              const runs = Array.from(li.childNodes).flatMap(child => processNode(child, context));
              return [`<w:p><w:pPr><w:numPr><w:ilvl w:val="0"/><w:numId w:val="1"/></w:numPr></w:pPr>${runs.join('')}</w:p>`];
            }
            return [];
          });
        }

        // Listes ordonnées
        if (nodeName === 'ol') {
          return Array.from(node.children).flatMap((li, idx) => {
            if (li.nodeName.toLowerCase() === 'li') {
              const runs = Array.from(li.childNodes).flatMap(child => processNode(child, context));
              return [`<w:p><w:pPr><w:numPr><w:ilvl w:val="0"/><w:numId w:val="2"/></w:numPr></w:pPr>${runs.join('')}</w:p>`];
            }
            return [];
          });
        }

        // Saut de ligne
        if (nodeName === 'br') {
          return ['<w:r><w:br/></w:r>'];
        }

        // Conteneur générique (div, span, etc.)
        return Array.from(node.childNodes).flatMap(child => processNode(child, context));
      }

      // Traiter tous les enfants du root
      Array.from(root.childNodes).forEach(node => {
        const paragraphs = processNode(node);
        wordMLParagraphs.push(...paragraphs);
      });

      // Si aucun contenu, ajouter un paragraphe vide
      if (wordMLParagraphs.length === 0) {
        wordMLParagraphs.push('<w:p><w:r><w:t>Cette note ne contient aucun contenu.</w:t></w:r></w:p>');
      }

      return {
        wordML: wordMLParagraphs.join('\n'),
        images,
        relationships
      };
    }

    // ========================================
    // EXPORT DOCX - FONCTION PRINCIPALE
    // ========================================

    /**
     * Exporte une note individuelle au format DOCX
     * @param {string} noteId - ID de la note à exporter
     */
    async function exportGlobalNoteAsDocx(noteId = '') {
      const nid = String(noteId || '').trim();
      if (!nid) return;

      // 1. Récupérer la note
      const note = await getDecrypted('globalNotes', nid, 'noteId');
      if (!note) {
        showToast('Note introuvable');
        return;
      }

      // 2. Préparer les données
      const title = String(note.title || '').trim() || 'Note';
      const safeTitle = sanitizeFilenameSegment(title);
      const contentHtml = sanitizeRichTextHtmlPreserve(
        String(note.contentHtml || '').trim() || plainTextToRichHtml(String(note.content || '').trim())
      );
      const tags = Array.isArray(note.tags) ? note.tags.map(t => String(t || '').trim()).filter(Boolean) : [];
      const author = String(note.createdByName || fallbackDirectoryName(note.createdBy || ''));
      const dateFormatted = new Date(Number(note.updatedAt || note.createdAt || Date.now())).toLocaleString('fr-FR');

      // 3. Convertir HTML → WordML
      const { wordML, images, relationships } = convertHtmlToWordML(contentHtml);

      // 4. Générer tous les fichiers XML
      const files = [
        {
          name: '[Content_Types].xml',
          data: generateContentTypesXml(images),
          mtime: Date.now()
        },
        {
          name: '_rels/.rels',
          data: generateRootRelsXml(),
          mtime: Date.now()
        },
        {
          name: 'word/document.xml',
          data: generateDocumentXml({ title, author, dateFormatted, tags }, wordML),
          mtime: Date.now()
        },
        {
          name: 'word/styles.xml',
          data: generateStylesXml(),
          mtime: Date.now()
        }
      ];

      // 5. Ajouter les relationships si images présentes
      if (images.length > 0) {
        files.push({
          name: 'word/_rels/document.xml.rels',
          data: generateDocumentRelsXml(relationships),
          mtime: Date.now()
        });

        // 6. Ajouter les images décodées
        images.forEach(img => {
          files.push({
            name: `word/media/${img.filename}`,
            data: base64ToUint8Array(img.base64),
            mtime: Date.now()
          });
        });
      }

      // 7. Créer le ZIP (fichier DOCX)
      const zipBytes = buildZipStoreArchive(files);

      // 8. Télécharger
      const tag = formatExportDateTag();
      downloadBlobFile(
        new Blob([zipBytes], { type: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document' }),
        `note_${safeTitle}_${tag}.docx`,
        'application/vnd.openxmlformats-officedocument.wordprocessingml.document'
      );

      showToast('Note exportée (DOCX)');
    }

    // ========================================
    // GESTION DU MENU DÉROULANT D'EXPORT
    // ========================================

    /**
     * Toggle (afficher/masquer) le menu d'export d'une note
     * @param {string} noteId - ID de la note
     */
    function toggleGlobalNoteExportMenu(noteId, event) {
      // Empêcher la propagation vers l'article parent
      if (event) {
        event.stopPropagation();
        event.preventDefault();
      }

      const nid = String(noteId || '').trim();
      if (!nid) return;

      const menu = document.getElementById(`export-menu-${nid}`);
      const btn = document.getElementById(`export-menu-btn-${nid}`);
      if (!menu || !btn) return;

      // Fermer tous les autres menus ouverts (exclure les boutons trigger)
      document.querySelectorAll('[id^="export-menu-"]:not([id^="export-menu-btn-"])').forEach(otherMenu => {
        if (otherMenu.id !== menu.id && !otherMenu.classList.contains('hidden')) {
          otherMenu.classList.add('hidden');
          const otherId = otherMenu.id.replace('export-menu-', '');
          const otherBtn = document.getElementById(`export-menu-btn-${otherId}`);
          if (otherBtn) otherBtn.setAttribute('aria-expanded', 'false');
        }
      });

      // Toggle le menu actuel
      const isHidden = menu.classList.contains('hidden');
      if (isHidden) {
        menu.classList.remove('hidden');
        btn.setAttribute('aria-expanded', 'true');
      } else {
        menu.classList.add('hidden');
        btn.setAttribute('aria-expanded', 'false');
      }
    }

    /**
     * Ferme le menu d'export d'une note
     * @param {string} noteId - ID de la note
     */
    function closeGlobalNoteExportMenu(noteId) {
      const nid = String(noteId || '').trim();
      if (!nid) return;

      const menu = document.getElementById(`export-menu-${nid}`);
      const btn = document.getElementById(`export-menu-btn-${nid}`);
      if (menu) menu.classList.add('hidden');
      if (btn) btn.setAttribute('aria-expanded', 'false');
    }

    // Event listener global pour fermer les menus au clic extérieur
    document.addEventListener('click', (event) => {
      const isMenuButton = event.target.closest('[id^="export-menu-btn-"]');
      const isMenu = event.target.closest('[id^="export-menu-"]');

      if (!isMenuButton && !isMenu) {
        document.querySelectorAll('[id^="export-menu-"]:not([id^="export-menu-btn-"])').forEach(menu => {
          if (!menu.classList.contains('hidden')) {
            menu.classList.add('hidden');
            const noteId = menu.id.replace('export-menu-', '');
            const btn = document.getElementById(`export-menu-btn-${noteId}`);
            if (btn) btn.setAttribute('aria-expanded', 'false');
          }
        });
      }
    });

    async function exportSelectedGlobalNotesAsZip(format = 'html') {
      if (!globalNotesBulkSelectionMode) return;
      const selectedIds = Array.from(selectedGlobalNoteIdsForBulkDelete).map((id) => String(id || '').trim()).filter(Boolean);
      if (!selectedIds.length) {
        showToast('Aucune note sélectionnée');
        return;
      }
      const allNotesRaw = await getAllDecrypted('globalNotes', 'noteId');
      const allNotes = Array.isArray(allNotesRaw) ? allNotesRaw : [];
      const selectedNotes = selectedIds
        .map((id) => allNotes.find((row) => String(row?.noteId || '').trim() === id))
        .filter((note) => note && canManageGlobalNote(note));
      if (!selectedNotes.length) {
        showToast('Aucune note exportable dans la sélection');
        return;
      }

      const mode = String(format || 'html').toLowerCase();
      const files = [];

      // Cas PDF : génération asynchrone des blobs
      if (mode === 'pdf') {
        showToast('Export PDF multiple en cours...');
        for (const note of selectedNotes) {
          const title = String(note.title || '').trim() || 'Note';
          const safeTitle = sanitizeFilenameSegment(title);
          const baseName = `${String(note.createdAt || Date.now())}_${safeTitle}`;
          const contentHtml = sanitizeRichTextHtmlPreserve(
            String(note.contentHtml || '').trim() || plainTextToRichHtml(String(note.content || '').trim())
          );
          const tags = Array.isArray(note.tags) ? note.tags.map(t => String(t || '').trim()).filter(Boolean) : [];
          const dateFormatted = new Date(Number(note.updatedAt || note.createdAt || Date.now())).toLocaleString('fr-FR');

          const pdfBlob = await generatePdfBlobForNote({ title, contentHtml, tags, dateFormatted });
          if (pdfBlob) {
            files.push({
              name: `${baseName}.pdf`,
              data: new Uint8Array(await pdfBlob.arrayBuffer()),
              mtime: Number(note.updatedAt || note.createdAt || Date.now())
            });
          }
        }
      }

      // Cas DOCX : génération de ZIP complets (DOCX = ZIP de XML)
      else if (mode === 'docx') {
        showToast('Export DOCX multiple en cours...');
        for (const note of selectedNotes) {
          const title = String(note.title || '').trim() || 'Note';
          const safeTitle = sanitizeFilenameSegment(title);
          const baseName = `${String(note.createdAt || Date.now())}_${safeTitle}`;
          const contentHtml = sanitizeRichTextHtmlPreserve(
            String(note.contentHtml || '').trim() || plainTextToRichHtml(String(note.content || '').trim())
          );
          const tags = Array.isArray(note.tags) ? note.tags.map(t => String(t || '').trim()).filter(Boolean) : [];
          const author = String(note.createdByName || fallbackDirectoryName(note.createdBy || ''));
          const dateFormatted = new Date(Number(note.updatedAt || note.createdAt || Date.now())).toLocaleString('fr-FR');

          // Convertir HTML → WordML
          const { wordML, images, relationships } = convertHtmlToWordML(contentHtml);

          // Générer tous les fichiers XML du DOCX
          const docxFiles = [
            { name: '[Content_Types].xml', data: generateContentTypesXml(images), mtime: Date.now() },
            { name: '_rels/.rels', data: generateRootRelsXml(), mtime: Date.now() },
            { name: 'word/document.xml', data: generateDocumentXml({ title, author, dateFormatted, tags }, wordML), mtime: Date.now() },
            { name: 'word/styles.xml', data: generateStylesXml(), mtime: Date.now() }
          ];

          if (images.length > 0) {
            docxFiles.push({ name: 'word/_rels/document.xml.rels', data: generateDocumentRelsXml(relationships), mtime: Date.now() });
            images.forEach(img => {
              docxFiles.push({ name: `word/media/${img.filename}`, data: base64ToUint8Array(img.base64), mtime: Date.now() });
            });
          }

          // Créer le ZIP DOCX
          const docxZip = buildZipStoreArchive(docxFiles);
          files.push({
            name: `${baseName}.docx`,
            data: docxZip,
            mtime: Number(note.updatedAt || note.createdAt || Date.now())
          });
        }
      }

      // Cas HTML et TXT : génération synchrone simple
      else {
        selectedNotes.forEach(note => {
          const title = String(note.title || '').trim() || 'Note';
          const safeTitle = sanitizeFilenameSegment(title);
          const baseName = `${String(note.createdAt || Date.now())}_${safeTitle}`;
          const tags = Array.isArray(note.tags) ? note.tags.map(t => String(t || '').trim()).filter(Boolean) : [];
          const contentHtml = sanitizeRichTextHtmlPreserve(
            String(note.contentHtml || '').trim() || plainTextToRichHtml(String(note.content || '').trim())
          );

          if (mode === 'txt') {
            const plain = getProjectDescriptionPlainText(contentHtml);
            const payload = `${title}\nAuteur: ${String(note.createdByName || fallbackDirectoryName(note.createdBy || '') || 'Auteur')}\nMise a jour: ${new Date(Number(note.updatedAt || note.createdAt || Date.now())).toLocaleString('fr-FR')}\nTags: ${tags.join(', ')}\n\n${plain}\n`;
            files.push({ name: `${baseName}.txt`, data: payload, mtime: Number(note.updatedAt || note.createdAt || Date.now()) });
          } else {
            const payload = `<!doctype html><html lang="fr"><head><meta charset="utf-8"><title>${escapeHtml(title)}</title><style>body{font-family:Segoe UI,Arial,sans-serif;margin:24px;color:#1e293b}h1{margin:0 0 8px}.meta{color:#64748b;font-size:13px;margin-bottom:12px}.chips{display:flex;flex-wrap:wrap;gap:6px;margin-bottom:14px}.chip{font-size:11px;border:1px solid #cbd5e1;border-radius:999px;padding:3px 8px;background:#f8fafc;color:#334155}</style></head><body><h1>${escapeHtml(title)}</h1><p class="meta">${escapeHtml(new Date(Number(note.updatedAt || note.createdAt || Date.now())).toLocaleString('fr-FR'))}</p><div class="chips">${tags.map(entry => `<span class="chip">#${escapeHtml(entry)}</span>`).join('')}</div><article>${contentHtml || '<p>Aucun contenu.</p>'}</article></body></html>`;
            files.push({ name: `${baseName}.html`, data: payload, mtime: Number(note.updatedAt || note.createdAt || Date.now()) });
          }
        });
      }

      const zipBytes = buildZipStoreArchive(files);
      const exportTag = formatExportDateTag();
      downloadBlobFile(new Blob([zipBytes], { type: 'application/zip' }), `notes_selection_${mode}_${exportTag}.zip`, 'application/zip');
      showToast(`Export ZIP ${mode.toUpperCase()} prêt (${files.length} notes)`);
    }

    async function confirmGlobalNotesBulkExportFromModal() {
      if (!globalNotesRuntime?.confirmGlobalNotesBulkExportFromModal) return;
      await globalNotesRuntime.confirmGlobalNotesBulkExportFromModal();
    }

    function readGlobalNoteEditorDraft() {
      const title = String(document.getElementById('global-note-title')?.value || '').trim();
      const contentHtml = getProjectDescriptionHtmlForStorage('global-note-content-editor', 'global-note-content');
      const content = getProjectDescriptionPlainText(contentHtml);
      const tags = normalizeProjectNoteTags(document.getElementById('global-note-tags')?.value || '');
      const themeInput = String(document.getElementById('global-note-theme')?.value || '').trim();
      const visibility = document.getElementById('global-note-transverse')?.checked ? 'transverse' : 'private';
      const shareToGlobalFeed = !!document.getElementById('global-note-share-feed')?.checked;
      const theme = themeInput || (tags.length > 0 ? String(tags[0] || '').trim() : '');
      return {
        title,
        content,
        contentHtml,
        tags,
        theme,
        visibility: normalizeGlobalNoteVisibility(visibility),
        shareToGlobalFeed
      };
    }

    async function upsertGlobalNoteFeedPost(note) {
      const noteId = String(note?.noteId || '').trim();
      if (!noteId) return;
      const postId = getGlobalNotePostId(noteId);
      const existing = await getDecrypted('globalPosts', postId, 'postId');
      const title = String(note?.title || '').trim() || 'Note transverse';
      const content = String(note?.content || '').trim();
      const authorIdentity = resolveKnownUserIdentity(
        String(note?.createdBy || ''),
        String(note?.createdByName || fallbackDirectoryName(note?.createdBy || ''))
      );
      const post = {
        postId,
        authorUserId: String(note?.createdBy || currentUser?.userId || ''),
        authorName: String(authorIdentity?.name || note?.createdByName || currentUser?.name || 'Utilisateur'),
        content: `🗒️ ${title}${content ? `\n\n${content}` : ''}`,
        mentions: [],
        refs: [{ type: 'global-note', id: noteId, label: title }],
        createdAt: Number(existing?.createdAt || note?.createdAt || Date.now()) || Date.now(),
        updatedAt: Date.now(),
        source: sharedFolderHandle ? 'shared' : 'local',
        isAuto: false,
        sourceEventId: `global-note:${noteId}`,
        deletedAt: null
      };
      await putEncrypted('globalPosts', post, 'postId');
      knownGlobalPostIds.add(post.postId);
      if (sharedFolderHandle) {
        await writeGlobalFeedPostToSharedFolder(post);
      }
    }

    async function removeGlobalNoteFromFeed(noteId) {
      const postId = getGlobalNotePostId(noteId);
      const existing = await getDecrypted('globalPosts', postId, 'postId');
      if (!existing || existing.deletedAt) return;
      existing.deletedAt = Date.now();
      existing.updatedAt = Date.now();
      await putEncrypted('globalPosts', existing, 'postId');
      if (sharedFolderHandle) {
        await writeGlobalFeedPostToSharedFolder(existing);
      }
    }

    async function syncGlobalNoteFeed(note) {
      if (!note) return;
      const shouldPublish = normalizeGlobalNoteVisibility(note.visibility) === 'transverse'
        && !Number(note.archivedAt || 0)
        && note.shareToGlobalFeed === true;
      if (shouldPublish) {
        await upsertGlobalNoteFeedPost(note);
      } else {
        await removeGlobalNoteFromFeed(note.noteId);
      }
    }

    function closeGlobalNoteEditor() {
      const modal = document.getElementById('modal-global-note');
      if (!modal) return;
      modal.classList.add('hidden');
      document.body.classList.remove('overflow-hidden');
      editingGlobalNoteId = '';
      const titleEl = document.getElementById('global-note-modal-title');
      if (titleEl) titleEl.textContent = 'Nouvelle note transverse';
      const titleInput = document.getElementById('global-note-title');
      const themeInput = document.getElementById('global-note-theme');
      const tagsInput = document.getElementById('global-note-tags');
      const transverseInput = document.getElementById('global-note-transverse');
      const shareInput = document.getElementById('global-note-share-feed');
      const deleteBtn = document.getElementById('btn-global-note-delete');
      const saveBtn = document.getElementById('btn-global-note-save');
      const digestBtn = document.getElementById('btn-global-note-digest');
      if (titleInput) titleInput.value = '';
      if (themeInput) themeInput.value = '';
      if (tagsInput) tagsInput.value = '';
      if (transverseInput) transverseInput.checked = true;
      if (shareInput) shareInput.checked = false;
      if (deleteBtn) deleteBtn.classList.add('hidden');
      if (saveBtn) saveBtn.classList.remove('hidden');
      if (digestBtn) digestBtn.classList.remove('hidden');
      [titleInput, themeInput, tagsInput, transverseInput, shareInput].forEach((el) => {
        if (el) el.disabled = false;
      });
      const quill = projectDescriptionQuillEditors.get('global-note-content-editor');
      if (quill) quill.enable(true);
      setProjectDescriptionEditorContent('global-note-content-editor', 'global-note-content', '');
    }

    async function openGlobalNoteEditor(noteId = '') {
      const modal = document.getElementById('modal-global-note');
      if (!modal) return;
      const nid = String(noteId || '').trim();
      const notes = await getAllDecrypted('globalNotes', 'noteId');
      const note = nid
        ? (notes || []).find((item) => String(item?.noteId || '').trim() === nid)
        : null;
      if (nid && !note) {
        showToast('Note introuvable');
        return;
      }
      const canManage = note ? canManageGlobalNote(note) : true;
      editingGlobalNoteId = note ? String(note.noteId || '').trim() : '';
      const titleEl = document.getElementById('global-note-modal-title');
      const titleInput = document.getElementById('global-note-title');
      const themeInput = document.getElementById('global-note-theme');
      const tagsInput = document.getElementById('global-note-tags');
      const transverseInput = document.getElementById('global-note-transverse');
      const shareInput = document.getElementById('global-note-share-feed');
      const deleteBtn = document.getElementById('btn-global-note-delete');
      const saveBtn = document.getElementById('btn-global-note-save');
      const digestBtn = document.getElementById('btn-global-note-digest');
      if (titleEl) titleEl.textContent = note ? (canManage ? 'Modifier la note' : 'Lecture de la note') : 'Nouvelle note transverse';
      if (titleInput) titleInput.value = String(note?.title || '');
      if (themeInput) themeInput.value = String(note?.theme || '');
      if (tagsInput) tagsInput.value = stringifyProjectNoteTags(note?.tags || []);
      if (transverseInput) transverseInput.checked = normalizeGlobalNoteVisibility(note?.visibility || 'transverse') === 'transverse';
      if (shareInput) shareInput.checked = note?.shareToGlobalFeed === true;
      if (deleteBtn) deleteBtn.classList.toggle('hidden', !note || !canManage);
      if (saveBtn) saveBtn.classList.toggle('hidden', !canManage);
      if (digestBtn) digestBtn.classList.toggle('hidden', !canManage);
      [titleInput, themeInput, tagsInput, transverseInput, shareInput].forEach((el) => {
        if (el) el.disabled = !canManage;
      });
      setProjectDescriptionEditorContent(
        'global-note-content-editor',
        'global-note-content',
        String(note?.contentHtml || '').trim() || plainTextToRichHtml(String(note?.content || '').trim())
      );
      const quill = projectDescriptionQuillEditors.get('global-note-content-editor');
      if (quill) {
        quill.enable(canManage);
      } else {
        const editor = document.getElementById('global-note-content-editor');
        if (editor) editor.setAttribute('contenteditable', canManage ? 'true' : 'false');
      }
      modal.classList.remove('hidden');
      document.body.classList.add('overflow-hidden');
      requestAnimationFrame(() => titleInput?.focus());
    }

    async function saveGlobalNoteFromEditor() {
      const draft = readGlobalNoteEditorDraft();
      if (!draft.title && !draft.content) {
        showToast('Ajoutez un titre ou un contenu');
        return;
      }
      const nowTs = Date.now();
      const notes = await getAllDecrypted('globalNotes', 'noteId');
      const existing = editingGlobalNoteId
        ? (notes || []).find((item) => String(item?.noteId || '').trim() === String(editingGlobalNoteId || '').trim())
        : null;
      if (existing && !canManageGlobalNote(existing)) {
        showToast('Action non autorisee');
        return;
      }
      const note = {
        ...(existing || {}),
        noteId: String(existing?.noteId || uuidv4()),
        title: draft.title,
        content: draft.content,
        contentHtml: draft.contentHtml,
        tags: draft.tags,
        theme: String(draft.theme || '').trim(),
        visibility: normalizeGlobalNoteVisibility(draft.visibility),
        shareToGlobalFeed: draft.shareToGlobalFeed === true,
        createdBy: String(existing?.createdBy || currentUser?.userId || ''),
        createdByName: String(existing?.createdByName || currentUser?.name || ''),
        createdAt: Number(existing?.createdAt || nowTs) || nowTs,
        updatedAt: nowTs,
        archivedAt: null
      };
      await putEncrypted('globalNotes', note, 'noteId');
      await syncGlobalNoteFeed(note);
      if (workspaceMode === 'global' && globalWorkspaceView === 'feed') {
        await renderGlobalFeed();
      }
      closeGlobalNoteEditor();
      globalNotesFocusNoteId = String(note.noteId || '');
      await renderGlobalNotes();
      showToast(existing ? 'Note mise a jour' : 'Note creee');
    }

    async function deleteGlobalNote(noteId = '') {
      const nid = String(noteId || editingGlobalNoteId || '').trim();
      if (!nid) return;
      const note = await getDecrypted('globalNotes', nid, 'noteId');
      if (!note) return;
      if (!canManageGlobalNote(note)) {
        showToast('Action non autorisee');
        return;
      }
      const noteTitle = String(note.title || '').trim() || 'cette note';
      if (!window.confirm(`Supprimer definitivement "${noteTitle}" ?`)) return;
      await deleteFromStore('globalNotes', nid);
      await removeGlobalNoteFromFeed(nid);
      if (workspaceMode === 'global' && globalWorkspaceView === 'feed') {
        await renderGlobalFeed();
      }
      if (String(editingGlobalNoteId || '') === nid) {
        closeGlobalNoteEditor();
      }
      await renderGlobalNotes();
      showToast('Note supprimee');
    }

    async function toggleGlobalNoteFeedPublish(noteId) {
      const nid = String(noteId || '').trim();
      if (!nid) return;
      const note = await getDecrypted('globalNotes', nid, 'noteId');
      if (!note) return;
      if (!canManageGlobalNote(note)) {
        showToast('Action non autorisee');
        return;
      }
      const next = {
        ...note,
        shareToGlobalFeed: !note.shareToGlobalFeed,
        updatedAt: Date.now()
      };
      await putEncrypted('globalNotes', next, 'noteId');
      await syncGlobalNoteFeed(next);
      if (workspaceMode === 'global' && globalWorkspaceView === 'feed') {
        await renderGlobalFeed();
      }
      await renderGlobalNotes();
      showToast(next.shareToGlobalFeed ? 'Note publiee dans le fil' : 'Note retiree du fil');
    }

    function buildGlobalNoteCardHtml(note, options = {}) {
      const canManage = !!options.canManage;
      const bulkSelectionMode = !!options.bulkSelectionMode;
      const isSelectedForBulkDelete = !!options.isSelectedForBulkDelete;
      const author = String(options.authorName || note.createdByName || fallbackDirectoryName(note.createdBy || '') || 'Auteur');
      const visibility = normalizeGlobalNoteVisibility(note.visibility);
      const theme = String(note.theme || '').trim();
      const tags = Array.isArray(note.tags) ? note.tags.map((tag) => String(tag || '').trim()).filter(Boolean) : [];
      const isFavorite = Number(note.favoriteAt || 0) > 0;
      const previewText = getProjectDescriptionPlainText(String(note.contentHtml || '').trim() || plainTextToRichHtml(String(note.content || '').trim()))
        .replace(/\s+/g, ' ')
        .trim();
      const isFocused = String(globalNotesFocusNoteId || '').trim() === String(note.noteId || '').trim();
      return `
        <article id="global-note-${escapeHtml(note.noteId)}" class="global-note-card rounded-xl border ${isFocused ? 'border-blue-400 shadow-[0_0_0_2px_rgba(59,130,246,0.14)]' : 'border-slate-200'} bg-white p-4 cursor-pointer ${isSelectedForBulkDelete ? 'is-bulk-selected' : ''}" onclick="openGlobalNoteEditor('${escapeHtml(note.noteId)}')">
          <div class="flex items-start justify-between gap-3">
            <div class="min-w-0">
              <div class="flex flex-wrap items-center gap-2">
                ${bulkSelectionMode ? `
                  <label class="taskmda-bulk-checkbox-wrap" onclick="event.stopPropagation()">
                    <input type="checkbox" class="taskmda-bulk-checkbox-input" data-note-id="${escapeHtml(note.noteId)}" ${isSelectedForBulkDelete ? 'checked' : ''} ${canManage ? '' : 'disabled'} onchange="toggleGlobalNoteBulkSelection('${escapeHtml(note.noteId)}', this.checked)" aria-label="Selectionner la note ${escapeHtml(note.title || '')}">
                    <span class="taskmda-bulk-checkbox-label">Selection</span>
                  </label>
                ` : ''}
                <span class="inline-flex text-[10px] px-2 py-1 rounded-full ${visibility === 'transverse' ? 'bg-blue-100 text-blue-700' : 'bg-slate-100 text-slate-700'} font-semibold">${visibility === 'transverse' ? 'Transverse' : 'Privee'}</span>
                ${note.shareToGlobalFeed ? '<span class="inline-flex text-[10px] px-2 py-1 rounded-full bg-indigo-100 text-indigo-700 font-semibold">Dans le fil</span>' : ''}
                ${isFavorite ? '<span class="inline-flex text-[10px] px-2 py-1 rounded-full bg-amber-100 text-amber-700 font-semibold">Favori</span>' : ''}
                ${theme ? `<span class="inline-flex text-[10px] px-2 py-1 rounded-full bg-emerald-100 text-emerald-700 font-semibold">${escapeHtml(theme)}</span>` : ''}
              </div>
              <h4 class="mt-2 text-base font-bold text-slate-800">${escapeHtml(note.title || 'Note sans titre')}</h4>
              <p class="mt-1 text-xs text-slate-500">${escapeHtml(author)} • ${new Date(Number(note.createdAt || Date.now())).toLocaleString('fr-FR')}</p>
            </div>
            ${canManage ? `
              <div class="flex items-center gap-1" onclick="event.stopPropagation();">
                <button type="button" class="workspace-action-inline" data-action-kind="edit" data-action-label="Modifier la note" onclick="openGlobalNoteEditor('${escapeHtml(note.noteId)}')">Editer</button>
                <button type="button" class="workspace-action-inline" data-action-kind="manage" data-action-label="${isFavorite ? 'Retirer des favoris' : 'Ajouter aux favoris'}" onclick="toggleGlobalNoteFavorite('${escapeHtml(note.noteId)}')">${isFavorite ? 'Defavoriser' : 'Favori'}</button>
                <button type="button" class="workspace-action-inline" data-action-kind="notify" data-action-label="Publier dans le fil" onclick="toggleGlobalNoteFeedPublish('${escapeHtml(note.noteId)}')">${note.shareToGlobalFeed ? 'Retirer fil' : 'Publier fil'}</button>
                <div class="relative inline-block">
                  <button type="button" class="workspace-action-inline" data-action-kind="export" data-action-label="Menu d'export" onclick="toggleGlobalNoteExportMenu('${escapeHtml(note.noteId)}', event)" aria-haspopup="true" aria-expanded="false" id="export-menu-btn-${escapeHtml(note.noteId)}">
                    Exporter
                    <span class="material-symbols-outlined" style="font-size: 14px; margin-left: 2px; vertical-align: middle;">expand_more</span>
                  </button>
                  <div id="export-menu-${escapeHtml(note.noteId)}" class="hidden absolute right-0 mt-1 w-44 bg-white rounded-lg shadow-lg border border-slate-200 z-50 overflow-hidden" role="menu" onclick="event.stopPropagation();">
                    <button type="button" class="export-menu-item w-full text-left px-3 py-2 text-sm hover:bg-slate-50 flex items-center gap-2" onclick="exportGlobalNote('${escapeHtml(note.noteId)}', 'html'); closeGlobalNoteExportMenu('${escapeHtml(note.noteId)}');" role="menuitem">
                      <span class="material-symbols-outlined" style="font-size: 16px;">code</span>
                      Export HTML
                    </button>
                    <button type="button" class="export-menu-item w-full text-left px-3 py-2 text-sm hover:bg-slate-50 flex items-center gap-2" onclick="exportGlobalNoteAsPdf('${escapeHtml(note.noteId)}'); closeGlobalNoteExportMenu('${escapeHtml(note.noteId)}');" role="menuitem">
                      <span class="material-symbols-outlined" style="font-size: 16px;">picture_as_pdf</span>
                      Export PDF
                    </button>
                    <button type="button" class="export-menu-item w-full text-left px-3 py-2 text-sm hover:bg-slate-50 flex items-center gap-2" onclick="exportGlobalNoteAsDocx('${escapeHtml(note.noteId)}'); closeGlobalNoteExportMenu('${escapeHtml(note.noteId)}');" role="menuitem">
                      <span class="material-symbols-outlined" style="font-size: 16px;">description</span>
                      Export DOCX
                    </button>
                    <button type="button" class="export-menu-item w-full text-left px-3 py-2 text-sm hover:bg-slate-50 flex items-center gap-2" onclick="exportGlobalNote('${escapeHtml(note.noteId)}', 'txt'); closeGlobalNoteExportMenu('${escapeHtml(note.noteId)}');" role="menuitem">
                      <span class="material-symbols-outlined" style="font-size: 16px;">text_snippet</span>
                      Export TXT
                    </button>
                  </div>
                </div>
                <button type="button" class="workspace-action-inline" data-action-kind="danger" data-action-label="Supprimer la note" onclick="deleteGlobalNote('${escapeHtml(note.noteId)}')">Supprimer</button>
              </div>
            ` : ''}
          </div>
          ${tags.length ? `<div class="mt-3 flex flex-wrap gap-1">${tags.map((tag) => `<span class="inline-flex text-[10px] px-2 py-1 rounded-full bg-slate-100 text-slate-700 font-semibold">#${escapeHtml(tag)}</span>`).join('')}</div>` : ''}
          <p class="mt-3 text-sm text-slate-600">${escapeHtml(previewText.length > 280 ? `${previewText.slice(0, 280)}...` : (previewText || 'Aucun contenu.'))}</p>
        </article>
      `;
    }

    async function renderGlobalNotes() {
      const host = document.getElementById('global-notes-list');
      const countEl = document.getElementById('global-notes-count');
      const paginationContainer = document.getElementById('global-notes-pagination');
      if (!host) return;
      const allNotesRaw = await getAllDecrypted('globalNotes', 'noteId');
      const notes = (Array.isArray(allNotesRaw) ? allNotesRaw : []).filter((note) => !Number(note?.archivedAt || 0));
      const me = String(currentUser?.userId || '').trim();
      const queryNeedle = normalizeSearch(globalNotesSearchQuery);
      const filtered = notes
        .filter((note) => {
          const visibility = normalizeGlobalNoteVisibility(note.visibility);
          if (visibility === 'private' && !isAppAdmin(currentUser?.userId) && String(note.createdBy || '').trim() !== me) return false;
          if (globalNotesScopeFilter === 'private' && visibility !== 'private') return false;
          if (globalNotesScopeFilter === 'transverse' && visibility !== 'transverse') return false;
          if (globalNotesTabMode === 'mine' && String(note.createdBy || '').trim() !== me) return false;
          if (globalNotesTabMode === 'favorites' && Number(note.favoriteAt || 0) <= 0) return false;
          if (globalNotesTabMode === 'private' && visibility !== 'private') return false;
          if (globalNotesTabMode === 'transverse' && visibility !== 'transverse') return false;
          if (globalNotesTabMode === 'published' && note.shareToGlobalFeed !== true) return false;
          if (!queryNeedle) return true;
          const blob = normalizeSearch([
            note.title,
            note.content,
            note.theme,
            ...(Array.isArray(note.tags) ? note.tags : [])
          ].join(' '));
          return blob.includes(queryNeedle);
        })
        .sort((a, b) => {
          if (globalNotesSortMode === 'oldest') return Number(a.updatedAt || a.createdAt || 0) - Number(b.updatedAt || b.createdAt || 0);
          if (globalNotesSortMode === 'favorites') {
            const af = Number(a.favoriteAt || 0);
            const bf = Number(b.favoriteAt || 0);
            if ((af > 0) !== (bf > 0)) return bf - af;
            if (af !== bf) return bf - af;
            return Number(b.updatedAt || b.createdAt || 0) - Number(a.updatedAt || a.createdAt || 0);
          }
          if (globalNotesSortMode === 'alpha') return String(a.title || '').localeCompare(String(b.title || ''), 'fr');
          return Number(b.updatedAt || b.createdAt || 0) - Number(a.updatedAt || a.createdAt || 0);
        });
      if (countEl) {
        const n = filtered.length;
        const selected = selectedGlobalNoteIdsForBulkDelete.size;
        countEl.textContent = globalNotesBulkSelectionMode
          ? `${n} note${n > 1 ? 's' : ''} • ${selected} selectionnee${selected > 1 ? 's' : ''}`
          : `${n} note${n > 1 ? 's' : ''}`;
      }
      if (!filtered.length) {
        host.innerHTML = `
          <div class="workspace-empty-state">
            <span class="workspace-empty-icon material-symbols-outlined" aria-hidden="true">sticky_note_2</span>
            <p class="workspace-empty-title">Aucune note pour ces criteres</p>
            <p class="workspace-empty-text">Essayez un autre filtre ou creez une nouvelle note.</p>
          </div>
        `;
        if (paginationContainer) paginationContainer.innerHTML = '';
      } else {
        const pagination = paginateItems(filtered, globalNotesPage, paginationConfig.globalNotesPerPage);
        globalNotesPage = pagination.currentPage;
        host.innerHTML = pagination.pageItems.map((note) => {
          const identity = resolveKnownUserIdentity(String(note.createdBy || ''), String(note.createdByName || fallbackDirectoryName(note.createdBy || '')));
          return buildGlobalNoteCardHtml(note, {
            canManage: canManageGlobalNote(note),
            authorName: identity?.name || note.createdByName || fallbackDirectoryName(note.createdBy || ''),
            bulkSelectionMode: globalNotesBulkSelectionMode,
            isSelectedForBulkDelete: selectedGlobalNoteIdsForBulkDelete.has(String(note.noteId || '').trim())
          });
        }).join('');
        renderPagination('global-notes-pagination', pagination, 'setGlobalNotesPage', 'notes');
      }
      const tabs = {
        all: document.getElementById('global-notes-tab-all'),
        mine: document.getElementById('global-notes-tab-mine'),
        favorites: document.getElementById('global-notes-tab-favorites'),
        private: document.getElementById('global-notes-tab-private'),
        transverse: document.getElementById('global-notes-tab-transverse'),
        published: document.getElementById('global-notes-tab-published')
      };
      Object.entries(tabs).forEach(([key, btn]) => {
        if (!btn) return;
        btn.classList.toggle('view-tab-active', key === globalNotesTabMode);
      });
      if (globalNotesFocusNoteId) {
        const focusId = String(globalNotesFocusNoteId || '').trim();
        globalNotesFocusNoteId = '';
        setTimeout(() => {
          document.getElementById(`global-note-${focusId}`)?.scrollIntoView?.({ behavior: 'smooth', block: 'center' });
        }, 40);
      }
      updateGlobalNotesBulkDeleteUi();
    }

    async function resolveUserRowsByIds(userIds = []) {
      const ids = Array.from(new Set((userIds || []).map(id => String(id || '').trim()).filter(Boolean)));
      if (ids.length === 0) return [];
      const users = await getAllDecrypted('users', 'userId');
      const usersById = new Map((users || []).map(user => [String(user.userId || ''), user]));
      const directory = await getAllDecrypted('directoryUsers', 'userId');
      const directoryById = new Map((directory || []).map(user => [String(user.userId || ''), user]));
      return ids.map((userId) => {
        const user = usersById.get(userId) || directoryById.get(userId);
        return {
          userId,
          displayName: String(user?.name || '').trim() || fallbackDirectoryName(userId)
        };
      });
    }

    async function resolveTaskSelectedGroupContext(state, rawGroupValue = '') {
      const rawValue = String(rawGroupValue || '').trim();
      if (!state?.project || !rawValue) return null;
      if (rawValue.startsWith('global:')) {
        const groupKey = rawValue.slice('global:'.length);
        const globalGroup = (globalGroupCatalog || []).find(group => String(group.groupKey || '') === groupKey);
        if (!globalGroup) return null;
        return {
          scope: 'global',
          groupKey,
          groupId: null,
          groupName: String(globalGroup.name || '').trim(),
          groupDescription: String(globalGroup.description || '').trim(),
          memberUserIds: Array.from(new Set((globalGroup.memberUserIds || []).map(id => String(id || '').trim()).filter(Boolean)))
        };
      }
      const projectGroup = (state.groups || []).find(group => group.groupId === rawValue);
      const groupName = String(projectGroup?.name || '').trim();
      const linkedUserGroup = (state.userGroups || []).find(group =>
        group.groupId === rawValue || (groupName && normalizeSearch(group.name) === normalizeSearch(groupName))
      );
      return {
        scope: 'project',
        groupKey: normalizeCatalogKey(groupName),
        groupId: rawValue,
        groupName,
        groupDescription: String(projectGroup?.description || '').trim(),
        memberUserIds: Array.from(new Set((linkedUserGroup?.memberUserIds || []).map(id => String(id || '').trim()).filter(Boolean)))
      };
    }

    async function refreshTaskGroupSelectionPreview(state, selectedUserIds = null) {
      const groupSelect = document.getElementById('task-group');
      const pendingBox = document.getElementById('task-group-pending-members');
      const assigneeSelect = document.getElementById('task-assignee');
      if (!groupSelect || !assigneeSelect) return;
      if (!state?.project || standaloneTaskMode) {
        taskPendingGroupMemberUserIds = [];
        if (pendingBox) {
          pendingBox.classList.add('hidden');
          pendingBox.innerHTML = '';
        }
        await refreshTaskAssigneeOptionsMulti(state, selectedUserIds || []);
        return;
      }

      const currentlySelected = Array.isArray(selectedUserIds)
        ? selectedUserIds
        : Array.from(assigneeSelect.selectedOptions || []).map(opt => String(opt.value || '').trim()).filter(Boolean);
      const groupContext = await resolveTaskSelectedGroupContext(state, groupSelect.value);
      if (!groupContext || !groupContext.groupName) {
        taskPendingGroupMemberUserIds = [];
        if (pendingBox) {
          pendingBox.classList.add('hidden');
          pendingBox.innerHTML = '';
        }
        await refreshTaskAssigneeOptionsMulti(state, currentlySelected);
        return;
      }

      const groupMemberIds = Array.from(new Set((groupContext.memberUserIds || []).filter(Boolean)));
      const memberIdsSet = new Set((state.members || []).map(member => String(member.userId || '').trim()).filter(Boolean));
      const pendingMemberIds = groupMemberIds.filter(userId => !memberIdsSet.has(userId));
      taskPendingGroupMemberUserIds = pendingMemberIds;
      const pendingMembers = await resolveUserRowsByIds(pendingMemberIds);
      const mergedSelected = Array.from(new Set([...currentlySelected, ...groupMemberIds]));
      await refreshTaskAssigneeOptionsMulti(state, mergedSelected, pendingMembers);

      if (!pendingBox) return;
      if (pendingMembers.length === 0) {
        pendingBox.classList.add('hidden');
        pendingBox.innerHTML = '';
        return;
      }
      pendingBox.classList.remove('hidden');
      const names = pendingMembers.map(member => escapeHtml(member.displayName)).join(', ');
      pendingBox.innerHTML = `<strong>En attente de validation</strong>: ${escapeHtml(groupContext.groupName)} ajoutera ${pendingMembers.length} membre(s) au projet lors de l'enregistrement de la tache. <span class="font-medium">${names}</span>`;
    }

    async function ensureTaskGroupAssociationInProject(state, groupContext) {
      if (!state?.project || !groupContext?.groupName) {
        return { state, groupId: null, groupName: null, addedMembersCount: 0 };
      }

      let latestState = state;
      let groupId = groupContext.groupId || null;
      const uniqueMemberIds = Array.from(new Set((groupContext.memberUserIds || []).map(id => String(id || '').trim()).filter(Boolean)));

      if (groupContext.scope === 'global') {
        let existingProjectGroup = (latestState.groups || []).find(group =>
          normalizeCatalogKey(group.name) === normalizeCatalogKey(groupContext.groupName)
        );
        if (!existingProjectGroup) {
          if (!canManageProjectCollaboration(latestState)) {
            throw new Error('Seuls Propriétaire/Manager peuvent associer un groupe global au projet.');
          }
          const createdGroupId = uuidv4();
          const createGroupEvent = createEvent(
            EventTypes.CREATE_GROUP,
            currentProjectId,
            currentUser.userId,
            { groupId: createdGroupId, name: groupContext.groupName, description: groupContext.groupDescription || '' }
          );
          await publishEvent(createGroupEvent);
          if (sharedFolderHandle) void syncProjectEventsToSharedSpace(currentProjectId, [createGroupEvent]);
          latestState = await getProjectState(currentProjectId, { ignoreAccessCheck: true });
          existingProjectGroup = (latestState?.groups || []).find(group => group.groupId === createdGroupId)
            || (latestState?.groups || []).find(group => normalizeCatalogKey(group.name) === normalizeCatalogKey(groupContext.groupName));
        }
        groupId = existingProjectGroup?.groupId || groupId;
      }

      if (!groupId) {
        return { state: latestState, groupId: null, groupName: groupContext.groupName, addedMembersCount: 0 };
      }

      if (uniqueMemberIds.length > 0) {
        const linkedUserGroup = (latestState.userGroups || []).find(group =>
          group.groupId === groupId || normalizeCatalogKey(group.name) === normalizeCatalogKey(groupContext.groupName)
        );
        const linkedMemberIds = Array.from(new Set((linkedUserGroup?.memberUserIds || []).map(id => String(id || '').trim()).filter(Boolean)));
        const mergedLinkedMemberIds = Array.from(new Set([...linkedMemberIds, ...uniqueMemberIds]));
        if (!linkedUserGroup) {
          const createUserGroupEvent = createEvent(
            EventTypes.CREATE_USER_GROUP,
            currentProjectId,
            currentUser.userId,
            { groupId, name: groupContext.groupName, memberUserIds: mergedLinkedMemberIds }
          );
          await publishEvent(createUserGroupEvent);
          if (sharedFolderHandle) void syncProjectEventsToSharedSpace(currentProjectId, [createUserGroupEvent]);
        } else if (mergedLinkedMemberIds.length !== linkedMemberIds.length) {
          const updateUserGroupEvent = createEvent(
            EventTypes.UPDATE_USER_GROUP,
            currentProjectId,
            currentUser.userId,
            { groupId: linkedUserGroup.groupId, changes: { memberUserIds: mergedLinkedMemberIds, name: groupContext.groupName } }
          );
          await publishEvent(updateUserGroupEvent);
          if (sharedFolderHandle) void syncProjectEventsToSharedSpace(currentProjectId, [updateUserGroupEvent]);
        }
        latestState = await getProjectState(currentProjectId, { ignoreAccessCheck: true });
      }

      const existingMemberIds = new Set((latestState.members || []).map(member => String(member.userId || '').trim()).filter(Boolean));
      const membersToAdd = uniqueMemberIds.filter(userId => !existingMemberIds.has(userId));
      if (membersToAdd.length > 0) {
        if (!canManageProjectCollaboration(latestState)) {
          throw new Error('Le groupe contient des membres hors projet. Droits Propriétaire/Manager requis pour les ajouter.');
        }
        const memberRows = await resolveUserRowsByIds(membersToAdd);
        const displayById = new Map(memberRows.map(row => [row.userId, row.displayName]));
        for (const userId of membersToAdd) {
          const addMemberEvent = createEvent(
            EventTypes.ADD_MEMBER,
            currentProjectId,
            currentUser.userId,
            {
              userId,
              role: 'member',
              displayName: displayById.get(userId) || fallbackDirectoryName(userId)
            }
          );
          await publishEvent(addMemberEvent);
          if (sharedFolderHandle) void syncProjectEventsToSharedSpace(currentProjectId, [addMemberEvent]);
        }
        latestState = await getProjectState(currentProjectId, { ignoreAccessCheck: true });
      }

      return {
        state: latestState,
        groupId,
        groupName: groupContext.groupName,
        addedMembersCount: membersToAdd.length
      };
    }

    async function renderMemberSelectOptions(state, selectId) {
      const select = document.getElementById(selectId);
      if (!select) return;
      const members = await getProjectMembersResolved(state);
      select.innerHTML = members.map(member => `
        <option value="${escapeHtml(member.userId)}">${escapeHtml(member.displayNameResolved)}</option>
      `).join('');
    }

    async function renderUserGroupMemberSelect(state) {
      await renderMemberSelectOptions(state, 'user-group-members-input');
    }

    async function renderProjectGroupMemberSelect(state) {
      await renderMemberSelectOptions(state, 'group-members-input');
    }

    async function renderProjectUserGroups(state) {
      const list = document.getElementById('project-user-groups-list');
      const createBtn = document.getElementById('btn-create-user-group');
      const updateBtn = document.getElementById('btn-update-user-group');
      const membersSelect = document.getElementById('user-group-members-input');
      if (!list || !createBtn || !updateBtn || !membersSelect) return;

      const canManage = canManageProjectCollaboration(state);
      createBtn.disabled = !canManage;
      createBtn.classList.toggle('opacity-50', !canManage);
      updateBtn.disabled = !canManage;
      updateBtn.classList.toggle('opacity-50', !canManage);
      membersSelect.disabled = !canManage;

      await renderUserGroupMemberSelect(state);
      const members = await getProjectMembersResolved(state);
      const byId = new Map(members.map(m => [m.userId, m.displayNameResolved]));
      const userGroups = state?.userGroups || [];

      if (userGroups.length === 0) {
        list.innerHTML = `
          <div class="empty-state-card">
            <p class="empty-state-title">Aucun groupe utilisateurs</p>
            <p class="empty-state-text">Regroupez des membres pour assigner plus vite les tâches collaboratives.</p>
            ${canManage ? '<button class="empty-state-cta" onclick="focusElementById(\'user-group-name-input\')">Créer un groupe utilisateurs</button>' : ''}
          </div>
        `;
        selectedUserGroupId = null;
        return;
      }

      if (!selectedUserGroupId || !userGroups.find(g => g.groupId === selectedUserGroupId)) {
        selectedUserGroupId = userGroups[0].groupId;
      }

      list.innerHTML = userGroups.map(group => {
        const active = group.groupId === selectedUserGroupId;
        const memberNames = (group.memberUserIds || []).map(id => byId.get(id) || fallbackDirectoryName(id));
        return `
          <div class="rounded-lg border ${active ? 'border-primary bg-blue-50' : 'border-slate-200 bg-white'} p-3">
            <div class="flex items-start justify-between gap-2">
              <div>
                <p class="text-sm font-semibold text-slate-800">${escapeHtml(group.name || 'Groupe')}</p>
                <p class="text-xs text-slate-500 mt-1">${escapeHtml(memberNames.join(', ') || 'Aucun membre')}</p>
              </div>
              <div class="flex items-center gap-2 text-xs">
                <button onclick="selectUserGroup('${group.groupId}')" class="task-action-btn task-action-btn-subtle" data-action-kind="open">Selectionner</button>
                ${canManage ? `<button onclick="deleteUserGroup('${group.groupId}')" class="task-action-btn task-action-btn-danger" data-action-kind="danger">Supprimer</button>` : ''}
              </div>
            </div>
          </div>
        `;
      }).join('');

      const selected = userGroups.find(g => g.groupId === selectedUserGroupId);
      const selectedIds = new Set(selected?.memberUserIds || []);
      Array.from(membersSelect.options || []).forEach(opt => {
        opt.selected = selectedIds.has(opt.value);
      });
    }

    async function renderProjectMembers(state) {
      const container = document.getElementById('project-members-list');
      const addBtn = document.getElementById('btn-add-member');
      const nameInput = document.getElementById('member-name-input');
      const roleInput = document.getElementById('member-role-input');
      if (!container || !addBtn || !nameInput || !roleInput) return;

      const members = await getProjectMembersResolved(state);
      const canManage = canManageProjectCollaboration(state);
      const myRole = normalizeProjectRole(getMyProjectRole(state));
      renderProjectRoleSelectors(state);

      addBtn.disabled = !canManage;
      addBtn.classList.toggle('opacity-50', !canManage);
      nameInput.disabled = !canManage;
      roleInput.disabled = !canManage;
      await renderMemberDirectoryAutocomplete(state);

      if (members.length === 0) {
        container.innerHTML = '<p class="text-sm text-slate-500">Aucun membre dans ce projet.</p>';
        return;
      }

      container.innerHTML = members.map(member => {
        const displayName = escapeHtml(member.displayNameResolved || fallbackDirectoryName(member.userId));
        const normalizedRole = normalizeProjectRole(member.role);
        const role = escapeHtml(getProjectRoleLabel(member.role));
        const canRemoveMember = canManage
          && member.userId !== currentUser?.userId
          && (myRole === 'owner' || normalizedRole === 'member');
        const removeBtn = canRemoveMember
          ? `<button onclick="removeProjectMember('${escapeHtml(member.userId)}')" class="task-action-btn task-action-btn-danger" data-action-kind="danger">Retirer</button>`
          : '';
        return `
          <div class="flex items-center justify-between gap-3 rounded-lg border border-slate-200 px-3 py-2 bg-slate-50">
            <div class="min-w-0">
              <p class="text-sm font-semibold text-slate-800 truncate">${displayName}</p>
              <p class="text-xs text-slate-500">Rôle: ${role}</p>
            </div>
            ${removeBtn}
          </div>
        `;
      }).join('');
    }

    function renderProjectPermissionMatrix(state) {
      const tbody = document.getElementById('project-permissions-matrix');
      const roleBadge = document.getElementById('project-permission-role-badge');
      const summary = document.getElementById('project-permission-summary');
      const details = document.getElementById('project-permissions-details');
      const toggle = document.getElementById('btn-toggle-permissions-details');
      if (!tbody) return;

      const roleRaw = getMyProjectRole(state);
      const role = normalizeProjectRole(roleRaw);
      const roleLabel = roleRaw ? getProjectRoleLabel(roleRaw) : 'Aucun';
      if (roleBadge) {
        roleBadge.textContent = `Role: ${roleLabel}`;
        roleBadge.className = `text-xs font-semibold px-2 py-1 rounded-full ${
          role === 'owner'
            ? 'bg-amber-100 text-amber-800'
            : role === 'manager'
              ? 'bg-blue-100 text-blue-800'
              : role === 'member'
                ? 'bg-emerald-100 text-emerald-800'
                : 'bg-slate-100 text-slate-700'
        }`;
      }

      const rows = [
        { action: 'Lire le projet (taches, docs, discussion)', owner: true, manager: true, member: true },
        { action: 'Modifier les infos projet', owner: true, manager: true, member: false },
        { action: 'Supprimer le projet', owner: true, manager: false, member: false },
        { action: 'Creer une tache', owner: true, manager: true, member: true },
        { action: 'Editer/supprimer ses taches', owner: true, manager: true, member: true },
        { action: 'Editer/supprimer toutes les taches', owner: true, manager: true, member: false },
        { action: 'Changer statut de toute tache', owner: true, manager: true, member: false },
        { action: 'Envoyer un message', owner: true, manager: true, member: true },
        { action: 'Editer/supprimer tous les messages', owner: true, manager: true, member: false },
        { action: 'Consulter le journal activite', owner: true, manager: true, member: false },
        { action: 'Invitations / Groupes sur-mesure (avec membres) / Thematiques', owner: true, manager: true, member: false },
        { action: 'Gerer les membres du projet*', owner: true, manager: true, member: false }
      ];

      const roleRules = {
        owner: { label: getProjectRoleLabel('owner'), description: 'Pilotage complet du projet', allowed: rows.filter(r => r.owner).length, total: rows.length, chip: 'bg-amber-100 text-amber-800' },
        manager: { label: 'Manager', description: 'Gestion opérationnelle avancée', allowed: rows.filter(r => r.manager).length, total: rows.length, chip: 'bg-blue-100 text-blue-800' },
        member: { label: 'Membre', description: 'Exécution et contribution', allowed: rows.filter(r => r.member).length, total: rows.length, chip: 'bg-emerald-100 text-emerald-800' }
      };
      if (summary) {
        summary.innerHTML = ['owner', 'manager', 'member'].map((key) => {
          const rr = roleRules[key];
          const active = role === key ? ' ring-2 ring-indigo-200' : '';
          return `
            <div class="rounded-xl border border-slate-200 bg-slate-50 px-3 py-2${active}">
              <div class="flex items-center justify-between gap-2">
                <p class="text-sm font-semibold text-slate-800">${rr.label}</p>
                <span class="text-[11px] px-2 py-0.5 rounded-full font-semibold ${rr.chip}">${rr.allowed}/${rr.total}</span>
              </div>
              <p class="text-xs text-slate-500 mt-1">${rr.description}</p>
            </div>
          `;
        }).join('');
      }

      const renderCell = (allowed, isCurrentCol) => {
        const base = 'py-2 px-2 border-b border-slate-100';
        const current = isCurrentCol ? ' bg-indigo-50' : '';
        if (allowed) {
          return `<td class="${base}${current}"><span class="inline-flex items-center text-emerald-700 font-semibold" title="Autorisé"><span class="material-symbols-outlined text-base">check_circle</span></span></td>`;
        }
        return `<td class="${base}${current}"><span class="inline-flex items-center text-slate-400 font-semibold" title="Non autorisé"><span class="material-symbols-outlined text-base">remove_circle</span></span></td>`;
      };

      tbody.innerHTML = rows.map((row) => `
        <tr>
          <td class="py-2 pr-3 border-b border-slate-100 text-slate-700">${escapeHtml(row.action)}</td>
          ${renderCell(row.owner, role === 'owner')}
          ${renderCell(row.manager, role === 'manager')}
          ${renderCell(row.member, role === 'member')}
        </tr>
      `).join('');

      if (details) {
        details.classList.toggle('hidden', !projectPermissionDetailsOpen);
      }
      if (toggle) {
        toggle.textContent = projectPermissionDetailsOpen ? 'Masquer le détail des droits' : 'Voir le détail des droits';
      }
    }

    function getMyProjectRole(state = currentProjectState) {
      if (!state?.project || !currentUser?.userId) return null;
      const member = (state?.members || []).find(m => m.userId === currentUser?.userId);
      if (member?.role) return member.role;
      if (state.project.createdBy && state.project.createdBy === currentUser.userId) return 'owner';
      return null;
    }

    function normalizeProjectRole(role) {
      return getProjectRoleMeta(role).baseRole;
    }

    function hasProjectRole(state = currentProjectState) {
      return Boolean(getMyProjectRole(state));
    }

    function isProjectOwner(state = currentProjectState) {
      return normalizeProjectRole(getMyProjectRole(state)) === 'owner';
    }

    function isProjectManagerOrOwner(state = currentProjectState) {
      const role = normalizeProjectRole(getMyProjectRole(state));
      return role === 'owner' || role === 'manager';
    }

    function canEditProjectMeta(state = currentProjectState) {
      return isProjectManagerOrOwner(state);
    }

    function canDeleteProjectMeta(state = currentProjectState) {
      return isProjectOwner(state);
    }

    function getAssignableProjectRolesForUser(state = currentProjectState) {
      const myRole = normalizeProjectRole(getMyProjectRole(state));
      const catalog = getProjectRoleCatalog();
      if (myRole === 'owner') return catalog;
      if (myRole === 'manager') return catalog.filter(item => normalizeProjectRoleBase(item.baseRole) === 'member');
      return [];
    }

    function renderProjectRoleSelectors(state = currentProjectState) {
      const roleInputs = [
        document.getElementById('member-role-input'),
        document.getElementById('invite-role-input')
      ].filter(Boolean);
      if (roleInputs.length === 0) return;
      const options = getAssignableProjectRolesForUser(state);
      roleInputs.forEach((input) => {
        const previous = String(input.value || '').trim();
        input.innerHTML = options.length === 0
          ? ''
          : options.map((item) => {
            const baseLabel = getBaseProjectRoleLabel(item.baseRole);
            const label = item.isSystem ? item.label : `${item.label} (${baseLabel})`;
            return `<option value="${escapeHtml(item.roleKey)}">${escapeHtml(label)}</option>`;
          }).join('');
        if (options.length === 0) {
          input.disabled = true;
          return;
        }
        input.disabled = false;
        const hasPrev = options.some(item => item.roleKey === previous);
        input.value = hasPrev ? previous : options[0].roleKey;
      });
    }

    function canCreateTaskInProject(state = currentProjectState) {
      return hasProjectRole(state);
    }

    function canEditTaskInProject(task, state = currentProjectState) {
      if (!task) return false;
      if (isProjectManagerOrOwner(state)) return true;
      return task.createdBy === currentUser?.userId;
    }

    function canChangeTaskStatus(task, state = currentProjectState) {
      if (!task) return false;
      if (canEditTaskInProject(task, state)) return true;
      const assigneeEntries = getTaskAssigneeEntries(task, state);
      if (assigneeEntries.some(a => a.userId && a.userId === currentUser?.userId)) return true;
      const me = normalizeSearch(currentUser?.name || '');
      return assigneeEntries.some(a => normalizeSearch(a.name || '') === me);
    }

    function canDeleteTaskInProject(task, state = currentProjectState) {
      if (!task) return false;
      if (isProjectManagerOrOwner(state)) return true;
      return task.createdBy === currentUser?.userId;
    }

    function canSendProjectMessage(state = currentProjectState) {
      return hasProjectRole(state);
    }

    function canEditProjectMessage(msg, state = currentProjectState) {
      if (!msg) return false;
      if (isProjectManagerOrOwner(state)) return true;
      return msg.author === currentUser?.userId;
    }

    function canDeleteProjectMessage(msg, state = currentProjectState) {
      return canEditProjectMessage(msg, state);
    }

    function canReadProjectActivity(state = currentProjectState) {
      return isProjectManagerOrOwner(state);
    }

    function canManageProjectCollaboration(state = currentProjectState) {
      return isProjectManagerOrOwner(state);
    }

    function getGroupNameById(state, groupId) {
      if (!groupId) return '';
      const group = (state?.groups || []).find(g => g.groupId === groupId);
      return group?.name || '';
    }

    function getTaskGroupName(task, state = currentProjectState) {
      if (!task) return '';
      if (task.groupName) return String(task.groupName);
      return getGroupNameById(state, task.groupId);
    }

    function getTaskFeature(task, state = currentProjectState) {
      if (!task || !state) return null;
      const featureId = String(task.featureId || '').trim();
      if (!featureId) return null;
      const feature = (state.features || []).find((item) => String(item?.featureId || '').trim() === featureId);
      if (!feature) return null;
      if (String(feature.status || '').trim().toLowerCase() === 'archived') return null;
      return feature;
    }

    function getTaskFeatureName(task, state = currentProjectState) {
      const feature = getTaskFeature(task, state);
      return feature ? String(feature.name || '').trim() : '';
    }

    function getTaskEpic(task, state = currentProjectState) {
      const feature = getTaskFeature(task, state);
      if (!feature || !state) return null;
      const epicId = String(feature.epicId || '').trim();
      if (!epicId) return null;
      const epic = (state.epics || []).find((item) => String(item?.epicId || '').trim() === epicId);
      if (!epic) return null;
      if (String(epic.status || '').trim().toLowerCase() === 'archived') return null;
      return epic;
    }

    function getTaskEpicName(task, state = currentProjectState) {
      const epic = getTaskEpic(task, state);
      return epic ? String(epic.name || '').trim() : '';
    }

    function buildTaskHierarchyChipsHtml(task, state = currentProjectState) {
      const epicName = getTaskEpicName(task, state);
      const featureName = getTaskFeatureName(task, state);
      return [
        epicName ? `<span class="task-epic-chip">${escapeHtml(epicName)}</span>` : '',
        featureName ? `<span class="task-feature-chip">${escapeHtml(featureName)}</span>` : ''
      ].join('');
    }

    function getTaskAssigneeEntries(task, state = currentProjectState) {
      if (!task) return [];
      const memberMap = new Map((state?.members || []).map(m => [m.userId, m.displayName || '']));
      if (Array.isArray(task.assignees) && task.assignees.length > 0) {
        const dedup = [];
        const seen = new Set();
        task.assignees.forEach((entry) => {
          const agentId = String(entry?.agentId || '').trim();
          const userId = String(entry?.userId || '').trim();
          const fallbackName = userId ? (memberMap.get(userId) || '') : '';
          const resolvedKnownName = userId ? resolveKnownUserIdentity(userId, String(entry?.name || fallbackName || '').trim()).name : '';
          const name = String(resolvedKnownName || entry?.name || fallbackName || (agentId ? `Agent ${agentId.slice(0, 8)}` : '')).trim();
          const email = String(entry?.email || '').trim().toLowerCase();
          const key = `${agentId}|${userId}|${normalizeSearch(name)}|${email}`;
          if (!agentId && !userId && !name) return;
          if (seen.has(key)) return;
          seen.add(key);
          dedup.push({ agentId: agentId || null, userId: userId || null, name, email });
        });
        return dedup;
      }
      const member = (state?.members || []).find(m => m.userId === task.assigneeUserId);
      const legacyName = task.assignee || member?.displayName || '';
      if (!task.assigneeUserId && !legacyName) return [];
      const parsedLegacy = parseAssigneeToken(legacyName);
      const resolvedLegacyName = task.assigneeUserId
        ? resolveKnownUserIdentity(task.assigneeUserId, String(parsedLegacy?.name || legacyName || '').trim()).name
        : String(parsedLegacy?.name || legacyName || '').trim();
      return [{
        userId: task.assigneeUserId || null,
        name: String(resolvedLegacyName || '').trim(),
        email: String(parsedLegacy?.email || '').trim().toLowerCase()
      }];
    }

    function getTaskAssigneeNames(task, state = currentProjectState) {
      return getTaskAssigneeEntries(task, state)
        .map(a => String(a.name || '').trim())
        .filter(Boolean);
    }

    function getTaskAssigneeName(task, state = currentProjectState, firstOnly = false) {
      const names = getTaskAssigneeNames(task, state);
      if (names.length === 0) return '';
      return firstOnly ? names[0] : names.join(', ');
    }

    function getTaskAssigneeAllocationKind(task, state = currentProjectState) {
      const entries = getTaskAssigneeEntries(task, state);
      let hasAgent = false;
      let hasMember = false;
      entries.forEach((entry) => {
        if (String(entry?.agentId || '').trim()) {
          hasAgent = true;
          return;
        }
        if (String(entry?.userId || '').trim()) {
          hasMember = true;
        }
      });
      if (hasAgent && hasMember) return 'mixed';
      if (hasAgent) return 'agent';
      if (hasMember) return 'member';
      return 'none';
    }

    function buildTaskAssigneeKindBadgeHtml(task, state = currentProjectState, compact = false) {
      const kind = getTaskAssigneeAllocationKind(task, state);
      if (kind === 'none') return '';
      const labels = {
        member: 'Membre',
        agent: 'Agent',
        mixed: 'Mixte'
      };
      const cssKind = kind === 'member' ? 'member' : kind === 'agent' ? 'agent' : 'mixed';
      const compactClass = compact ? ' task-assignee-kind-chip-compact' : '';
      return `<span class="task-assignee-kind-chip task-assignee-kind-${cssKind}${compactClass}">${labels[kind] || 'Responsable'}</span>`;
    }

    function buildTaskAssigneeInlineHtml(task, state = currentProjectState, fallback = 'Aucun responsable') {
      const assigneeName = getTaskAssigneeName(task, state) || fallback;
      const badge = buildTaskAssigneeKindBadgeHtml(task, state, true);
      return `<span>${escapeHtml(assigneeName)}</span>${badge}`;
    }

    function matchesTaskAssigneeKindFilter(task, state, rawFilter = 'all') {
      const filter = String(rawFilter || 'all').trim();
      if (!filter || filter === 'all') return true;
      const kind = getTaskAssigneeAllocationKind(task, state);
      if (filter === 'members') return kind === 'member';
      if (filter === 'agents') return kind === 'agent';
      if (filter === 'mixed') return kind === 'mixed';
      return true;
    }

    function buildGlobalTaskRef(task) {
      return encodeURIComponent(JSON.stringify({
        sourceType: task?.sourceType || '',
        sourceProjectId: task?.sourceProjectId || null,
        taskId: task?.taskId || null,
        id: task?.id || null
      }));
    }

    function buildTaskCompletionFxQueueKey(payload = {}) {
      const sourceType = payload.sourceType === 'standalone' ? 'standalone' : 'project';
      const projectId = sourceType === 'project' ? String(payload.projectId || '').trim() : '';
      const entityId = String(payload.entityId || '').trim();
      return `${sourceType}::${projectId}::${entityId}`;
    }

    function queueTaskCompletionFx(payload = {}) {
      const entityId = String(payload.entityId || payload.taskId || payload.id || '').trim();
      if (!entityId) return;
      const sourceType = payload.sourceType === 'standalone' ? 'standalone' : 'project';
      const projectId = sourceType === 'project' ? String(payload.projectId || currentProjectId || '').trim() : '';
      const eventTs = Number(payload.eventTs || Date.now()) || Date.now();
      if (Date.now() - eventTs > TASK_COMPLETION_FX_MAX_EVENT_AGE_MS) return;
      const entry = {
        sourceType,
        projectId,
        entityId,
        queuedAt: Date.now()
      };
      taskCompletionFxQueue.set(buildTaskCompletionFxQueueKey(entry), entry);
    }

    function playTaskCompletionFx(anchorEl) {
      if (!(anchorEl instanceof HTMLElement)) return;
      const emote = document.createElement('span');
      emote.className = 'task-completion-fx-emote';
      emote.textContent = '👍';
      emote.setAttribute('aria-hidden', 'true');
      const driftX = (Math.random() * 52) - 26;
      emote.style.setProperty('--task-fx-drift-x', `${driftX.toFixed(1)}px`);
      anchorEl.appendChild(emote);
      requestAnimationFrame(() => {
        emote.classList.add('is-active');
      });
      emote.addEventListener('animationend', () => {
        emote.remove();
      }, { once: true });
    }

    function flushTaskCompletionFxQueue() {
      if (!taskCompletionFxQueue.size) return;
      const now = Date.now();
      for (const [queueKey, payload] of taskCompletionFxQueue.entries()) {
        if (!payload || (now - Number(payload.queuedAt || 0) > TASK_COMPLETION_FX_QUEUE_TTL_MS)) {
          taskCompletionFxQueue.delete(queueKey);
          continue;
        }
        const sourceType = payload.sourceType === 'standalone' ? 'standalone' : 'project';
        const candidates = Array.from(document.querySelectorAll('.task-completion-fx-anchor')).filter((node) => {
          if (!(node instanceof HTMLElement)) return false;
          if (String(node.dataset.taskEntityId || '').trim() !== payload.entityId) return false;
          if (String(node.dataset.taskSourceType || '').trim() !== sourceType) return false;
          if (sourceType === 'project') {
            return String(node.dataset.taskProjectId || '').trim() === String(payload.projectId || '').trim();
          }
          return true;
        });
        if (!candidates.length) continue;
        playTaskCompletionFx(candidates[0]);
        taskCompletionFxQueue.delete(queueKey);
      }
    }

    function parseGlobalTaskRef(ref) {
      try {
        return JSON.parse(decodeURIComponent(ref || ''));
      } catch {
        return null;
      }
    }

    async function resolveGlobalTaskFromRef(ref) {
      const parsed = parseGlobalTaskRef(ref);
      if (!parsed) return null;
      if (parsed.sourceType === 'standalone' && parsed.id) {
        const task = await getDecrypted('globalTasks', parsed.id, 'id');
        if (!task) return null;
        return { task, sourceType: 'standalone' };
      }
      if (parsed.sourceType === 'project' && parsed.sourceProjectId && parsed.taskId) {
        const state = await getProjectState(parsed.sourceProjectId);
        if (!state?.project) return null;
        const task = (state.tasks || []).find(t => t.taskId === parsed.taskId);
        if (!task) return null;
        return { task, state, sourceType: 'project', projectId: parsed.sourceProjectId };
      }
      return null;
    }

    function normalizeTaskSubtasks(task) {
      const subtasks = Array.isArray(task?.subtasks) ? task.subtasks : [];
      return subtasks
        .map((item, index) => {
          if (typeof item === 'string') {
            return { id: `subtask-${index}`, text: item, done: false };
          }
          return {
            id: String(item?.id || `subtask-${index}`),
            text: String(item?.text || item?.label || item?.title || '').trim(),
            done: Boolean(item?.done)
          };
        })
        .filter(item => item.text);
    }

    function canToggleTaskDetailSubtasks(task = currentGlobalTaskDetailTask, resolved = currentGlobalTaskDetailResolved) {
      if (!task) return false;
      if (resolved?.sourceType === 'standalone') return true;
      return canChangeTaskStatus(task, resolved?.state);
    }

    function renderTaskDetailSubtasks(el, task = currentGlobalTaskDetailTask, options = {}) {
      if (!el) return;
      const subtasks = normalizeTaskSubtasks(task);
      const doneSubtasks = subtasks.filter((item) => item.done).length;
      const taskRef = String(options.taskRef || currentGlobalTaskDetailRef || '');
      const canToggle = options.canToggle !== undefined
        ? !!options.canToggle
        : canToggleTaskDetailSubtasks(task, options.resolved || currentGlobalTaskDetailResolved);
      if (!subtasks.length) {
        el.innerHTML = '<p class="text-slate-500">Aucune sous-tâche.</p>';
        return;
      }
      el.innerHTML = `
        <p class="text-xs text-slate-500 mb-2">${doneSubtasks}/${subtasks.length} terminées</p>
        ${subtasks.map((item) => `
          <label class="flex items-center gap-2" data-task-detail-subtask-row="1">
            <input
              class="subtask-checkbox"
              type="checkbox"
              data-task-detail-subtask-toggle="1"
              data-task-ref="${escapeHtml(taskRef)}"
              data-subtask-id="${escapeHtml(item.id)}"
              ${item.done ? 'checked' : ''}
              ${canToggle ? '' : 'disabled'}
            >
            <span class="${item.done ? 'line-through text-slate-400' : 'text-slate-700'}">${escapeHtml(item.text)}</span>
          </label>
        `).join('')}
      `;
    }

    async function flushTaskDetailInlinePendingSaves() {
      const pending = Array.from(taskDetailInlinePendingSaves.values());
      if (!pending.length) return;
      for (const item of pending) {
        try {
          if (!item?.taskRef) continue;
          if (item.kind === 'descriptionHtml') {
            await persistTaskDetailDescriptionHtml(item.taskRef, item.value, { force: true });
          } else if (item.kind === 'recurring') {
            await persistTaskDetailRecurring(item.taskRef, item.value, { force: true });
          } else if (item.kind === 'field') {
            await persistTaskDetailInlineField(item.taskRef, item.field, item.value, { force: true });
          }
          taskDetailInlinePendingSaves.delete(item.key);
        } catch (error) {
          console.error('flush task detail pending save failed', error);
        }
      }
    }

    async function commitOpenTaskDetailInlineEditors(modal) {
      if (!modal) return;
      const editingTriggers = Array.from(modal.querySelectorAll('[data-inline-task-field][data-inline-editing="1"]'));
      for (const triggerEl of editingTriggers) {
        const field = String(triggerEl?.dataset?.inlineTaskField || '').trim();
        if (!field) continue;
        try {
          if (field === 'documents') continue;
          if (field === 'description') {
            const quillRoot = triggerEl.querySelector('.ql-editor');
            if (quillRoot) {
              const html = String(quillRoot.innerHTML || '').trim();
              await scheduleTaskDetailInlineDescriptionSave(html, { immediate: true });
              const nextDescriptionText = getProjectDescriptionPlainText(html).trim();
              currentGlobalTaskDetailTask = {
                ...(currentGlobalTaskDetailTask || {}),
                descriptionHtml: sanitizeProjectDescriptionHtml(html),
                description: nextDescriptionText
              };
              triggerEl.dataset.inlineEditing = '0';
              triggerEl.classList.remove('is-inline-editing');
              refreshTaskDetailInlineDisplay(field, nextDescriptionText);
              continue;
            }
          }
          if (field === 'recurring') {
            const enabledEl = triggerEl.querySelector('[data-inline-recurring="enabled"]');
            if (enabledEl instanceof HTMLInputElement) {
              const enabled = !!enabledEl.checked;
              let config = null;
              if (enabled) {
                const frequency = String(triggerEl.querySelector('[data-inline-recurring="frequency"]')?.value || 'weekly');
                const interval = Math.max(1, Number.parseInt(String(triggerEl.querySelector('[data-inline-recurring="interval"]')?.value || '1'), 10) || 1);
                const startDate = String(triggerEl.querySelector('[data-inline-recurring="startDate"]')?.value || toYmd(new Date()));
                const endType = String(triggerEl.querySelector('[data-inline-recurring="endType"]')?.value || 'infinite');
                const weekdays = String(triggerEl.querySelector('[data-inline-recurring="weekdays"]')?.value || '')
                  .split(',').map((v) => Number.parseInt(v.trim(), 10)).filter((v) => Number.isInteger(v) && v >= 0 && v <= 6);
                const monthDays = String(triggerEl.querySelector('[data-inline-recurring="monthDays"]')?.value || '')
                  .split(',').map((v) => Number.parseInt(v.trim(), 10)).filter((v) => Number.isInteger(v) && v >= 1 && v <= 31);
                const yearDates = String(triggerEl.querySelector('[data-inline-recurring="yearDates"]')?.value || '')
                  .split(',').map((v) => v.trim()).filter((v) => /^\d{2}-\d{2}$/.test(v));
                const endValue = String(triggerEl.querySelector('[data-inline-recurring="endValue"]')?.value || '').trim();
                const next = {
                  enabled: true,
                  frequency,
                  interval,
                  startDate,
                  endType,
                  weekdays,
                  monthDays,
                  yearDates
                };
                if (endType === 'count') next.endCount = Math.max(1, Number.parseInt(endValue || '10', 10) || 10);
                if (endType === 'until') next.endDate = /^\d{4}-\d{2}-\d{2}$/.test(endValue) ? endValue : startDate;
                config = normalizeTaskRecurringConfig(next);
              }
              currentGlobalTaskDetailTask = {
                ...(currentGlobalTaskDetailTask || {}),
                recurring: config
              };
              await scheduleTaskDetailRecurringSave(config, { immediate: true });
              triggerEl.dataset.inlineEditing = '0';
              triggerEl.classList.remove('is-inline-editing');
              refreshTaskDetailInlineDisplay('recurring', '');
              continue;
            }
          }

          const inputEl = triggerEl.querySelector('textarea, input, select');
          if (!inputEl) continue;
          const rawValue = String(inputEl.value || '');
          const nextValue = normalizeTaskDetailInlineFieldValue(field, rawValue);
          applyTaskDetailInlineFieldToTask(currentGlobalTaskDetailTask || {}, field, nextValue);
          await scheduleTaskDetailInlineSave(field, nextValue, { immediate: true });
          triggerEl.dataset.inlineEditing = '0';
          triggerEl.classList.remove('is-inline-editing');
          refreshTaskDetailInlineDisplay(field, nextValue);
        } catch (error) {
          console.error('task detail inline commit before close failed', error);
        }
      }
    }

    async function closeGlobalTaskDetails() {
      const modal = document.getElementById('modal-global-task-details');
      if (!modal) return;
      await commitOpenTaskDetailInlineEditors(modal);
      modal.classList.add('hidden');
      await flushTaskDetailInlinePendingSaves();
      resetTaskDetailInlineEditingState();
      currentGlobalTaskDetailRef = '';
      currentGlobalTaskDetailContext = null;
      currentGlobalTaskDetailTask = null;
      currentGlobalTaskDetailResolved = null;
      currentGlobalTaskDetailCanEdit = false;
    }

    function resetTaskDetailInlineEditingState() {
      for (const timer of taskDetailInlineDebounceTimers.values()) {
        clearTimeout(timer);
      }
      for (const timer of taskDetailInlineFinalizeTimers.values()) {
        clearTimeout(timer);
      }
      taskDetailInlineDebounceTimers.clear();
      taskDetailInlineFinalizeTimers.clear();
      taskDetailInlineLastSavedValues.clear();
      taskDetailInlinePendingSaves.clear();
    }

    function normalizeTaskDetailInlineFieldValue(field, rawValue) {
      const value = rawValue === null || rawValue === undefined ? '' : String(rawValue);
      if (field === 'status') {
        return ['todo', 'en-cours', 'suspendu', 'termine'].includes(value) ? value : 'todo';
      }
      if (field === 'urgency') {
        return ['low', 'medium', 'high'].includes(value) ? value : 'medium';
      }
      if (field === 'requestDate' || field === 'dueDate') {
        const trimmed = value.trim();
        return /^\d{4}-\d{2}-\d{2}$/.test(trimmed) ? trimmed : '';
      }
      if (field === 'theme') return value.trim() || 'General';
      if (field === 'subtasks') return value.replace(/\r\n/g, '\n');
      if (field === 'title') return value.trim();
      if (field === 'description') return value.replace(/\r\n/g, '\n');
      return value.trim();
    }

    function getTaskDetailInlineFieldValue(task = {}, field = '') {
      if (!task) return '';
      if (field === 'title') return String(task.title || '');
      if (field === 'description') return String(task.description || '');
      if (field === 'requestDate') return String(task.requestDate || '');
      if (field === 'dueDate') return String(task.dueDate || '');
      if (field === 'status') return String(task.status || 'todo');
      if (field === 'urgency') return String(task.urgency || 'medium');
      if (field === 'theme') return String(task.theme || 'General');
      if (field === 'subtasks') {
        const subtasks = normalizeTaskSubtasks(task);
        return subtasks.map((item) => `${item.done ? '[x]' : '[ ]'} ${item.text}`).join('\n');
      }
      return '';
    }

    function applyTaskDetailInlineFieldToTask(task = {}, field = '', value = '') {
      if (!task) return;
      if (field === 'title') task.title = value;
      if (field === 'description') {
        task.description = value.trim();
        task.descriptionHtml = value.trim() ? plainTextToRichHtml(value) : '';
      }
      if (field === 'requestDate') task.requestDate = value || null;
      if (field === 'dueDate') {
        task.dueDate = value || null;
        task.deadlineMode = 'date';
        task.deadlineDate = value || null;
        task.deadlineMonth = null;
        task.deadlineYear = null;
        task.deadlineStart = null;
        task.deadlineEnd = null;
      }
      if (field === 'status') task.status = value || 'todo';
      if (field === 'urgency') task.urgency = value || 'medium';
      if (field === 'theme') task.theme = value || 'General';
      if (field === 'subtasks') {
        const parsed = parseSubtasks(String(value || ''));
        task.subtasks = mergeSubtasksWithExisting(task.subtasks || [], parsed);
      }
      task.updatedAt = Date.now();
    }

    function buildTaskDetailInlineChanges(field, normalizedValue) {
      if (field === 'title') return { title: normalizedValue };
      if (field === 'description') {
        const descriptionText = String(normalizedValue || '').trim();
        const descriptionHtml = descriptionText ? plainTextToRichHtml(descriptionText) : '';
        return { description: descriptionText, descriptionHtml };
      }
      if (field === 'requestDate') return { requestDate: normalizedValue || null };
      if (field === 'dueDate') {
        return {
          dueDate: normalizedValue || null,
          deadlineMode: 'date',
          deadlineDate: normalizedValue || null,
          deadlineMonth: null,
          deadlineYear: null,
          deadlineStart: null,
          deadlineEnd: null
        };
      }
      if (field === 'status') {
        const nextStatus = normalizedValue || 'todo';
        return {
          status: nextStatus,
          completedAt: nextStatus === 'termine' ? Date.now() : null
        };
      }
      if (field === 'urgency') return { urgency: normalizedValue || 'medium' };
      if (field === 'theme') return { theme: normalizedValue || 'General' };
      if (field === 'subtasks') {
        const parsed = parseSubtasks(String(normalizedValue || ''));
        return { subtasks: mergeSubtasksWithExisting((currentGlobalTaskDetailTask?.subtasks || []), parsed) };
      }
      return {};
    }

    function shouldRefreshTaskWorkspaceForInlineField(field = '') {
      return ['title', 'status', 'urgency', 'theme', 'requestDate', 'dueDate', 'subtasks'].includes(String(field || '').trim());
    }

    function scheduleTaskDetailWorkspaceRefresh(options = {}) {
      const immediate = !!options.immediate;
      if (taskDetailWorkspaceRefreshTimer) {
        clearTimeout(taskDetailWorkspaceRefreshTimer);
      }
      taskDetailWorkspaceRefreshTimer = setTimeout(() => {
        taskDetailWorkspaceRefreshTimer = null;
        taskDetailWorkspaceRefreshQueue = taskDetailWorkspaceRefreshQueue
          .then(async () => {
            if (workspaceMode === 'global' && globalWorkspaceView === 'tasks') {
              await renderGlobalTasks();
              return;
            }
            if (workspaceMode === 'project' && currentProjectId && currentProjectState) {
              const latestState = await getProjectState(currentProjectId);
              if (latestState?.project) {
                currentProjectState = latestState;
              }
              const tasks = currentProjectState?.tasks || [];
              if (activeProjectView === 'list') {
                renderTasks(tasks);
                return;
              }
              if (activeProjectView === 'kanban') {
                renderKanban(tasks);
                return;
              }
              if (activeProjectView === 'timeline') {
                renderTimeline(tasks);
                return;
              }
              if (activeProjectView === 'gantt') {
                renderGantt(tasks);
              }
            }
          })
          .catch((error) => {
            console.error('task detail workspace refresh failed', error);
          });
      }, immediate ? 0 : 120);
    }

    async function persistTaskDetailDescriptionHtml(taskRef, htmlValue, options = {}) {
      const safeHtml = sanitizeProjectDescriptionHtml(String(htmlValue || ''));
      const descriptionText = getProjectDescriptionPlainText(safeHtml).trim();
      const saveKey = `${taskRef}::descriptionHtml`;
      const currentSig = `descriptionHtml::${safeHtml}`;
      if (taskDetailInlineLastSavedValues.get(saveKey) === currentSig) {
        if (options.force) {
          scheduleTaskDetailWorkspaceRefresh({ immediate: true });
        }
        return safeHtml;
      }
      const resolved = await resolveGlobalTaskFromRef(taskRef);
      if (!resolved?.task) return safeHtml;
      const changes = {
        description: descriptionText,
        descriptionHtml: safeHtml
      };
      if (resolved.sourceType === 'standalone') {
        await putEncrypted('globalTasks', {
          ...resolved.task,
          ...changes,
          updatedAt: Date.now()
        }, 'id');
      } else {
        const event = createEvent(
          EventTypes.UPDATE_TASK,
          resolved.projectId,
          currentUser.userId,
          { taskId: resolved.task.taskId, changes }
        );
        await publishEvent(event);
        if (sharedFolderHandle) { void syncProjectEventsToSharedSpace(resolved.projectId, [event]); }
      }
      taskDetailInlineLastSavedValues.set(saveKey, currentSig);
      currentGlobalTaskDetailTask = {
        ...(currentGlobalTaskDetailTask || {}),
        ...changes,
        updatedAt: Date.now()
      };
      const pendingKey = 'descriptionHtml';
      const pending = taskDetailInlinePendingSaves.get(pendingKey);
      if (pending?.taskRef === taskRef && pending.value === safeHtml) {
        taskDetailInlinePendingSaves.delete(pendingKey);
      }
      scheduleTaskDetailWorkspaceRefresh({ immediate: !!options.force });
      return safeHtml;
    }

    async function scheduleTaskDetailInlineDescriptionSave(htmlValue, options = {}) {
      const taskRef = currentGlobalTaskDetailRef;
      if (!taskRef) return;
      const safeHtml = sanitizeProjectDescriptionHtml(String(htmlValue || ''));
      const pendingKey = 'descriptionHtml';
      taskDetailInlinePendingSaves.set(pendingKey, {
        key: pendingKey,
        kind: 'descriptionHtml',
        taskRef,
        value: safeHtml
      });
      const debounceDelay = options.immediate ? 0 : 220;
      const timerKey = 'descriptionHtml';
      if (taskDetailInlineDebounceTimers.has(timerKey)) {
        clearTimeout(taskDetailInlineDebounceTimers.get(timerKey));
      }
      taskDetailInlineDebounceTimers.set(timerKey, setTimeout(() => {
        setInlineSaveIndicator('task-detail', 'saving');
        runWithoutGlobalLoading(() => persistTaskDetailDescriptionHtml(taskRef, safeHtml))
          .then(() => setInlineSaveIndicator('task-detail', 'saved'))
          .catch((error) => {
            setInlineSaveIndicator('task-detail', 'error');
            console.error('inline description save failed', error);
          });
      }, debounceDelay));
      if (taskDetailInlineFinalizeTimers.has(timerKey)) {
        clearTimeout(taskDetailInlineFinalizeTimers.get(timerKey));
      }
      taskDetailInlineFinalizeTimers.set(timerKey, setTimeout(() => {
        setInlineSaveIndicator('task-detail', 'saving');
        runWithoutGlobalLoading(() => persistTaskDetailDescriptionHtml(taskRef, safeHtml, { force: true }))
          .then(() => setInlineSaveIndicator('task-detail', 'saved'))
          .catch((error) => {
            setInlineSaveIndicator('task-detail', 'error');
            console.error('inline description finalize save failed', error);
          });
      }, 900));
    }

    function normalizeTaskRecurringConfig(rawConfig) {
      const cfg = rawConfig && typeof rawConfig === 'object' ? rawConfig : {};
      const enabled = !!cfg.enabled;
      if (!enabled) return null;
      const frequency = ['weekly', 'monthly', 'yearly'].includes(String(cfg.frequency || ''))
        ? String(cfg.frequency)
        : 'weekly';
      const interval = Math.max(1, Number.parseInt(String(cfg.interval || '1'), 10) || 1);
      const startDate = /^\d{4}-\d{2}-\d{2}$/.test(String(cfg.startDate || '')) ? String(cfg.startDate) : toYmd(new Date());
      const endType = ['infinite', 'count', 'until'].includes(String(cfg.endType || ''))
        ? String(cfg.endType)
        : 'infinite';
      const weekdays = Array.isArray(cfg.weekdays)
        ? [...new Set(cfg.weekdays.map((v) => Number.parseInt(String(v), 10)).filter((v) => Number.isInteger(v) && v >= 0 && v <= 6))]
        : [];
      const monthDays = Array.isArray(cfg.monthDays)
        ? [...new Set(cfg.monthDays.map((v) => Number.parseInt(String(v), 10)).filter((v) => Number.isInteger(v) && v >= 1 && v <= 31))]
        : [];
      const yearDates = Array.isArray(cfg.yearDates)
        ? [...new Set(cfg.yearDates.map((v) => String(v || '').trim()).filter((v) => /^\d{2}-\d{2}$/.test(v)))]
        : [];
      const normalized = {
        enabled: true,
        frequency,
        interval,
        weekdays: frequency === 'weekly' ? (weekdays.length ? weekdays : [1]) : [],
        monthDays: frequency === 'monthly' ? (monthDays.length ? monthDays : [1]) : [],
        yearDates: frequency === 'yearly' ? (yearDates.length ? yearDates : ['01-01']) : [],
        endType,
        startDate
      };
      if (endType === 'count') {
        normalized.endCount = Math.max(1, Number.parseInt(String(cfg.endCount || '10'), 10) || 10);
      } else if (endType === 'until') {
        normalized.endDate = /^\d{4}-\d{2}-\d{2}$/.test(String(cfg.endDate || ''))
          ? String(cfg.endDate)
          : startDate;
      }
      return normalized;
    }

    async function persistTaskDetailRecurring(taskRef, recurringConfig, options = {}) {
      const normalized = normalizeTaskRecurringConfig(recurringConfig);
      const saveKey = `${taskRef}::recurring`;
      const signature = JSON.stringify(normalized || null);
      if (taskDetailInlineLastSavedValues.get(saveKey) === signature) return normalized;
      const resolved = await resolveGlobalTaskFromRef(taskRef);
      if (!resolved?.task) return normalized;
      const changes = { recurring: normalized };
      if (resolved.sourceType === 'standalone') {
        await putEncrypted('globalTasks', {
          ...resolved.task,
          ...changes,
          updatedAt: Date.now()
        }, 'id');
      } else {
        const event = createEvent(
          EventTypes.UPDATE_TASK,
          resolved.projectId,
          currentUser.userId,
          { taskId: resolved.task.taskId, changes }
        );
        await publishEvent(event);
        if (sharedFolderHandle) void syncProjectEventsToSharedSpace(resolved.projectId, [event]);
      }
      currentGlobalTaskDetailTask = {
        ...(currentGlobalTaskDetailTask || {}),
        recurring: normalized
      };
      taskDetailInlineLastSavedValues.set(saveKey, signature);
      const pendingKey = 'recurring';
      const pending = taskDetailInlinePendingSaves.get(pendingKey);
      const pendingSignature = pending ? JSON.stringify(normalizeTaskRecurringConfig(pending.value) || null) : '';
      if (pending?.taskRef === taskRef && pendingSignature === signature) {
        taskDetailInlinePendingSaves.delete(pendingKey);
      }
      if (options.force) {
        scheduleTaskDetailWorkspaceRefresh({ immediate: true });
      }
      return normalized;
    }

    async function scheduleTaskDetailRecurringSave(config, options = {}) {
      const taskRef = currentGlobalTaskDetailRef;
      if (!taskRef) return;
      const normalizedConfig = normalizeTaskRecurringConfig(config);
      const pendingKey = 'recurring';
      taskDetailInlinePendingSaves.set(pendingKey, {
        key: pendingKey,
        kind: 'recurring',
        taskRef,
        value: normalizedConfig
      });
      const timerKey = 'recurring';
      if (taskDetailInlineDebounceTimers.has(timerKey)) clearTimeout(taskDetailInlineDebounceTimers.get(timerKey));
      taskDetailInlineDebounceTimers.set(timerKey, setTimeout(() => {
        setInlineSaveIndicator('task-detail', 'saving');
        runWithoutGlobalLoading(() => persistTaskDetailRecurring(taskRef, normalizedConfig))
          .then(() => setInlineSaveIndicator('task-detail', 'saved'))
          .catch((error) => {
            setInlineSaveIndicator('task-detail', 'error');
            console.error('inline recurring save failed', error);
          });
      }, options.immediate ? 0 : 220));
      if (taskDetailInlineFinalizeTimers.has(timerKey)) clearTimeout(taskDetailInlineFinalizeTimers.get(timerKey));
      taskDetailInlineFinalizeTimers.set(timerKey, setTimeout(() => {
        setInlineSaveIndicator('task-detail', 'saving');
        runWithoutGlobalLoading(() => persistTaskDetailRecurring(taskRef, normalizedConfig, { force: true }))
          .then(() => setInlineSaveIndicator('task-detail', 'saved'))
          .catch((error) => {
            setInlineSaveIndicator('task-detail', 'error');
            console.error('inline recurring finalize save failed', error);
          });
      }, 900));
    }

    async function readTaskDetailInlineFiles(fileList) {
      const files = Array.from(fileList || []);
      if (!files.length) return [];
      const docs = await Promise.all(
        files.map((file) => new Promise((resolve, reject) => {
          const reader = new FileReader();
          reader.onload = () => {
            resolve({
              docId: uuidv4(),
              name: file.name,
              type: file.type || 'application/octet-stream',
              size: file.size,
              data: reader.result,
              uploadedAt: Date.now()
            });
          };
          reader.onerror = reject;
          reader.readAsDataURL(file);
        }))
      );
      return docs;
    }

    async function persistTaskDetailDocuments(taskRef, payload = {}, options = {}) {
      const resolved = await resolveGlobalTaskFromRef(taskRef);
      if (!resolved?.task) return;
      const attachments = Array.isArray(payload.attachments) ? payload.attachments : (resolved.task.attachments || []);
      const changes = { attachments };
      if (resolved.sourceType === 'standalone') {
        await putEncrypted('globalTasks', {
          ...resolved.task,
          ...changes,
          updatedAt: Date.now()
        }, 'id');
      } else {
        const event = createEvent(
          EventTypes.UPDATE_TASK,
          resolved.projectId,
          currentUser.userId,
          { taskId: resolved.task.taskId, changes }
        );
        await publishEvent(event);
        if (sharedFolderHandle) void syncProjectEventsToSharedSpace(resolved.projectId, [event]);

        if (Array.isArray(payload.linkedProjectDocIds)) {
          const state = await getProjectState(resolved.projectId);
          const selected = new Set(payload.linkedProjectDocIds.map((id) => String(id || '').trim()).filter(Boolean));
          const docs = Array.isArray(state?.documents) ? state.documents : [];
          for (const doc of docs) {
            const currentIds = Array.isArray(doc.linkedTaskIds) ? [...new Set(doc.linkedTaskIds.map((id) => String(id || '').trim()).filter(Boolean))] : [];
            const hasLink = currentIds.includes(resolved.task.taskId);
            const shouldLink = selected.has(String(doc.docId || ''));
            if (hasLink === shouldLink) continue;
            const nextLinkedTaskIds = shouldLink
              ? [...new Set([...currentIds, resolved.task.taskId])]
              : currentIds.filter((id) => id !== resolved.task.taskId);
            const updateDocEvent = createEvent(
              EventTypes.UPDATE_DOCUMENT,
              resolved.projectId,
              currentUser.userId,
              { docId: doc.docId, changes: { linkedTaskIds: nextLinkedTaskIds } }
            );
            await publishEvent(updateDocEvent);
            if (sharedFolderHandle) void syncProjectEventsToSharedSpace(resolved.projectId, [updateDocEvent]);
          }
        }
      }
      currentGlobalTaskDetailTask = {
        ...(currentGlobalTaskDetailTask || {}),
        attachments
      };
      if (!options.quiet) {
        showToast('✅ Documents mis à jour');
      }
    }

    async function persistTaskDetailInlineField(taskRef, field, rawValue, options = {}) {
      const normalizedValue = normalizeTaskDetailInlineFieldValue(field, rawValue);
      const saveKey = `${taskRef}::${field}`;
      const currentSig = `${field}::${normalizedValue}`;
      if (taskDetailInlineLastSavedValues.get(saveKey) === currentSig) return normalizedValue;
      let changes = buildTaskDetailInlineChanges(field, normalizedValue);
      if (!Object.keys(changes).length) return normalizedValue;
      const resolved = await resolveGlobalTaskFromRef(taskRef);
      if (!resolved?.task) return normalizedValue;
      let completionTransition = null;
      if (field === 'status' && Object.prototype.hasOwnProperty.call(changes, 'status')) {
        completionTransition = buildTaskStatusTransitionChanges(resolved.task, changes.status, { nowTs: Date.now() });
        changes = completionTransition.changes;
      }
      const becameCompleted = completionTransition
        ? completionTransition.didCompleteOccurrence
        : (
          field === 'status'
          && normalizeTaskStatusValue(resolved.task.status) !== 'termine'
          && normalizeTaskStatusValue(changes.status) === 'termine'
        );
      if (resolved.sourceType === 'standalone') {
        if (becameCompleted) {
          queueTaskCompletionFx({
            sourceType: 'standalone',
            id: resolved.task.id
          });
        }
        await putEncrypted('globalTasks', {
          ...resolved.task,
          ...changes,
          updatedAt: Date.now()
        }, 'id');
      } else {
        const event = createEvent(
          EventTypes.UPDATE_TASK,
          resolved.projectId,
          currentUser.userId,
          { taskId: resolved.task.taskId, changes }
        );
        await publishEvent(event);
        if (sharedFolderHandle) { void syncProjectEventsToSharedSpace(resolved.projectId, [event]); }
      }
      taskDetailInlineLastSavedValues.set(saveKey, currentSig);
      const pendingKey = `field::${field}`;
      const pending = taskDetailInlinePendingSaves.get(pendingKey);
      if (pending?.taskRef === taskRef && pending.value === normalizedValue) {
        taskDetailInlinePendingSaves.delete(pendingKey);
      }
      if (shouldRefreshTaskWorkspaceForInlineField(field)) {
        scheduleTaskDetailWorkspaceRefresh({ immediate: field === 'status' || field === 'urgency' });
      }
      return normalizedValue;
    }

    async function toggleTaskDetailSubtaskChecked(taskRef, subtaskId, done) {
      const safeTaskRef = String(taskRef || '').trim();
      const safeSubtaskId = String(subtaskId || '').trim();
      if (!safeTaskRef || !safeSubtaskId) return false;
      const resolved = await resolveGlobalTaskFromRef(safeTaskRef);
      if (!resolved?.task) return false;

      const canToggle = canToggleTaskDetailSubtasks(resolved.task, resolved);
      if (!canToggle) {
        showToast('Action non autorisee');
        return false;
      }

      const currentSubtasks = normalizeTaskSubtasks(resolved.task);
      const nextSubtasks = currentSubtasks.map((item) => (
        item.id === safeSubtaskId ? { ...item, done: !!done } : item
      ));

      if (resolved.sourceType === 'standalone') {
        await putEncrypted('globalTasks', {
          ...resolved.task,
          subtasks: nextSubtasks,
          updatedAt: Date.now()
        }, 'id');
      } else {
        if (!ensureProjectResourceUnlockedForAction(resolved.state, LOCK_SCOPE_TASK, resolved.task.taskId, 'Mise a jour sous-tache').ok) {
          return false;
        }
        const event = createEvent(
          EventTypes.UPDATE_TASK,
          resolved.projectId,
          currentUser.userId,
          {
            taskId: resolved.task.taskId,
            changes: { subtasks: nextSubtasks }
          }
        );
        await publishEvent(event);
        if (sharedFolderHandle) { void syncProjectEventsToSharedSpace(resolved.projectId, [event]); }
      }

      if (currentGlobalTaskDetailRef === safeTaskRef) {
        currentGlobalTaskDetailTask = {
          ...(currentGlobalTaskDetailTask || {}),
          subtasks: nextSubtasks,
          updatedAt: Date.now()
        };
        if (currentGlobalTaskDetailResolved?.sourceType === 'project' && currentGlobalTaskDetailResolved?.task) {
          currentGlobalTaskDetailResolved.task = {
            ...currentGlobalTaskDetailResolved.task,
            subtasks: nextSubtasks,
            updatedAt: Date.now()
          };
        }
        refreshTaskDetailInlineDisplay('subtasks', getTaskDetailInlineFieldValue(currentGlobalTaskDetailTask, 'subtasks'));
      }
      return true;
    }

    function decorateTaskDetailEditableElement(el, field) {
      if (!el) return;
      el.dataset.inlineTaskField = field;
      el.classList.toggle('task-detail-inline-editable', !!currentGlobalTaskDetailCanEdit);
      if (currentGlobalTaskDetailCanEdit) {
        el.setAttribute('title', 'Cliquer pour modifier');
        el.setAttribute('tabindex', '0');
        el.setAttribute('role', 'button');
      } else {
        el.removeAttribute('title');
        el.removeAttribute('tabindex');
        el.removeAttribute('role');
      }
    }

    function refreshTaskDetailInlineDisplay(field, value) {
      const normalizedValue = normalizeTaskDetailInlineFieldValue(field, value);
      if (field === 'title') {
        const el = document.getElementById('global-task-detail-title');
        if (el) {
          el.textContent = normalizedValue || 'Tache';
          decorateTaskDetailEditableElement(el, 'title');
        }
        return;
      }
      if (field === 'description') {
        const el = document.getElementById('global-task-detail-description');
        if (el) {
          const previewTask = { ...currentGlobalTaskDetailTask, description: normalizedValue, descriptionHtml: normalizedValue ? plainTextToRichHtml(normalizedValue) : '' };
          renderTaskDescriptionToElement(previewTask, el);
          decorateTaskDetailEditableElement(el, 'description');
        }
        return;
      }
      if (field === 'subtasks') {
        const el = document.getElementById('global-task-detail-subtasks');
        if (el) {
          renderTaskDetailSubtasks(el, currentGlobalTaskDetailTask, {
            taskRef: currentGlobalTaskDetailRef,
            resolved: currentGlobalTaskDetailResolved
          });
          decorateTaskDetailEditableElement(el, 'subtasks');
        }
        return;
      }
      if (field === 'recurring') {
        const wrapEl = document.getElementById('global-task-detail-recurrence-wrap');
        const el = document.getElementById('global-task-detail-recurrence');
        if (wrapEl && el) {
          const cfg = normalizeTaskRecurringConfig(currentGlobalTaskDetailTask?.recurring);
          const label = cfg
            ? (window.TaskMDARecurrence?.formatRecurrenceLabel?.(cfg) || 'Récurrence configurable')
            : 'Non récurrente';
          el.textContent = label;
          wrapEl.classList.remove('hidden');
          decorateTaskDetailEditableElement(el, 'recurring');
        }
        return;
      }
      if (field === 'documents') {
        const el = document.getElementById('global-task-detail-attachments');
        if (el) decorateTaskDetailEditableElement(el, 'documents');
        return;
      }
      if (field === 'requestDate') {
        const el = document.getElementById('global-task-detail-request-date');
        if (el) {
          el.textContent = formatDate(normalizedValue || null);
          decorateTaskDetailEditableElement(el, 'requestDate');
        }
        return;
      }
      if (field === 'dueDate') {
        const el = document.getElementById('global-task-detail-due-date');
        if (el) {
          el.textContent = formatDate(normalizedValue || null);
          decorateTaskDetailEditableElement(el, 'dueDate');
        }
        return;
      }
      if (field === 'theme') {
        const el = document.getElementById('global-task-detail-theme');
        if (el) {
          el.textContent = normalizedValue || 'General';
          decorateTaskDetailEditableElement(el, 'theme');
        }
        return;
      }
      if (field === 'status') {
        const el = document.getElementById('global-task-detail-status-chip');
        if (el) {
          const meta = getTaskStatusMeta(normalizedValue || 'todo');
          el.className = `${meta.chipClass} task-detail-inline-editable`;
          el.textContent = meta.label;
          el.dataset.inlineTaskField = 'status';
          if (currentGlobalTaskDetailCanEdit) {
            el.setAttribute('title', 'Cliquer pour modifier');
            el.setAttribute('tabindex', '0');
            el.setAttribute('role', 'button');
          } else {
            el.removeAttribute('title');
            el.removeAttribute('tabindex');
            el.removeAttribute('role');
          }
        }
        return;
      }
      if (field === 'urgency') {
        const el = document.getElementById('global-task-detail-urgency-chip');
        if (el) {
          const meta = getTaskUrgencyMeta(normalizedValue || 'medium');
          el.className = `${meta.chipClass} task-detail-inline-editable`;
          el.textContent = meta.label;
          el.dataset.inlineTaskField = 'urgency';
          if (currentGlobalTaskDetailCanEdit) {
            el.setAttribute('title', 'Cliquer pour modifier');
            el.setAttribute('tabindex', '0');
            el.setAttribute('role', 'button');
          } else {
            el.removeAttribute('title');
            el.removeAttribute('tabindex');
            el.removeAttribute('role');
          }
        }
      }
    }

    function buildTaskDetailInlineEditor(field, value) {
      if (field === 'description') {
        const input = document.createElement('textarea');
        input.rows = 6;
        input.className = 'task-detail-inline-input task-detail-inline-textarea';
        input.value = value || '';
        input.placeholder = 'Saisissez une description';
        return input;
      }
      if (field === 'subtasks') {
        const input = document.createElement('textarea');
        input.rows = 6;
        input.className = 'task-detail-inline-input task-detail-inline-textarea';
        input.value = value || '';
        input.placeholder = '[ ] Action 1\n[x] Action terminee';
        return input;
      }
      if (field === 'status') {
        const select = document.createElement('select');
        select.className = 'task-detail-inline-input task-detail-inline-select';
        [
          ['todo', 'A faire'],
          ['en-cours', 'En cours'],
          ['suspendu', 'Suspendu'],
          ['termine', 'Termine']
        ].forEach(([v, l]) => {
          const opt = document.createElement('option');
          opt.value = v;
          opt.textContent = l;
          if (v === value) opt.selected = true;
          select.appendChild(opt);
        });
        return select;
      }
      if (field === 'urgency') {
        const select = document.createElement('select');
        select.className = 'task-detail-inline-input task-detail-inline-select';
        [
          ['low', 'Basse'],
          ['medium', 'Moyenne'],
          ['high', 'Haute']
        ].forEach(([v, l]) => {
          const opt = document.createElement('option');
          opt.value = v;
          opt.textContent = l;
          if (v === value) opt.selected = true;
          select.appendChild(opt);
        });
        return select;
      }
      const input = document.createElement('input');
      input.type = (field === 'requestDate' || field === 'dueDate') ? 'date' : 'text';
      input.className = 'task-detail-inline-input';
      input.value = value || '';
      return input;
    }

    async function scheduleTaskDetailInlineSave(field, rawValue, options = {}) {
      const taskRef = currentGlobalTaskDetailRef;
      if (!taskRef) return;
      const normalizedValue = normalizeTaskDetailInlineFieldValue(field, rawValue);
      const pendingKey = `field::${field}`;
      taskDetailInlinePendingSaves.set(pendingKey, {
        key: pendingKey,
        kind: 'field',
        taskRef,
        field,
        value: normalizedValue
      });
      const debounceDelay = options.immediate ? 0 : 220;
      if (taskDetailInlineDebounceTimers.has(field)) {
        clearTimeout(taskDetailInlineDebounceTimers.get(field));
      }
      taskDetailInlineDebounceTimers.set(field, setTimeout(() => {
        setInlineSaveIndicator('task-detail', 'saving');
        runWithoutGlobalLoading(() => persistTaskDetailInlineField(taskRef, field, normalizedValue))
          .then(() => setInlineSaveIndicator('task-detail', 'saved'))
          .catch((error) => {
            setInlineSaveIndicator('task-detail', 'error');
            console.error('inline save failed', error);
          });
      }, debounceDelay));

      if (taskDetailInlineFinalizeTimers.has(field)) {
        clearTimeout(taskDetailInlineFinalizeTimers.get(field));
      }
      taskDetailInlineFinalizeTimers.set(field, setTimeout(() => {
        setInlineSaveIndicator('task-detail', 'saving');
        runWithoutGlobalLoading(() => persistTaskDetailInlineField(taskRef, field, normalizedValue, { force: true }))
          .then(() => setInlineSaveIndicator('task-detail', 'saved'))
          .catch((error) => {
            setInlineSaveIndicator('task-detail', 'error');
            console.error('inline finalize save failed', error);
          });
      }, 900));
    }

    async function startTaskDetailRecurringInlineEdit(triggerEl) {
      if (!triggerEl || triggerEl.dataset.inlineEditing === '1') return;
      const initial = normalizeTaskRecurringConfig(currentGlobalTaskDetailTask?.recurring) || {
        enabled: false,
        frequency: 'weekly',
        interval: 1,
        weekdays: [1],
        monthDays: [1],
        yearDates: ['01-01'],
        endType: 'infinite',
        startDate: toYmd(new Date())
      };
      triggerEl.dataset.inlineEditing = '1';
      triggerEl.classList.add('is-inline-editing');
      triggerEl.innerHTML = `
        <div class="task-detail-inline-editor-wrap task-detail-inline-block">
          <label class="inline-flex items-center gap-2 text-xs font-semibold text-slate-700 mb-2">
            <input type="checkbox" data-inline-recurring="enabled" ${initial.enabled ? 'checked' : ''}>
            <span>Activer la récurrence</span>
          </label>
          <div class="grid grid-cols-1 md:grid-cols-2 gap-2">
            <label class="text-xs text-slate-600">Fréquence
              <select data-inline-recurring="frequency" class="task-detail-inline-input task-detail-inline-select mt-1">
                <option value="weekly" ${initial.frequency === 'weekly' ? 'selected' : ''}>Hebdomadaire</option>
                <option value="monthly" ${initial.frequency === 'monthly' ? 'selected' : ''}>Mensuelle</option>
                <option value="yearly" ${initial.frequency === 'yearly' ? 'selected' : ''}>Annuelle</option>
              </select>
            </label>
            <label class="text-xs text-slate-600">Intervalle
              <input data-inline-recurring="interval" type="number" min="1" value="${Math.max(1, Number(initial.interval || 1))}" class="task-detail-inline-input mt-1">
            </label>
            <label class="text-xs text-slate-600">Date de départ
              <input data-inline-recurring="startDate" type="date" value="${escapeHtml(initial.startDate || toYmd(new Date()))}" class="task-detail-inline-input mt-1">
            </label>
            <label class="text-xs text-slate-600">Fin
              <select data-inline-recurring="endType" class="task-detail-inline-input task-detail-inline-select mt-1">
                <option value="infinite" ${initial.endType === 'infinite' ? 'selected' : ''}>Jamais</option>
                <option value="count" ${initial.endType === 'count' ? 'selected' : ''}>Après N occurrences</option>
                <option value="until" ${initial.endType === 'until' ? 'selected' : ''}>Jusqu'à une date</option>
              </select>
            </label>
          </div>
          <div class="grid grid-cols-1 md:grid-cols-2 gap-2 mt-2">
            <label class="text-xs text-slate-600">Jours semaine (0-6)
              <input data-inline-recurring="weekdays" type="text" value="${escapeHtml((initial.weekdays || []).join(','))}" class="task-detail-inline-input mt-1" placeholder="1,3,5">
            </label>
            <label class="text-xs text-slate-600">Jours mois
              <input data-inline-recurring="monthDays" type="text" value="${escapeHtml((initial.monthDays || []).join(','))}" class="task-detail-inline-input mt-1" placeholder="1,15,28">
            </label>
            <label class="text-xs text-slate-600">Dates annuelles (MM-DD)
              <input data-inline-recurring="yearDates" type="text" value="${escapeHtml((initial.yearDates || []).join(','))}" class="task-detail-inline-input mt-1" placeholder="01-01,06-15">
            </label>
            <label class="text-xs text-slate-600">Occurrences / Date fin
              <input data-inline-recurring="endValue" type="text" value="${escapeHtml(initial.endType === 'count' ? String(initial.endCount || 10) : (initial.endDate || ''))}" class="task-detail-inline-input mt-1" placeholder="10 ou 2026-12-31">
            </label>
          </div>
          <div class="flex items-center justify-end gap-2 mt-3">
            <button type="button" class="task-action-btn task-action-btn-subtle" data-inline-recurring-action="close">Fermer</button>
          </div>
        </div>
      `;

      const readConfigFromEditor = () => {
        const enabled = !!triggerEl.querySelector('[data-inline-recurring="enabled"]')?.checked;
        if (!enabled) return null;
        const frequency = String(triggerEl.querySelector('[data-inline-recurring="frequency"]')?.value || 'weekly');
        const interval = Math.max(1, Number.parseInt(String(triggerEl.querySelector('[data-inline-recurring="interval"]')?.value || '1'), 10) || 1);
        const startDate = String(triggerEl.querySelector('[data-inline-recurring="startDate"]')?.value || toYmd(new Date()));
        const endType = String(triggerEl.querySelector('[data-inline-recurring="endType"]')?.value || 'infinite');
        const weekdays = String(triggerEl.querySelector('[data-inline-recurring="weekdays"]')?.value || '')
          .split(',').map((v) => Number.parseInt(v.trim(), 10)).filter((v) => Number.isInteger(v) && v >= 0 && v <= 6);
        const monthDays = String(triggerEl.querySelector('[data-inline-recurring="monthDays"]')?.value || '')
          .split(',').map((v) => Number.parseInt(v.trim(), 10)).filter((v) => Number.isInteger(v) && v >= 1 && v <= 31);
        const yearDates = String(triggerEl.querySelector('[data-inline-recurring="yearDates"]')?.value || '')
          .split(',').map((v) => v.trim()).filter((v) => /^\d{2}-\d{2}$/.test(v));
        const endValue = String(triggerEl.querySelector('[data-inline-recurring="endValue"]')?.value || '').trim();
        const next = {
          enabled: true,
          frequency,
          interval,
          startDate,
          endType,
          weekdays,
          monthDays,
          yearDates
        };
        if (endType === 'count') next.endCount = Math.max(1, Number.parseInt(endValue || '10', 10) || 10);
        if (endType === 'until') next.endDate = /^\d{4}-\d{2}-\d{2}$/.test(endValue) ? endValue : startDate;
        return normalizeTaskRecurringConfig(next);
      };

      const autosave = async (immediate = false) => {
        const config = readConfigFromEditor();
        currentGlobalTaskDetailTask = {
          ...(currentGlobalTaskDetailTask || {}),
          recurring: config
        };
        await scheduleTaskDetailRecurringSave(config, { immediate });
      };

      triggerEl.querySelectorAll('input, select').forEach((el) => {
        el.addEventListener('input', () => {
          autosave(false).catch((error) => console.error('recurring autosave failed', error));
        });
        el.addEventListener('change', () => {
          autosave(false).catch((error) => console.error('recurring autosave failed', error));
        });
      });
      triggerEl.querySelector('[data-inline-recurring-action="close"]')?.addEventListener('click', async () => {
        await autosave(true);
        triggerEl.dataset.inlineEditing = '0';
        triggerEl.classList.remove('is-inline-editing');
        refreshTaskDetailInlineDisplay('recurring', '');
      });
    }

    function renderTaskDetailDocumentsEditorSection(attachments = [], projectDocs = [], linkedDocIdSet = new Set()) {
      const attachmentItems = attachments.map((file, index) => `
        <div class="flex items-center justify-between gap-2 rounded-lg border border-slate-200 px-2 py-1">
          <span class="truncate text-xs text-slate-700">${escapeHtml(file?.name || `piece-jointe-${index + 1}`)}</span>
          <button type="button" class="task-action-btn task-action-btn-danger" data-inline-doc-remove-attachment="${index}">Supprimer</button>
        </div>
      `).join('');
      const docItems = projectDocs.map((doc) => `
        <label class="flex items-center gap-2 rounded-lg border border-slate-200 px-2 py-1 text-xs text-slate-700">
          <input type="checkbox" data-inline-doc-link-id="${escapeHtml(String(doc.docId || ''))}" ${linkedDocIdSet.has(String(doc.docId || '')) ? 'checked' : ''}>
          <span class="truncate">${escapeHtml(doc.name || 'document')}</span>
        </label>
      `).join('');
      return `
        <div class="task-detail-inline-editor-wrap task-detail-inline-block">
          <p class="text-xs font-semibold text-slate-700 mb-2">Pièces jointes de la tâche</p>
          <div class="space-y-1 mb-2">${attachmentItems || '<p class="text-xs text-slate-500">Aucune pièce jointe.</p>'}</div>
          <input type="file" multiple class="task-detail-inline-input" data-inline-doc-add-files>
          ${projectDocs.length ? `
            <p class="text-xs font-semibold text-slate-700 mt-3 mb-2">Lier/Délier documents du projet</p>
            <div class="space-y-1 max-h-40 overflow-auto">${docItems}</div>
          ` : ''}
          <div class="flex items-center justify-end gap-2 mt-3">
            <button type="button" class="task-action-btn task-action-btn-subtle" data-inline-doc-action="close">Fermer</button>
          </div>
        </div>
      `;
    }

    async function startTaskDetailDocumentsInlineEdit(triggerEl) {
      if (!triggerEl || triggerEl.dataset.inlineEditing === '1') return;
      const resolved = currentGlobalTaskDetailResolved || await resolveGlobalTaskFromRef(currentGlobalTaskDetailRef);
      if (!resolved?.task) return;
      const currentAttachments = Array.isArray(resolved.task.attachments) ? [...resolved.task.attachments] : [];
      const stateDocs = resolved.sourceType === 'project' ? (resolved.state?.documents || []) : [];
      const projectDocs = stateDocs.filter((doc) => String(doc?.origin || '') !== 'project-description-image');
      const taskId = String(resolved.task.taskId || '');
      const linkedDocIdSet = new Set(
        projectDocs
          .filter((doc) => Array.isArray(doc.linkedTaskIds) && doc.linkedTaskIds.includes(taskId))
          .map((doc) => String(doc.docId || ''))
      );

      triggerEl.dataset.inlineEditing = '1';
      triggerEl.classList.add('is-inline-editing');
      let attachmentsDraft = [...currentAttachments];
      let linkedDocIdsDraft = new Set(linkedDocIdSet);
      const rerender = () => {
        triggerEl.innerHTML = renderTaskDetailDocumentsEditorSection(attachmentsDraft, projectDocs, linkedDocIdsDraft);
        bind();
      };
      const autosave = async (immediate = false, quiet = true) => {
        setInlineSaveIndicator('task-detail', 'saving');
        try {
          await runWithoutGlobalLoading(() => persistTaskDetailDocuments(currentGlobalTaskDetailRef, {
            attachments: attachmentsDraft,
            linkedProjectDocIds: Array.from(linkedDocIdsDraft)
          }, { quiet }));
          setInlineSaveIndicator('task-detail', 'saved');
        } catch (error) {
          setInlineSaveIndicator('task-detail', 'error');
          throw error;
        }
        if (immediate) {
          refreshTaskDetailInlineDisplay('documents', '');
        }
      };
      const bind = () => {
        triggerEl.querySelectorAll('[data-inline-doc-remove-attachment]').forEach((btn) => {
          btn.addEventListener('click', () => {
            const idx = Number.parseInt(String(btn.getAttribute('data-inline-doc-remove-attachment') || '-1'), 10);
            if (idx < 0 || idx >= attachmentsDraft.length) return;
            attachmentsDraft.splice(idx, 1);
            rerender();
            autosave(false).catch((error) => console.error('doc autosave failed', error));
          });
        });
        triggerEl.querySelector('[data-inline-doc-add-files]')?.addEventListener('change', async (event) => {
          const files = await readTaskDetailInlineFiles(event.target?.files);
          if (files.length) {
            attachmentsDraft = [...attachmentsDraft, ...files];
            rerender();
            await autosave(false);
          }
        });
        triggerEl.querySelectorAll('[data-inline-doc-link-id]').forEach((input) => {
          input.addEventListener('change', () => {
            const docId = String(input.getAttribute('data-inline-doc-link-id') || '').trim();
            if (!docId) return;
            if (input.checked) linkedDocIdsDraft.add(docId);
            else linkedDocIdsDraft.delete(docId);
            autosave(false).catch((error) => console.error('doc link autosave failed', error));
          });
        });
        triggerEl.querySelector('[data-inline-doc-action="close"]')?.addEventListener('click', async () => {
          await autosave(true, false);
          triggerEl.dataset.inlineEditing = '0';
          triggerEl.classList.remove('is-inline-editing');
          const latest = await resolveGlobalTaskFromRef(currentGlobalTaskDetailRef);
          if (latest?.task) {
            currentGlobalTaskDetailTask = { ...latest.task };
            currentGlobalTaskDetailResolved = latest;
          }
          const parsedRef = parseGlobalTaskRef(currentGlobalTaskDetailRef);
          if (parsedRef?.sourceType === 'project' && parsedRef?.taskId) {
            await openProjectTaskDetails(parsedRef.taskId);
          } else {
            await openGlobalTaskDetails(currentGlobalTaskDetailRef);
          }
        });
      };
      rerender();
    }

    function startTaskDetailInlineEdit(triggerEl) {
      if (!currentGlobalTaskDetailCanEdit || !triggerEl) return;
      const field = String(triggerEl.dataset.inlineTaskField || '').trim();
      if (!field || triggerEl.dataset.inlineEditing === '1') return;
      if (field === 'recurring') { startTaskDetailRecurringInlineEdit(triggerEl).catch((error) => console.error(error)); return; }
      if (field === 'documents') { startTaskDetailDocumentsInlineEdit(triggerEl).catch((error) => console.error(error)); return; }
      const startValue = getTaskDetailInlineFieldValue(currentGlobalTaskDetailTask || {}, field);
      triggerEl.dataset.inlineEditing = '1';
      triggerEl.classList.add('is-inline-editing');
      triggerEl.innerHTML = '';
      const wrap = document.createElement('span');
      wrap.className = 'task-detail-inline-editor-wrap';
      let editor = null;
      let quillEditor = null;
      if (field === 'description' && window.Quill && typeof ensureProjectDescriptionQuillEditor === 'function') {
        const editorId = `task-detail-inline-desc-${uuidv4()}`;
        const host = document.createElement('div');
        host.id = editorId;
        host.className = 'task-detail-inline-quill-host';
        wrap.appendChild(host);
        triggerEl.appendChild(wrap);
        const quill = ensureProjectDescriptionQuillEditor(editorId);
        const safeHtml = sanitizeProjectDescriptionHtml(currentGlobalTaskDetailTask?.descriptionHtml || plainTextToRichHtml(startValue || ''));
        if (quill) {
          quillEditor = quill;
          quill.clipboard.dangerouslyPasteHTML(safeHtml || '<p><br></p>');
          quill.on('text-change', () => {
            const html = String(quill.root?.innerHTML || '').trim();
            currentGlobalTaskDetailTask = {
              ...(currentGlobalTaskDetailTask || {}),
              descriptionHtml: sanitizeProjectDescriptionHtml(html),
              description: getProjectDescriptionPlainText(html).trim()
            };
            scheduleTaskDetailInlineDescriptionSave(html).catch((error) => {
              console.error('inline quill autosave failed', error);
            });
          });
          editor = quill.root;
        } else {
          const fallback = document.createElement('textarea');
          fallback.rows = 6;
          fallback.className = 'task-detail-inline-input task-detail-inline-textarea';
          fallback.value = startValue || '';
          host.appendChild(fallback);
          editor = fallback;
        }
      } else {
        editor = buildTaskDetailInlineEditor(field, startValue);
        wrap.appendChild(editor);
        triggerEl.appendChild(wrap);
      }
      if (!editor) return;

      let done = false;
      const finish = async (nextRawValue, commit) => {
        if (done) return;
        done = true;
        const nextValue = normalizeTaskDetailInlineFieldValue(field, nextRawValue);
        triggerEl.dataset.inlineEditing = '0';
        triggerEl.classList.remove('is-inline-editing');
        if (commit) {
          if (field === 'description' && window.Quill) {
            const html = triggerEl.querySelector('.ql-editor')?.innerHTML || '';
            await scheduleTaskDetailInlineDescriptionSave(html, { immediate: true });
            const nextDescriptionText = getProjectDescriptionPlainText(html).trim();
            currentGlobalTaskDetailTask = {
              ...(currentGlobalTaskDetailTask || {}),
              descriptionHtml: sanitizeProjectDescriptionHtml(html),
              description: nextDescriptionText
            };
            refreshTaskDetailInlineDisplay(field, nextDescriptionText);
          } else {
            applyTaskDetailInlineFieldToTask(currentGlobalTaskDetailTask || {}, field, nextValue);
            await scheduleTaskDetailInlineSave(field, nextValue, { immediate: true });
            refreshTaskDetailInlineDisplay(field, nextValue);
          }
        } else {
          refreshTaskDetailInlineDisplay(field, getTaskDetailInlineFieldValue(currentGlobalTaskDetailTask || {}, field));
        }
      };

      editor.addEventListener('input', async () => {
        if (field === 'description' && window.Quill) return;
        const nextValue = editor.value;
        applyTaskDetailInlineFieldToTask(currentGlobalTaskDetailTask || {}, field, nextValue);
        await scheduleTaskDetailInlineSave(field, nextValue);
      });
      if (quillEditor && field === 'description') {
        const root = quillEditor.root;
        let interactingWithToolbar = false;
        const toolbar = wrap.querySelector('.ql-toolbar');
        if (toolbar) {
          const markToolbarInteraction = () => {
            interactingWithToolbar = true;
            setTimeout(() => {
              interactingWithToolbar = false;
            }, 0);
          };
          toolbar.addEventListener('pointerdown', markToolbarInteraction);
          toolbar.addEventListener('mousedown', markToolbarInteraction);
        }
        root.addEventListener('keydown', async (event) => {
          if (event.key !== 'Escape') return;
          event.preventDefault();
          await finish(getTaskDetailInlineFieldValue(currentGlobalTaskDetailTask || {}, field), false);
        });
        wrap.addEventListener('focusout', async (event) => {
          if (interactingWithToolbar) return;
          if (wrap.contains(event.relatedTarget)) return;
          const active = document.activeElement;
          if (active instanceof Element && wrap.contains(active)) return;
          const html = String(quillEditor.root?.innerHTML || '').trim();
          await finish(html, true);
        });
      } else {
        editor.addEventListener('blur', async () => {
          await finish(editor.value, true);
        });
        editor.addEventListener('keydown', async (event) => {
          if (event.key === 'Escape') {
            event.preventDefault();
            await finish(getTaskDetailInlineFieldValue(currentGlobalTaskDetailTask || {}, field), false);
            return;
          }
          if (event.key === 'Enter' && field !== 'description' && field !== 'subtasks') {
            event.preventDefault();
            editor.blur();
          }
        });
      }

      requestAnimationFrame(() => {
        editor.focus();
        if (typeof editor.select === 'function' && field !== 'status' && field !== 'urgency' && field !== 'description') {
          editor.select();
        }
      });
    }

    function shouldIgnoreInlineActivationKeydown(target, trigger) {
      if (!(target instanceof Element) || !(trigger instanceof Element)) return true;
      if (trigger.querySelector('.task-detail-inline-editor-wrap')) return true;
      if (target.closest('input, textarea, select, button, a[href], [contenteditable="true"], [contenteditable=""]')) return true;
      return false;
    }

    function initTaskDetailInlineEditing(canEdit = false) {
      currentGlobalTaskDetailCanEdit = !!canEdit;
      const titleEl = document.getElementById('global-task-detail-title');
      const descriptionEl = document.getElementById('global-task-detail-description');
      const requestDateEl = document.getElementById('global-task-detail-request-date');
      const dueDateEl = document.getElementById('global-task-detail-due-date');
      const themeEl = document.getElementById('global-task-detail-theme');
      const statusEl = document.getElementById('global-task-detail-status-chip');
      const urgencyEl = document.getElementById('global-task-detail-urgency-chip');
      const recurrenceEl = document.getElementById('global-task-detail-recurrence');
      const subtasksEl = document.getElementById('global-task-detail-subtasks');
      const attachmentsEl = document.getElementById('global-task-detail-attachments');
      decorateTaskDetailEditableElement(titleEl, 'title');
      decorateTaskDetailEditableElement(descriptionEl, 'description');
      decorateTaskDetailEditableElement(requestDateEl, 'requestDate');
      decorateTaskDetailEditableElement(dueDateEl, 'dueDate');
      decorateTaskDetailEditableElement(themeEl, 'theme');
      decorateTaskDetailEditableElement(statusEl, 'status');
      decorateTaskDetailEditableElement(urgencyEl, 'urgency');
      decorateTaskDetailEditableElement(recurrenceEl, 'recurring');
      decorateTaskDetailEditableElement(subtasksEl, 'subtasks');
      decorateTaskDetailEditableElement(attachmentsEl, 'documents');

      const modal = document.getElementById('modal-global-task-details');
      if (!modal || modal.dataset.inlineTaskEditorBound === '1') return;
      modal.dataset.inlineTaskEditorBound = '1';
      modal.addEventListener('click', (event) => {
        const rawTarget = event.target;
        const clickTarget = rawTarget instanceof Element ? rawTarget : null;
        if (clickTarget?.closest('a[data-inline-ignore], a[href]')) return;
        if (clickTarget?.closest('[data-task-detail-subtask-row="1"]')) return;
        const trigger = clickTarget?.closest('[data-inline-task-field]');
        if (!trigger) return;
        if (trigger.querySelector('.task-detail-inline-editor-wrap')) return;
        startTaskDetailInlineEdit(trigger);
      });
      modal.addEventListener('change', (event) => {
        const target = event.target;
        if (!(target instanceof HTMLInputElement)) return;
        if (target.dataset.taskDetailSubtaskToggle !== '1') return;
        const taskRef = String(target.dataset.taskRef || '');
        const subtaskId = String(target.dataset.subtaskId || '');
        toggleTaskDetailSubtaskChecked(taskRef, subtaskId, !!target.checked)
          .then((ok) => {
            if (!ok) target.checked = !target.checked;
          })
          .catch((error) => {
            console.error('task detail subtask toggle failed', error);
            target.checked = !target.checked;
          });
      });
      modal.addEventListener('keydown', (event) => {
        const target = event.target instanceof Element ? event.target : null;
        const trigger = target?.closest('[data-inline-task-field]');
        if (!trigger) return;
        if (event.key !== 'Enter' && event.key !== ' ') return;
        if (shouldIgnoreInlineActivationKeydown(target, trigger)) return;
        event.preventDefault();
        startTaskDetailInlineEdit(trigger);
      });
    }

    async function releaseActiveProjectEditLock() {
      if (!activeProjectEditLock) return;
      await releaseProjectResourceLock(
        activeProjectEditLock.projectId,
        activeProjectEditLock.resourceType,
        activeProjectEditLock.resourceId,
        activeProjectEditLock.lockId
      );
      activeProjectEditLock = null;
      updateEditLockBadges();
    }

    async function releaseActiveTaskEditLock() {
      if (!activeTaskEditLock) return;
      await releaseProjectResourceLock(
        activeTaskEditLock.projectId,
        activeTaskEditLock.resourceType,
        activeTaskEditLock.resourceId,
        activeTaskEditLock.lockId
      );
      activeTaskEditLock = null;
      updateEditLockBadges();
    }

    function updateEditLockBadges() {
      const taskBadge = document.getElementById('task-edit-lock-badge');
      const projectBadge = document.getElementById('project-edit-lock-badge');

      if (taskBadge) {
        if (activeTaskEditLock?.lockId) {
          taskBadge.textContent = 'Verrou actif: cette tache est reservee a votre edition temporaire.';
          taskBadge.classList.remove('hidden');
        } else {
          taskBadge.classList.add('hidden');
          taskBadge.textContent = '';
        }
      }

      if (projectBadge) {
        if (activeProjectEditLock?.lockId) {
          projectBadge.textContent = 'Verrou actif: ce projet est reserve a votre edition temporaire.';
          projectBadge.classList.remove('hidden');
        } else {
          projectBadge.classList.add('hidden');
          projectBadge.textContent = '';
        }
      }
    }

    function renderTaskDescriptionToElement(task = {}, targetEl = null) {
      if (!targetEl) return;
      const html = sanitizeRichTextHtmlPreserve(task.descriptionHtml || '');
      if (html) {
        targetEl.innerHTML = html;
        return;
      }
      targetEl.textContent = applyProfanityFilterToText(String(task.description || '').trim()) || 'Aucune description.';
    }

    function mapTaskStatusToProjectStatus(taskStatus = '') {
      const status = String(taskStatus || '').trim();
      if (status === 'termine') return 'termine';
      if (status === 'todo') return 'planifie';
      return 'en-cours';
    }

    function closeTaskConvertModal() {
      const modal = document.getElementById('modal-task-convert');
      if (!modal) return;
      modal.classList.add('hidden');
      pendingTaskConvertRef = null;
      const errorEl = document.getElementById('task-convert-error');
      if (errorEl) errorEl.classList.add('hidden');
    }

    async function openTaskConvertModal(taskRef, prefill = {}) {
      const modal = document.getElementById('modal-task-convert');
      if (!modal) {
        await convertTaskToProject(taskRef, { ...prefill, __fromModal: true });
        return;
      }
      const resolved = await resolveGlobalTaskFromRef(taskRef);
      if (!resolved?.task) {
        showToast('Tache introuvable');
        return;
      }
      const task = resolved.task;
      const sourceType = resolved.sourceType;
      const sourceState = sourceType === 'project' ? resolved.state : null;
      if (sourceType === 'project' && !canEditTaskInProject(task, sourceState)) {
        showToast('Action non autorisee');
        return;
      }

      const suggestedName = String(task.title || '').trim() || 'Nouveau projet';
      const sharingMode = normalizeSharingMode(
        prefill?.sharingMode || task.sharingMode || sourceState?.project?.sharingMode || 'private',
        'private'
      );
      const sourceProjectName = sourceType === 'project'
        ? String(sourceState?.project?.name || '').trim()
        : 'Hors projet';

      const sourceLabelEl = document.getElementById('task-convert-source-label');
      const projectNameInput = document.getElementById('task-convert-project-name');
      const modeSelect = document.getElementById('task-convert-mode');
      const archiveCheckbox = document.getElementById('task-convert-archive-source');
      const openCheckbox = document.getElementById('task-convert-open-project');
      const errorEl = document.getElementById('task-convert-error');

      if (sourceLabelEl) sourceLabelEl.textContent = `${String(task.title || 'Tâche').trim()} • ${sourceProjectName}`;
      if (projectNameInput) projectNameInput.value = String(prefill?.projectName || suggestedName);
      if (modeSelect) modeSelect.value = sharingMode;
      if (archiveCheckbox) archiveCheckbox.checked = prefill?.archiveSource !== false;
      if (openCheckbox) openCheckbox.checked = prefill?.openProjectAfterConvert !== false;
      if (errorEl) errorEl.classList.add('hidden');

      pendingTaskConvertRef = taskRef;
      modal.classList.remove('hidden');
      requestAnimationFrame(() => {
        projectNameInput?.focus();
        projectNameInput?.select();
      });
    }

    async function convertTaskToProject(taskRef, options = {}) {
      if (!options?.__fromModal) {
        await openTaskConvertModal(taskRef, options || {});
        return;
      }

      const resolved = await resolveGlobalTaskFromRef(taskRef);
      if (!resolved?.task) {
        showToast('Tache introuvable');
        return;
      }
      const task = resolved.task;
      const sourceType = resolved.sourceType;
      const sourceState = sourceType === 'project' ? resolved.state : null;
      if (sourceType === 'project' && !canEditTaskInProject(task, sourceState)) {
        showToast('Action non autorisee');
        return;
      }

      const suggestedName = String(task.title || '').trim() || 'Nouveau projet';
      const projectName = String(options?.projectName || suggestedName).trim();
      if (!projectName) return;

      const archiveSourceTask = options?.archiveSource === true;

      const projectId = `project-${Date.now()}-${Math.floor(Math.random() * 1000)}`;
      const sourceProject = sourceState?.project || null;
      const sharingMode = normalizeSharingMode(
        options?.sharingMode || task.sharingMode || sourceProject?.sharingMode || 'private',
        'private'
      );
      const readAccess = String(sourceProject?.readAccess || 'private') === 'public' ? 'public' : 'private';
      const descriptionHtml = sanitizeProjectDescriptionHtml(
        String(task.descriptionHtml || task.description || '').trim()
      );
      const assignees = Array.isArray(task.assignees) && task.assignees.length > 0
        ? task.assignees
        : getTaskAssigneeEntries(task, sourceState);
      const preparedAssignees = assignees
        .map((entry) => ({
          agentId: entry?.agentId ? String(entry.agentId).trim() : null,
          userId: entry?.userId ? String(entry.userId).trim() : null,
          name: String(entry?.name || '').trim(),
          email: String(entry?.email || '').trim()
        }))
        .filter((entry) => entry.agentId || entry.userId || entry.name || entry.email);
      const primaryAssignee = preparedAssignees[0] || { userId: null, name: '', email: '' };
      const firstTaskId = uuidv4();
      const firstGroupName = String(task.groupName || getTaskGroupName(task, sourceState) || '').trim();
      const firstGroupId = firstGroupName ? uuidv4() : null;

      let sharedKeyHex = null;
      try {
        await runWithLoading(async () => {
          if (sharingMode === 'shared') {
            const sharedKey = await window.TaskMDACrypto.generateSharedKey();
            sharedKeyHex = await window.TaskMDACrypto.exportSharedKey(sharedKey);
            await putEncrypted('sharedKeys', {
              projectId,
              sharedKey: sharedKeyHex,
              passphrase: null,
              createdAt: Date.now()
            }, 'projectId');
          }

          const createProjectEvent = createEvent(
            EventTypes.CREATE_PROJECT,
            projectId,
            currentUser.userId,
            {
              name: projectName,
              description: descriptionHtml,
              status: mapTaskStatusToProjectStatus(task.status || ''),
              readAccess,
              sharingMode,
              joinPassphrase: null
            }
          );
          await publishEvent(createProjectEvent);

          const addOwnerEvent = createEvent(
            EventTypes.ADD_MEMBER,
            projectId,
            currentUser.userId,
            { userId: currentUser.userId, role: 'owner' }
          );
          await publishEvent(addOwnerEvent);

          const createGroupEvent = firstGroupId
            ? createEvent(
                EventTypes.CREATE_GROUP,
                projectId,
                currentUser.userId,
                { groupId: firstGroupId, name: firstGroupName, description: 'Groupe importé depuis une tâche convertie' }
              )
            : null;
          if (createGroupEvent) {
            await publishEvent(createGroupEvent);
          }

          const createTaskEvent = createEvent(
            EventTypes.CREATE_TASK,
            projectId,
            currentUser.userId,
            {
              taskId: firstTaskId,
              createdBy: task.createdBy || currentUser.userId,
              title: task.title || 'Tâche convertie',
              assignee: primaryAssignee.name || '',
              assigneeUserId: primaryAssignee.userId || null,
              assignees: preparedAssignees,
              description: getProjectDescriptionPlainText(descriptionHtml).trim() || String(task.description || '').trim(),
              descriptionHtml: descriptionHtml || '',
              requestDate: task.requestDate || null,
              dueDate: task.dueDate || null,
              status: task.status || 'todo',
              urgency: task.urgency || 'medium',
              theme: String(task.theme || '').trim(),
              groupId: firstGroupId,
              groupName: firstGroupName || null,
              subtasks: normalizeTaskSubtasks(task),
              attachments: Array.isArray(task.attachments) ? task.attachments : []
            }
          );
          await publishEvent(createTaskEvent);

          if (sharingMode === 'shared') {
            const bootstrapEvents = [
              createProjectEvent,
              addOwnerEvent,
              ...(createGroupEvent ? [createGroupEvent] : []),
              createTaskEvent
            ];
            void syncProjectBootstrapToSharedSpace(projectId, sharedKeyHex, bootstrapEvents);
          }

          if (archiveSourceTask) {
            if (sourceType === 'project') {
              const sourceProjectId = resolved.projectId;
              const archiveEvent = createEvent(
                EventTypes.UPDATE_TASK,
                sourceProjectId,
                currentUser.userId,
                {
                  taskId: task.taskId,
                  changes: {
                    status: 'termine',
                    archivedAt: Date.now(),
                    convertedProjectId: projectId,
                    convertedAt: Date.now()
                  }
                }
              );
              await publishEvent(archiveEvent);
              if (sharedFolderHandle) { void syncProjectEventsToSharedSpace(sourceProjectId, [archiveEvent]); }
            } else {
              await putEncrypted('globalTasks', {
                ...task,
                status: 'termine',
                archivedAt: Date.now(),
                convertedProjectId: projectId,
                convertedAt: Date.now(),
                updatedAt: Date.now()
              }, 'id');
            }
          }
        });

        await closeGlobalTaskDetails();
        await refreshStats();
        await renderProjects();
        if (workspaceMode === 'global') {
          await renderGlobalTasks();
        }
        if (resolved.sourceType === 'project' && currentProjectId === resolved.projectId) {
          await showProjectDetail(currentProjectId);
        }
        showToast('✅ Tâche convertie en projet');
        if (options?.openProjectAfterConvert !== false) {
          await showProjectDetail(projectId);
        }
      } catch (error) {
        console.error('Task convert to project failed:', error);
        showToast('❌ Conversion impossible');
      }
    }

    async function openGlobalTaskDetails(taskRef) {
      const modal = document.getElementById('modal-global-task-details');
      if (!modal) return;
      const resolved = await resolveGlobalTaskFromRef(taskRef);
      if (!resolved?.task) {
        showToast('Tache introuvable');
        return;
      }
      const task = resolved.task;
      const state = resolved.sourceType === 'project' ? resolved.state : null;
      const isStandalone = resolved.sourceType === 'standalone';
      const canEdit = isStandalone ? true : canEditTaskInProject(task, state);
      const canArchive = isStandalone ? true : canEditTaskInProject(task, state);
      const canDelete = isStandalone ? true : canDeleteTaskInProject(task, state);
      resetTaskDetailInlineEditingState();
      const titleEl = document.getElementById('global-task-detail-title');
      const subtitleEl = document.getElementById('global-task-detail-subtitle');
      const badgesEl = document.getElementById('global-task-detail-badges');
      const descriptionEl = document.getElementById('global-task-detail-description');
      const requestDateEl = document.getElementById('global-task-detail-request-date');
      const dueDateEl = document.getElementById('global-task-detail-due-date');
      const assigneesEl = document.getElementById('global-task-detail-assignees');
      const groupEl = document.getElementById('global-task-detail-group');
      const recurrenceWrapEl = document.getElementById('global-task-detail-recurrence-wrap');
      const recurrenceEl = document.getElementById('global-task-detail-recurrence');
      const subtasksEl = document.getElementById('global-task-detail-subtasks');
      const attachmentsEl = document.getElementById('global-task-detail-attachments');
      const btnConvert = document.getElementById('btn-global-task-detail-convert');
      const btnTaskEmail = document.getElementById('btn-global-task-detail-email');
      const taskEmailTemplateSelect = document.getElementById('global-task-detail-email-template');
      const btnEdit = document.getElementById('btn-global-task-detail-edit');
      const btnArchive = document.getElementById('btn-global-task-detail-archive');
      const btnDelete = document.getElementById('btn-global-task-detail-delete');
      const statusMeta = getTaskStatusMeta(task.status || 'todo');
      const urgencyMeta = getTaskUrgencyMeta(task.urgency || 'medium');
      const sourceProjectName = isStandalone
        ? 'Hors projet'
        : (state?.project?.name || 'Projet');
      const sourceTheme = String(task.theme || 'General');
      const assigneeNames = getTaskAssigneeName(task, state) || 'Aucun responsable';
      const groupName = getTaskGroupName(task, state) || task.groupName || 'Aucun groupe';
      const attachments = Array.isArray(task.attachments) ? task.attachments : [];
      const canToggleSubtasks = canToggleTaskDetailSubtasks(task, resolved);

      if (titleEl) titleEl.textContent = task.title || 'Tache';
      if (subtitleEl) {
        subtitleEl.innerHTML = `${escapeHtml(sourceProjectName)} • <span id="global-task-detail-theme">${escapeHtml(sourceTheme || 'General')}</span>`;
      }
      if (badgesEl) {
        badgesEl.innerHTML = `
          <span id="global-task-detail-urgency-chip" class="${urgencyMeta.chipClass}">${urgencyMeta.label}</span>
          <span id="global-task-detail-status-chip" class="${statusMeta.chipClass}">${statusMeta.label}</span>
          ${buildTaskAssigneeKindBadgeHtml(task, state)}
          ${buildTaskHierarchyChipsHtml(task, state)}
          ${sharingModeBadge(task.sharingMode)}
        `;
      }
      renderTaskDescriptionToElement(task, descriptionEl);
      if (requestDateEl) requestDateEl.textContent = formatDate(task.requestDate);
      if (dueDateEl) dueDateEl.textContent = formatTaskDeadline(task);
      if (assigneesEl) assigneesEl.innerHTML = `<span class="inline-flex items-center gap-1.5">${buildTaskAssigneeInlineHtml(task, state)}</span>`;
      if (groupEl) groupEl.textContent = groupName;
      if (recurrenceWrapEl && recurrenceEl) {
        const recurringCfg = normalizeTaskRecurringConfig(task?.recurring);
        const recurrenceLabel = recurringCfg
          ? (window.TaskMDARecurrence?.formatRecurrenceLabel?.(recurringCfg) || 'Récurrence configurable')
          : 'Non récurrente';
        recurrenceEl.textContent = recurrenceLabel;
        recurrenceWrapEl.classList.remove('hidden');
      }
      if (subtasksEl) {
        renderTaskDetailSubtasks(subtasksEl, task, { taskRef, canToggle: canToggleSubtasks, resolved });
      }
      if (attachmentsEl) {
        if (attachments.length === 0) {
          attachmentsEl.innerHTML = '<p class="text-slate-500">Aucun document lié.</p>';
        } else {
          const canDeleteAttachment = canEdit;
          attachmentsEl.innerHTML = attachments.map((file, index) => {
            const safeHref = sanitizeDownloadHref(file?.data || '', String(file?.type || ''));
            const href = safeHref ? safeHref.replace(/"/g, '&quot;') : '#';
            return `
            <span class="inline-flex items-center gap-2 mr-3 mb-1">
              <a class="inline-flex items-center gap-1 text-primary hover:underline ${safeHref ? '' : 'opacity-60 pointer-events-none'}" href="${href}" ${safeHref ? `download="${escapeHtml(file?.name || `piece-jointe-${index + 1}`)}"` : ''}>
                <span class="material-symbols-outlined text-sm">attach_file</span>
                <span>${escapeHtml(file?.name || `piece-jointe-${index + 1}`)}</span>
              </a>
              ${canDeleteAttachment ? `<button type="button" class="task-action-btn task-action-btn-danger" onclick="removeAttachment('${escapeHtml(task.taskId)}', ${index})">Supprimer</button>` : ''}
            </span>
          `;
          }).join('');
        }
      }

      if (btnConvert) {
        btnConvert.classList.toggle('hidden', !canEdit);
        btnConvert.onclick = async () => {
          await closeGlobalTaskDetails();
          await convertTaskToProject(taskRef);
        };
      }
      if (taskEmailTemplateSelect) {
        taskEmailTemplateSelect.value = getSavedTaskEmailTemplatePreference();
      }
      if (btnTaskEmail) {
        btnTaskEmail.classList.remove('hidden');
        btnTaskEmail.onclick = async () => {
          const selectedTemplate = normalizeTaskEmailTemplate(taskEmailTemplateSelect?.value || 'auto');
          saveTaskEmailTemplatePreference(selectedTemplate);
          await sendTaskEmailByRef(taskRef, selectedTemplate);
        };
      }
      if (btnEdit) {
        btnEdit.classList.toggle('hidden', !canEdit);
        btnEdit.onclick = async () => {
          await closeGlobalTaskDetails();
          await editGlobalTask(taskRef);
        };
      }
      if (btnArchive) {
        btnArchive.classList.toggle('hidden', !canArchive);
        btnArchive.onclick = async () => {
          await closeGlobalTaskDetails();
          await archiveGlobalTask(taskRef);
        };
      }
      if (btnDelete) {
        btnDelete.classList.toggle('hidden', !canDelete);
        btnDelete.onclick = async () => {
          await closeGlobalTaskDetails();
          await deleteGlobalTask(taskRef);
        };
      }

      currentGlobalTaskDetailContext = isStandalone
        ? {
          entityType: 'globalTask',
          entityId: String(task.id || '').trim(),
          label: `Tâche hors projet: ${task.title || 'Tâche'}`
        }
        : {
          entityType: 'task',
          entityId: `${state?.project?.projectId || ''}:${task.taskId || ''}`,
          label: `Tâche: ${task.title || 'Tâche'}`
        };
      currentGlobalTaskDetailTask = { ...task };
      currentGlobalTaskDetailResolved = resolved;
      await renderTaskDetailRgpdImpactCard(currentGlobalTaskDetailContext);
      currentGlobalTaskDetailRef = taskRef;
      initTaskDetailInlineEditing(canEdit);
      modal.classList.remove('hidden');
    }

    async function openProjectTaskDetails(taskId) {
      if (!currentProjectId || !taskId) return;
      const modal = document.getElementById('modal-global-task-details');
      if (!modal) return;
      const state = await getProjectState(currentProjectId);
      if (!state?.project) return;
      const task = (state.tasks || []).find(t => t.taskId === taskId);
      if (!task) {
        showToast('Tache introuvable');
        return;
      }

      const canEdit = canEditTaskInProject(task, state);
      const canArchive = canEditTaskInProject(task, state);
      const canDelete = canDeleteTaskInProject(task, state);
      resetTaskDetailInlineEditingState();
      const titleEl = document.getElementById('global-task-detail-title');
      const subtitleEl = document.getElementById('global-task-detail-subtitle');
      const badgesEl = document.getElementById('global-task-detail-badges');
      const descriptionEl = document.getElementById('global-task-detail-description');
      const requestDateEl = document.getElementById('global-task-detail-request-date');
      const dueDateEl = document.getElementById('global-task-detail-due-date');
      const assigneesEl = document.getElementById('global-task-detail-assignees');
      const groupEl = document.getElementById('global-task-detail-group');
      const recurrenceWrapEl = document.getElementById('global-task-detail-recurrence-wrap');
      const recurrenceEl = document.getElementById('global-task-detail-recurrence');
      const subtasksEl = document.getElementById('global-task-detail-subtasks');
      const attachmentsEl = document.getElementById('global-task-detail-attachments');
      const btnConvert = document.getElementById('btn-global-task-detail-convert');
      const btnTaskEmail = document.getElementById('btn-global-task-detail-email');
      const taskEmailTemplateSelect = document.getElementById('global-task-detail-email-template');
      const btnEdit = document.getElementById('btn-global-task-detail-edit');
      const btnArchive = document.getElementById('btn-global-task-detail-archive');
      const btnDelete = document.getElementById('btn-global-task-detail-delete');
      const statusMeta = getTaskStatusMeta(task.status || 'todo');
      const urgencyMeta = getTaskUrgencyMeta(task.urgency || 'medium');
      const sourceProjectName = state?.project?.name || 'Projet';
      const sourceTheme = String(task.theme || 'General');
      const assigneeNames = getTaskAssigneeName(task, state) || 'Aucun responsable';
      const groupName = getTaskGroupName(task, state) || task.groupName || 'Aucun groupe';
      const attachments = Array.isArray(task.attachments) ? task.attachments : [];
      const linkedDocs = (state.documents || []).filter(doc => (doc.linkedTaskIds || []).includes(taskId));
      const sharingMode = task.sharingMode || state?.project?.sharingMode || 'shared';
      const canToggleSubtasks = canToggleTaskDetailSubtasks(task, {
        sourceType: 'project',
        state,
        task,
        projectId: currentProjectId
      });

      if (titleEl) titleEl.textContent = task.title || 'Tache';
      if (subtitleEl) {
        subtitleEl.innerHTML = `${escapeHtml(sourceProjectName)} • <span id="global-task-detail-theme">${escapeHtml(sourceTheme || 'General')}</span>`;
      }
      if (badgesEl) {
        badgesEl.innerHTML = `
          <span id="global-task-detail-urgency-chip" class="${urgencyMeta.chipClass}">${urgencyMeta.label}</span>
          <span id="global-task-detail-status-chip" class="${statusMeta.chipClass}">${statusMeta.label}</span>
          ${buildTaskAssigneeKindBadgeHtml(task, state)}
          ${buildTaskHierarchyChipsHtml(task, state)}
          ${sharingModeBadge(sharingMode)}
        `;
      }
      renderTaskDescriptionToElement(task, descriptionEl);
      if (requestDateEl) requestDateEl.textContent = formatDate(task.requestDate);
      if (dueDateEl) dueDateEl.textContent = formatTaskDeadline(task);
      if (assigneesEl) assigneesEl.innerHTML = `<span class="inline-flex items-center gap-1.5">${buildTaskAssigneeInlineHtml(task, state)}</span>`;
      if (groupEl) groupEl.textContent = groupName;
      if (recurrenceWrapEl && recurrenceEl) {
        const recurringCfg = normalizeTaskRecurringConfig(task?.recurring);
        const recurrenceLabel = recurringCfg
          ? (window.TaskMDARecurrence?.formatRecurrenceLabel?.(recurringCfg) || 'Récurrence configurable')
          : 'Non récurrente';
        recurrenceEl.textContent = recurrenceLabel;
        recurrenceWrapEl.classList.remove('hidden');
      }
      if (subtasksEl) {
        renderTaskDetailSubtasks(subtasksEl, task, {
          taskRef: buildGlobalTaskRef({ sourceType: 'project', sourceProjectId: currentProjectId, taskId: task.taskId }),
          canToggle: canToggleSubtasks,
          resolved: {
            sourceType: 'project',
            state,
            task,
            projectId: currentProjectId
          }
        });
      }
      if (attachmentsEl) {
        const allItems = [
          ...attachments.map((file, index) => ({ type: 'attachment', file, index })),
          ...linkedDocs.map((doc) => ({ type: 'project-doc', doc }))
        ];
        if (allItems.length === 0) {
          attachmentsEl.innerHTML = '<p class="text-slate-500">Aucun document lie.</p>';
        } else {
          attachmentsEl.innerHTML = allItems.map((item) => {
            if (item.type === 'attachment') {
              const file = item.file || {};
              const safeHref = sanitizeDownloadHref(file?.data || '', String(file?.type || ''));
              const href = safeHref ? safeHref.replace(/"/g, '&quot;') : '#';
              return `
                <span class="inline-flex items-center gap-2 mr-3 mb-1">
                  <a class="inline-flex items-center gap-1 text-primary hover:underline ${safeHref ? '' : 'opacity-60 pointer-events-none'}" href="${href}" ${safeHref ? `download="${escapeHtml(file?.name || `piece-jointe-${item.index + 1}`)}"` : ''}>
                    <span class="material-symbols-outlined text-sm">attach_file</span>
                    <span>${escapeHtml(file?.name || `piece-jointe-${item.index + 1}`)}</span>
                  </a>
                  ${canEdit ? `<button type="button" class="task-action-btn task-action-btn-danger" onclick="removeAttachment('${escapeHtml(task.taskId)}', ${item.index})">Supprimer</button>` : ''}
                </span>
              `;
            }
            const doc = item.doc || {};
            const safeHref = sanitizeDownloadHref(doc?.data || '', String(doc?.type || ''));
            const href = safeHref ? safeHref.replace(/"/g, '&quot;') : '#';
            return `
              <a class="inline-flex items-center gap-1 text-primary hover:underline mr-3 ${safeHref ? '' : 'opacity-60 pointer-events-none'}" href="${href}" ${safeHref ? `download="${escapeHtml(doc?.name || 'document')}"` : ''}>
                <span class="material-symbols-outlined text-sm">description</span>
                <span>${escapeHtml(doc?.name || 'document')}</span>
              </a>
            `;
          }).join('');
        }
      }

      if (btnConvert) {
        btnConvert.classList.toggle('hidden', !canEdit);
        btnConvert.onclick = async () => {
          const taskRef = buildGlobalTaskRef({
            sourceType: 'project',
            sourceProjectId: currentProjectId,
            taskId: task.taskId
          });
          await closeGlobalTaskDetails();
          await convertTaskToProject(taskRef);
        };
      }
      if (taskEmailTemplateSelect) {
        taskEmailTemplateSelect.value = getSavedTaskEmailTemplatePreference();
      }
      if (btnTaskEmail) {
        btnTaskEmail.classList.remove('hidden');
        btnTaskEmail.onclick = async () => {
          const selectedTemplate = normalizeTaskEmailTemplate(taskEmailTemplateSelect?.value || 'auto');
          saveTaskEmailTemplatePreference(selectedTemplate);
          await sendTaskEmail(task.taskId, selectedTemplate);
        };
      }
      if (btnEdit) {
        btnEdit.classList.toggle('hidden', !canEdit);
        btnEdit.onclick = async () => {
          await closeGlobalTaskDetails();
          await editTask(taskId);
        };
      }
      if (btnArchive) {
        btnArchive.classList.toggle('hidden', !canArchive);
        btnArchive.onclick = async () => {
          await closeGlobalTaskDetails();
          await archiveTask(taskId);
        };
      }
      if (btnDelete) {
        btnDelete.classList.toggle('hidden', !canDelete);
        btnDelete.onclick = async () => {
          await closeGlobalTaskDetails();
          await deleteTask(taskId);
        };
      }

      currentGlobalTaskDetailContext = {
        entityType: 'task',
        entityId: `${state?.project?.projectId || ''}:${task.taskId || ''}`,
        label: `Tâche: ${task.title || 'Tâche'}`
      };
      currentGlobalTaskDetailTask = { ...task };
      currentGlobalTaskDetailResolved = {
        sourceType: 'project',
        projectId: currentProjectId,
        state,
        task
      };
      await renderTaskDetailRgpdImpactCard(currentGlobalTaskDetailContext);
      currentGlobalTaskDetailRef = buildGlobalTaskRef({
        sourceType: 'project',
        sourceProjectId: currentProjectId,
        taskId
      });
      initTaskDetailInlineEditing(canEdit);
      modal.classList.remove('hidden');
    }

    async function collectProjectRecipientEmails(state = currentProjectState, options = {}) {
      const recipients = new Set();
      const includeInvites = options.includeInvites !== false;
      const includeProjectAssignees = options.includeProjectAssignees === true;
      const task = options.task || null;

      if (includeInvites) {
        (state?.invites || []).forEach((inv) => {
          const email = String(inv?.email || '').trim().toLowerCase();
          if (inv?.status === 'declined') return;
          if (isValidEmailAddress(email)) recipients.add(email);
        });
      }

      const users = await getAllDecrypted('users', 'userId');
      const directoryUsers = await getAllDecrypted('directoryUsers', 'userId');
      const emailByUserId = new Map();
      (directoryUsers || []).forEach((user) => {
        const id = String(user?.userId || '').trim();
        const email = String(user?.email || '').trim().toLowerCase();
        if (id && isValidEmailAddress(email)) emailByUserId.set(id, email);
      });
      (users || []).forEach((user) => {
        const id = String(user?.userId || '').trim();
        const email = String(user?.email || '').trim().toLowerCase();
        if (id && isValidEmailAddress(email)) emailByUserId.set(id, email);
      });

      (state?.members || []).forEach((member) => {
        const memberEmail = String(member?.email || '').trim().toLowerCase();
        if (isValidEmailAddress(memberEmail)) recipients.add(memberEmail);
        const mapped = emailByUserId.get(String(member?.userId || '').trim());
        if (mapped) recipients.add(mapped);
      });

      const addAssigneeEmail = (entry) => {
        if (!entry) return;
        const directEmail = String(entry?.email || '').trim().toLowerCase();
        if (isValidEmailAddress(directEmail)) recipients.add(directEmail);
        const mappedById = emailByUserId.get(String(entry?.userId || '').trim());
        if (mappedById) recipients.add(mappedById);
        const parsedFromName = parseAssigneeToken(entry?.name || '');
        if (isValidEmailAddress(parsedFromName?.email || '')) {
          recipients.add(String(parsedFromName.email).toLowerCase());
        }
      };

      if (task) {
        getTaskAssigneeEntries(task, state).forEach(addAssigneeEmail);
      } else if (includeProjectAssignees) {
        (state?.tasks || []).forEach((projectTask) => {
          getTaskAssigneeEntries(projectTask, state).forEach(addAssigneeEmail);
        });
      }

      return Array.from(recipients);
    }

    function normalizeMailText(value) {
      return String(value || '')
        .normalize('NFD')
        .replace(/[\u0300-\u036f]/g, '')
        .replace(/[â€™â€˜]/g, "'")
        .replace(/[“”]/g, '"')
        .replace(/\u2026/g, '...');
    }

    function openMailto({ to = [], subject = '', body = '' }) {
      const toValue = Array.isArray(to) ? to.join(',') : String(to || '');
      // Outlook/clients Windows can misread UTF-8 percent-encoding in mailto.
      // We normalize to ASCII-safe text to avoid mojibake in generated drafts.
      const safeSubject = normalizeMailText(subject);
      const safeBody = normalizeMailText(body);
      const mailto = `mailto:${encodeURIComponent(toValue)}?subject=${encodeURIComponent(safeSubject)}&body=${encodeURIComponent(safeBody)}`;
      window.location.href = mailto;
    }

    async function sendInvitationEmail(inviteId) {
      if (!currentProjectId) return;
      if (!canManageProjectCollaboration(currentProjectState)) {
        showToast('Seuls Propriétaire/Manager peuvent envoyer des invitations');
        return;
      }
      const state = await getProjectState(currentProjectId);
      const invite = (state?.invites || []).find(i => i.inviteId === inviteId);
      if (!invite) return;

      const projectName = state?.project?.name || 'Projet';
      const roleLabel = getProjectRoleLabel(invite.role);
      const typeLabel = invite.inviteType === 'agent' ? 'agent' : 'utilisateur';
      const subject = `[NEXUS MDA] Invitation projet: ${projectName}`;
      const body = [
        `Bonjour ${invite.displayName || ''},`,
        '',
        `Vous êtes invité(e) en tant que ${typeLabel} (${roleLabel}) sur le projet "${projectName}".`,
        '',
        'Merci de confirmer votre disponibilité et votre prise en charge.',
        '',
        `Envoyé par: ${currentUser?.name || 'Equipe projet'}`,
        `Date: ${new Date().toLocaleDateString('fr-FR')}`
      ].join('\n');

      openMailto({ to: [invite.email], subject, body });

      const event = createEvent(
        EventTypes.UPDATE_INVITE,
        currentProjectId,
        currentUser.userId,
        { inviteId, changes: { status: 'sent', lastSentAt: Date.now() } }
      );
      await publishEvent(event);
      if (sharedFolderHandle) void syncProjectEventsToSharedSpace(currentProjectId, [event]);
      await showProjectDetail(currentProjectId);
    }

    async function updateInviteStatus(inviteId, status) {
      if (!currentProjectId || !inviteId) return;
      if (!canManageProjectCollaboration(currentProjectState)) {
        showToast('Seuls Propriétaire/Manager peuvent mettre à jour les invitations');
        return;
      }
      const normalized = ['pending', 'sent', 'accepted', 'declined'].includes(status) ? status : 'pending';
      const invite = (currentProjectState?.invites || []).find(i => i.inviteId === inviteId);
      const myRole = normalizeProjectRole(getMyProjectRole(currentProjectState));
      if (normalized === 'accepted' && myRole === 'manager' && normalizeProjectRole(invite?.role) !== 'member') {
        showToast('Action non autorisee');
        return;
      }
      const event = createEvent(
        EventTypes.UPDATE_INVITE,
        currentProjectId,
        currentUser.userId,
        { inviteId, changes: { status: normalized } }
      );
      await publishEvent(event);
      if (sharedFolderHandle) void syncProjectEventsToSharedSpace(currentProjectId, [event]);
      if (normalized === 'accepted' && invite) {
        const users = await getAllDecrypted('users', 'userId');
        let user = users.find(u => normalizeSearch(u.name) === normalizeSearch(invite.displayName));
        if (!user) {
          user = { userId: uuidv4(), name: invite.displayName, email: invite.email, createdAt: Date.now() };
          await putEncrypted('users', user, 'userId');
        }
        await upsertDirectoryUser({
          userId: user.userId,
          name: user.name,
          email: user.email || '',
          source: 'invite_accept',
          lastSeenAt: Date.now()
        });
        const memberExists = (currentProjectState?.members || []).some(m => m.userId === user.userId);
        if (!memberExists) {
          const memberEvent = createEvent(
            EventTypes.ADD_MEMBER,
            currentProjectId,
            currentUser.userId,
            { userId: user.userId, role: invite.role || 'member', displayName: user.name }
          );
          await publishEvent(memberEvent);
          if (sharedFolderHandle) void syncProjectEventsToSharedSpace(currentProjectId, [memberEvent]);
        }
      }
      showToast(`Invitation marquée: ${normalized}`);
      await showProjectDetail(currentProjectId);
    }

    async function addProjectInvite() {
      if (!currentProjectId || !currentProjectState) return;
      if (!canManageProjectCollaboration(currentProjectState)) {
        showToast('Seuls Propriétaire/Manager peuvent inviter');
        return;
      }

      const nameInput = document.getElementById('invite-name-input');
      const emailInput = document.getElementById('invite-email-input');
      const typeInput = document.getElementById('invite-type-input');
      const roleInput = document.getElementById('invite-role-input');
      const displayName = (nameInput?.value || '').trim();
      const email = (emailInput?.value || '').trim().toLowerCase();
      const inviteType = (typeInput?.value || 'user').trim();
      const selectedRoleKey = String(roleInput?.value || 'member').trim() || 'member';
      const role = getProjectRoleMeta(selectedRoleKey).roleKey;
      const targetRoleBase = normalizeProjectRole(selectedRoleKey);
      const myRole = normalizeProjectRole(getMyProjectRole(currentProjectState));
      if (myRole === 'manager' && targetRoleBase !== 'member') {
        showToast('Action non autorisee');
        return;
      }

      if (!displayName) {
        showToast('Nom invité requis');
        return;
      }
      const emailOk = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
      if (!emailOk) {
        showToast('Email professionnel invalide');
        return;
      }
      const exists = (currentProjectState.invites || []).some(inv => normalizeSearch(inv.email) === normalizeSearch(email));
      if (exists) {
        showToast('Cette adresse est déjà invitée');
        return;
      }

      const event = createEvent(
        EventTypes.CREATE_INVITE,
        currentProjectId,
        currentUser.userId,
        {
          inviteId: uuidv4(),
          displayName,
          email,
          inviteType: inviteType === 'agent' ? 'agent' : 'user',
          role,
          status: 'pending'
        }
      );
      await publishEvent(event);
      if (sharedFolderHandle) void syncProjectEventsToSharedSpace(currentProjectId, [event]);

      if (nameInput) nameInput.value = '';
      if (emailInput) emailInput.value = '';
      showToast('Invitation créée');
      addNotification('Invitation', `${displayName} invité(e)`, currentProjectId);
      await showProjectDetail(currentProjectId);
    }

    function renderProjectInvitations(state) {
      const container = document.getElementById('project-invites-list');
      const btn = document.getElementById('btn-send-invite');
      if (!container || !btn) return;
      const canManage = canManageProjectCollaboration(state);
      const myRole = normalizeProjectRole(getMyProjectRole(state));
      btn.disabled = !canManage;
      btn.classList.toggle('opacity-50', !canManage);

      const invites = state?.invites || [];
      if (invites.length === 0) {
        container.innerHTML = `
          <div class="empty-state-card">
            <p class="empty-state-title">Aucune invitation envoyée</p>
            <p class="empty-state-text">Invitez un utilisateur ou un agent pour activer la collaboration.</p>
            ${canManage ? '<button class="empty-state-cta" onclick="focusElementById(\'invite-email-input\')">Envoyer une invitation</button>' : ''}
          </div>
        `;
        return;
      }

      const statusClass = {
        pending: 'bg-amber-100 text-amber-700',
        sent: 'bg-blue-100 text-blue-700',
        accepted: 'bg-emerald-100 text-emerald-700',
        declined: 'bg-rose-100 text-rose-700'
      };

      container.innerHTML = invites
        .slice()
        .sort((a, b) => (b.invitedAt || 0) - (a.invitedAt || 0))
        .map(inv => `
          <div class="rounded-lg border border-slate-200 bg-white p-3">
            <div class="flex items-start justify-between gap-2">
              <div>
                <p class="text-sm font-semibold text-slate-800">${escapeHtml(inv.displayName || 'Invité')}</p>
                <p class="text-xs text-slate-500">${escapeHtml(inv.email || '')} • ${(inv.inviteType === 'agent' ? 'Agent' : 'Utilisateur')} • ${escapeHtml(getProjectRoleLabel(inv.role || 'member'))}</p>
              </div>
              <span class="text-[10px] px-2 py-1 rounded-full font-semibold ${statusClass[inv.status] || statusClass.pending}">${escapeHtml(inv.status || 'pending')}</span>
            </div>
            <div class="mt-2 flex flex-wrap gap-2 text-xs">
              ${canManage ? `<button onclick="sendInvitationEmail('${inv.inviteId}')" class="task-action-btn task-action-btn-subtle" data-action-kind="notify">Email</button>` : ''}
              ${canManage && (myRole === 'owner' || normalizeProjectRole(inv.role) === 'member') ? `<button onclick="updateInviteStatus('${inv.inviteId}','accepted')" class="task-action-btn" data-action-kind="success">Accepté</button>` : ''}
              ${canManage ? `<button onclick="updateInviteStatus('${inv.inviteId}','declined')" class="task-action-btn task-action-btn-danger" data-action-kind="danger">Refusé</button>` : ''}
            </div>
          </div>
        `).join('');
    }

    async function createProjectGroup() {
      if (!currentProjectId || !currentProjectState) return;
      if (!canManageProjectCollaboration(currentProjectState)) {
        showToast('Seuls Propriétaire/Manager peuvent créer des groupes');
        return;
      }
      const nameInput = document.getElementById('group-name-input');
      const descInput = document.getElementById('group-description-input');
      const membersSelect = document.getElementById('group-members-input');
      const name = (nameInput?.value || '').trim();
      const description = (descInput?.value || '').trim();
      const selectedIds = Array.from(membersSelect?.selectedOptions || []).map(o => o.value).filter(Boolean);
      if (!name) {
        showToast('Nom de groupe requis');
        return;
      }
      const editGroup = selectedProjectGroupId
        ? (currentProjectState.groups || []).find(g => g.groupId === selectedProjectGroupId)
        : null;
      const exists = (currentProjectState.groups || []).some(g =>
        normalizeSearch(g.name) === normalizeSearch(name)
        && (!editGroup || g.groupId !== editGroup.groupId)
      );
      if (exists) {
        showToast('Ce groupe existe déjà');
        return;
      }

      const groupId = editGroup?.groupId || uuidv4();
      if (editGroup) {
        const event = createEvent(
          EventTypes.UPDATE_GROUP,
          currentProjectId,
          currentUser.userId,
          { groupId, changes: { name, description } }
        );
        await publishEvent(event);
        if (sharedFolderHandle) void syncProjectEventsToSharedSpace(currentProjectId, [event]);
      } else {
        const event = createEvent(
          EventTypes.CREATE_GROUP,
          currentProjectId,
          currentUser.userId,
          { groupId, name, description }
        );
        await publishEvent(event);
        if (sharedFolderHandle) void syncProjectEventsToSharedSpace(currentProjectId, [event]);
      }
      const existingUserGroup = (currentProjectState.userGroups || []).find(g =>
        g.groupId === groupId || normalizeSearch(g.name) === normalizeSearch(editGroup?.name || name)
      );
      if (existingUserGroup) {
        const eventUserGroupUpdate = createEvent(
          EventTypes.UPDATE_USER_GROUP,
          currentProjectId,
          currentUser.userId,
          { groupId: existingUserGroup.groupId, changes: { memberUserIds: [...new Set(selectedIds)], name, description } }
        );
        await publishEvent(eventUserGroupUpdate);
        if (sharedFolderHandle) void syncProjectEventsToSharedSpace(currentProjectId, [eventUserGroupUpdate]);
      } else {
        const eventUserGroupCreate = createEvent(
          EventTypes.CREATE_USER_GROUP,
          currentProjectId,
          currentUser.userId,
          { groupId, name, memberUserIds: [...new Set(selectedIds)] }
        );
        await publishEvent(eventUserGroupCreate);
        if (sharedFolderHandle) void syncProjectEventsToSharedSpace(currentProjectId, [eventUserGroupCreate]);
      }
      const refreshedAfterGroupSave = await getProjectState(currentProjectId, { ignoreAccessCheck: true });
      const savedGroup = (refreshedAfterGroupSave?.groups || []).find(g => g.groupId === groupId)
        || { name, description };
      const savedLinkedUserGroup = (refreshedAfterGroupSave?.userGroups || []).find(ug =>
        ug.groupId === groupId || normalizeSearch(ug.name) === normalizeSearch(savedGroup.name || name)
      );
      const savedMemberUserIds = Array.from(new Set(
        (savedLinkedUserGroup?.memberUserIds || selectedIds).map(id => String(id || '').trim()).filter(Boolean)
      ));
      await upsertGlobalGroup({
        name: savedGroup.name || name,
        description: savedGroup.description || description,
        memberUserIds: savedMemberUserIds,
        projectId: currentProjectId  // Tracker l'origine du groupe
      });
      await refreshGlobalTaxonomyCache();
      if (nameInput) nameInput.value = '';
      if (descInput) descInput.value = '';
      if (membersSelect) {
        Array.from(membersSelect.options || []).forEach(opt => { opt.selected = false; });
      }
      selectedProjectGroupId = null;
      showToast(editGroup ? 'Groupe modifié' : 'Groupe créé');
      addNotification('Groupe', editGroup ? `Groupe ${name} modifié` : `Groupe ${name} créé`, currentProjectId);
      await showProjectDetail(currentProjectId);
    }

    async function deleteProjectGroup(groupId) {
      if (!currentProjectId || !currentProjectState || !groupId) return;
      if (!canManageProjectCollaboration(currentProjectState)) {
        showToast('Seuls Propriétaire/Manager peuvent supprimer des groupes');
        return;
      }
      const groupName = getGroupNameById(currentProjectState, groupId) || 'ce groupe';
      if (!confirm(`Supprimer le groupe "${groupName}" ?`)) return;

      const event = createEvent(
        EventTypes.DELETE_GROUP,
        currentProjectId,
        currentUser.userId,
        { groupId }
      );
      await publishEvent(event);
      if (sharedFolderHandle) void syncProjectEventsToSharedSpace(currentProjectId, [event]);
      const linkedUserGroups = (currentProjectState.userGroups || []).filter(g =>
        g.groupId === groupId || normalizeSearch(g.name) === normalizeSearch(groupName)
      );
      for (const userGroup of linkedUserGroups) {
        const userGroupDeleteEvent = createEvent(
          EventTypes.DELETE_USER_GROUP,
          currentProjectId,
          currentUser.userId,
          { groupId: userGroup.groupId }
        );
        await publishEvent(userGroupDeleteEvent);
        if (sharedFolderHandle) void syncProjectEventsToSharedSpace(currentProjectId, [userGroupDeleteEvent]);
      }
      showToast('Groupe supprimé');
      await showProjectDetail(currentProjectId);
    }

    function renderProjectGroups(state) {
      const container = document.getElementById('project-groups-list');
      const btn = document.getElementById('btn-create-group');
      if (!container || !btn) return;
      const canManage = canManageProjectCollaboration(state);
      btn.disabled = !canManage;
      btn.classList.toggle('opacity-50', !canManage);

      const groups = state?.groups || [];
      if (groups.length === 0) {
        container.innerHTML = `
          <div class="empty-state-card">
            <p class="empty-state-title">Aucun groupe configuré</p>
            <p class="empty-state-text">Créez des groupes métier pour structurer les tâches et les documents.</p>
            ${canManage ? '<button class="empty-state-cta" onclick="focusElementById(\'group-name-input\')">Créer un groupe</button>' : ''}
          </div>
        `;
        return;
      }

      container.innerHTML = groups.map(group => {
        const assignedCount = (state?.tasks || []).filter(t => t.groupId === group.groupId).length;
        return `
          <div class="rounded-lg border border-slate-200 bg-white p-3 flex items-center justify-between gap-3">
            <div class="min-w-0">
              <p class="text-sm font-semibold text-slate-800 truncate">${escapeHtml(group.name)}</p>
              <p class="text-xs text-slate-500 truncate">${escapeHtml(group.description || 'Sans description')}</p>
              <p class="text-[11px] text-slate-500 mt-1">${assignedCount} tâche(s)</p>
            </div>
            ${canManage ? `<button onclick="deleteProjectGroup('${group.groupId}')" class="task-action-btn task-action-btn-danger" data-action-kind="danger">Supprimer</button>` : ''}
          </div>
        `;
      }).join('');
    }

    async function renderProjectGroups(state) {
      const container = document.getElementById('project-groups-list');
      const createBtn = document.getElementById('btn-create-group');
      const membersSelect = document.getElementById('group-members-input');
      if (!container || !createBtn || !membersSelect) return;
      const canManage = canManageProjectCollaboration(state);
      createBtn.disabled = !canManage;
      createBtn.classList.toggle('opacity-50', !canManage);
      membersSelect.disabled = !canManage;

      await renderProjectGroupMemberSelect(state);
      const members = await getProjectMembersResolved(state);
      const byId = new Map(members.map(m => [m.userId, m.displayNameResolved]));

      const groups = state?.groups || [];
      if (groups.length === 0) {
        container.innerHTML = `
          <div class="empty-state-card">
            <p class="empty-state-title">Aucun groupe configuré</p>
            <p class="empty-state-text">Créez des groupes et assignez des membres pour faciliter la répartition.</p>
            ${canManage ? '<button class="empty-state-cta" onclick="focusElementById(\'group-name-input\')">Créer un groupe</button>' : ''}
          </div>
        `;
        selectedProjectGroupId = null;
        createBtn.textContent = 'Créer groupe';
        const groupNameInput = document.getElementById('group-name-input');
        const groupDescriptionInput = document.getElementById('group-description-input');
        if (groupNameInput) groupNameInput.value = '';
        if (groupDescriptionInput) groupDescriptionInput.value = '';
        Array.from(membersSelect.options || []).forEach(opt => { opt.selected = false; });
        return;
      }

      if (selectedProjectGroupId && !groups.find(g => g.groupId === selectedProjectGroupId)) {
        selectedProjectGroupId = null;
      }

      container.innerHTML = groups.map(group => {
        const active = group.groupId === selectedProjectGroupId;
        const assignedCount = (state?.tasks || []).filter(t => t.groupId === group.groupId).length;
        const linkedUserGroup = (state?.userGroups || []).find(ug =>
          ug.groupId === group.groupId || normalizeSearch(ug.name) === normalizeSearch(group.name)
        );
        const memberNames = (linkedUserGroup?.memberUserIds || []).map(id => byId.get(id) || fallbackDirectoryName(id));
        return `
          <div class="rounded-lg border ${active ? 'border-primary bg-blue-50' : 'border-slate-200 bg-white'} p-3">
            <div class="flex items-start justify-between gap-2">
              <div class="min-w-0">
                <p class="text-sm font-semibold text-slate-800 truncate">${escapeHtml(group.name)}</p>
                <p class="text-xs text-slate-500 truncate">${escapeHtml(group.description || 'Sans description')}</p>
                <p class="text-[11px] text-slate-500 mt-1">${assignedCount} tâche(s) • ${(linkedUserGroup?.memberUserIds || []).length} membre(s)</p>
                <p class="text-[11px] text-slate-500 truncate">${escapeHtml(memberNames.join(', ') || 'Aucun membre')}</p>
              </div>
              <div class="flex items-center gap-2 text-xs">
                <button onclick="selectProjectGroup('${group.groupId}')" class="task-action-btn task-action-btn-subtle" data-action-kind="edit">Modifier</button>
                ${canManage ? `<button onclick="deleteProjectGroup('${group.groupId}')" class="task-action-btn task-action-btn-danger" data-action-kind="danger">Supprimer</button>` : ''}
              </div>
            </div>
          </div>
        `;
      }).join('');

      const selectedGroup = selectedProjectGroupId
        ? (groups.find(g => g.groupId === selectedProjectGroupId) || null)
        : null;
      const linkedSelectedUserGroup = selectedGroup
        ? (state?.userGroups || []).find(ug =>
            ug.groupId === selectedGroup.groupId || normalizeSearch(ug.name) === normalizeSearch(selectedGroup.name)
          )
        : null;
      const selectedIds = new Set(linkedSelectedUserGroup?.memberUserIds || []);
      Array.from(membersSelect.options || []).forEach(opt => {
        opt.selected = selectedIds.has(opt.value);
      });
      const groupNameInput = document.getElementById('group-name-input');
      const groupDescriptionInput = document.getElementById('group-description-input');
      if (selectedGroup) {
        if (groupNameInput) groupNameInput.value = selectedGroup.name || '';
        if (groupDescriptionInput) groupDescriptionInput.value = selectedGroup.description || '';
      }
      createBtn.textContent = selectedGroup ? 'Enregistrer modifications' : 'Créer groupe';
    }

