    async function createUserGroup() {
      if (!currentProjectId || !currentProjectState) return;
      if (!canManageProjectCollaboration(currentProjectState)) {
        showToast('Action non autorisee');
        return;
      }
      const nameInput = document.getElementById('user-group-name-input');
      const membersSelect = document.getElementById('user-group-members-input');
      const name = (nameInput?.value || '').trim();
      if (!name) {
        showToast('Nom de groupe utilisateurs requis');
        return;
      }
      const exists = (currentProjectState.userGroups || []).some(g => normalizeSearch(g.name) === normalizeSearch(name));
      if (exists) {
        showToast('Ce groupe utilisateurs existe deja');
        return;
      }
      const selectedIds = Array.from(membersSelect?.selectedOptions || []).map(o => o.value).filter(Boolean);
      const event = createEvent(
        EventTypes.CREATE_USER_GROUP,
        currentProjectId,
        currentUser.userId,
        { groupId: uuidv4(), name, memberUserIds: selectedIds }
      );
      await publishEvent(event);
      if (sharedFolderHandle) void syncProjectEventsToSharedSpace(currentProjectId, [event]);
      if (nameInput) nameInput.value = '';
      showToast('Groupe utilisateurs cree');
      await showProjectDetail(currentProjectId);
    }

    async function updateUserGroupSelection() {
      if (!currentProjectId || !currentProjectState || !selectedUserGroupId) return;
      if (!canManageProjectCollaboration(currentProjectState)) {
        showToast('Action non autorisee');
        return;
      }
      const exists = (currentProjectState.userGroups || []).some(g => g.groupId === selectedUserGroupId);
      if (!exists) {
        showToast('Selectionnez un groupe utilisateurs');
        return;
      }
      const membersSelect = document.getElementById('user-group-members-input');
      const selectedIds = Array.from(membersSelect?.selectedOptions || []).map(o => o.value).filter(Boolean);
      const event = createEvent(
        EventTypes.UPDATE_USER_GROUP,
        currentProjectId,
        currentUser.userId,
        { groupId: selectedUserGroupId, changes: { memberUserIds: [...new Set(selectedIds)] } }
      );
      await publishEvent(event);
      if (sharedFolderHandle) void syncProjectEventsToSharedSpace(currentProjectId, [event]);
      showToast('Groupe utilisateurs mis a jour');
      await showProjectDetail(currentProjectId);
    }

    async function deleteUserGroup(groupId) {
      if (!currentProjectId || !currentProjectState || !groupId) return;
      if (!canManageProjectCollaboration(currentProjectState)) {
        showToast('Action non autorisee');
        return;
      }
      const group = (currentProjectState.userGroups || []).find(g => g.groupId === groupId);
      if (!group) return;
      if (!confirm(`Supprimer le groupe utilisateurs "${group.name}" ?`)) return;
      const event = createEvent(
        EventTypes.DELETE_USER_GROUP,
        currentProjectId,
        currentUser.userId,
        { groupId }
      );
      await publishEvent(event);
      if (sharedFolderHandle) void syncProjectEventsToSharedSpace(currentProjectId, [event]);
      if (selectedUserGroupId === groupId) selectedUserGroupId = null;
      showToast('Groupe utilisateurs supprime');
      await showProjectDetail(currentProjectId);
    }

    function selectUserGroup(groupId) {
      selectedUserGroupId = groupId || null;
      renderProjectUserGroups(currentProjectState);
    }

    window.selectUserGroup = selectUserGroup;
    window.deleteUserGroup = deleteUserGroup;

    function parseSubtasks(textValue) {
      if (window.TaskMDATasks?.parseSubtasks) {
        return window.TaskMDATasks.parseSubtasks(textValue, uuidv4);
      }
      if (!textValue) return [];
      return textValue
        .split('\n')
        .map(line => line.trim())
        .filter(Boolean)
        .map(label => ({ id: uuidv4(), label, done: false }));
    }

    function normalizeTaskStatusValue(rawStatus) {
      const value = String(rawStatus || '').trim().toLowerCase();
      if (!value) return 'todo';
      const aliasMap = {
        'todo': 'todo',
        'a-faire': 'todo',
        'à-faire': 'todo',
        'afaire': 'todo',
        'a faire': 'todo',
        'à faire': 'todo',
        'en-cours': 'en-cours',
        'encours': 'en-cours',
        'in-progress': 'en-cours',
        'in progress': 'en-cours',
        'en-attente': 'suspendu',
        'en attente': 'suspendu',
        'suspendu': 'suspendu',
        'paused': 'suspendu',
        'termine': 'termine',
        'terminé': 'termine',
        'done': 'termine',
        'completed': 'termine',
        'realise': 'termine',
        'réalisé': 'termine'
      };
      return aliasMap[value] || 'todo';
    }

    function normalizeTaskStatusForCreate(rawStatus) {
      return normalizeTaskStatusValue(rawStatus);
    }

    function openProjectTaskCreateModalWithStatus(status = 'todo') {
      trackUxMetric('openNewTaskProject');
      standaloneTaskMode = false;
      pendingTaskStatusPrefill = normalizeTaskStatusForCreate(status);
      openTaskModal();
    }

    function openGlobalTaskCreateModalWithStatus(status = 'todo') {
      trackUxMetric('openNewTaskGlobal');
      standaloneTaskMode = true;
      pendingTaskStatusPrefill = normalizeTaskStatusForCreate(status);
      openTaskModal();
    }

    function openTaskModal(task = null) {
      const modal = document.getElementById('modal-new-task');
      modal.classList.remove('hidden');
      updateEditLockBadges();
      const titleEl = modal.querySelector('h3');
      const standaloneModeWrap = document.getElementById('task-standalone-mode-wrap');
      const standaloneModeInput = document.getElementById('task-standalone-mode');
      const metadataWrap = document.getElementById('task-project-metadata-wrap');
      const groupAssignWrap = document.getElementById('task-group-assignment-wrap');
      const featureAssignWrap = document.getElementById('task-feature-assignment-wrap');
      const groupPendingBox = document.getElementById('task-group-pending-members');
      const taskThemeInput = document.getElementById('task-theme');
      const taskGroupInput = document.getElementById('task-group');
      const taskFeatureInput = document.getElementById('task-feature');
      if (standaloneModeWrap) {
        standaloneModeWrap.classList.toggle('hidden', !standaloneTaskMode);
      }
      if (metadataWrap) {
        metadataWrap.classList.remove('hidden');
      }
      if (groupAssignWrap) {
        groupAssignWrap.classList.toggle('hidden', standaloneTaskMode);
      }
      if (featureAssignWrap) {
        featureAssignWrap.classList.toggle('hidden', standaloneTaskMode);
      }
      if (groupPendingBox) {
        groupPendingBox.classList.add('hidden');
        groupPendingBox.innerHTML = '';
      }
      taskPendingGroupMemberUserIds = [];
      refreshTaskMetadataOptions(
        standaloneTaskMode ? null : currentProjectState,
        { skipGroups: standaloneTaskMode }
      );
      const currentAssignees = getTaskAssigneeEntries(task, standaloneTaskMode ? null : currentProjectState);
      const selectedAssigneeValues = currentAssignees
        .map((entry) => buildTaskAssigneeSelectValue(entry))
        .filter(Boolean);
      const defaultCreatorAssigneeValue = !task ? String(currentUser?.userId || '').trim() : '';
      const effectiveSelectedAssigneeValues = (!task && !selectedAssigneeValues.length && defaultCreatorAssigneeValue)
        ? [defaultCreatorAssigneeValue]
        : selectedAssigneeValues;
      refreshTaskAssigneeOptionsMulti(
        standaloneTaskMode ? null : currentProjectState,
        effectiveSelectedAssigneeValues
      );
      refreshTaskQuickAssigneeSuggestions(standaloneTaskMode ? null : currentProjectState);
      if (titleEl) {
        titleEl.textContent = standaloneTaskMode ? 'Nouvelle tâche hors projet' : 'Nouvelle tâche';
      }

      if (task) {
        pendingTaskStatusPrefill = null;
        editingTaskId = task.taskId;
        editingStandaloneTaskId = standaloneTaskMode ? (task.id || editingStandaloneTaskId || null) : null;
        document.getElementById('task-title').value = task.title || '';
        setProjectDescriptionEditorContent(
          'task-description-editor',
          'task-description',
          task.descriptionHtml || task.description || ''
        );
        const manualAssignees = currentAssignees
          .filter(a => !a.userId && !a.agentId && a.name)
          .map(a => (a.email && normalizeSearch(a.email) !== normalizeSearch(a.name || '')) ? `${a.name} <${a.email}>` : a.name);
        document.getElementById('task-assignee-manual').value = manualAssignees.join('\n');
        document.getElementById('task-request-date').value = task.requestDate || (task.createdAt ? toYmd(new Date(task.createdAt)) : '');
        populateTaskDeadlineForm(task);
        document.getElementById('task-status').value = task.status || 'todo';
        document.getElementById('task-urgency').value = task.urgency || 'medium';
        document.getElementById('task-subtasks').value = (task.subtasks || []).map(st => st.label).join('\n');
        document.getElementById('task-files').value = '';
        const taskEditorImageInput = document.getElementById('task-description-image-input');
        if (taskEditorImageInput) taskEditorImageInput.value = '';
        document.getElementById('task-share-docs').checked = true;
        const saveTaskBtn = document.getElementById('btn-save-task');
        if (saveTaskBtn) {
          saveTaskBtn.setAttribute('data-action-kind', 'save');
          saveTaskBtn.setAttribute('data-action-label', 'Mettre à jour');
          saveTaskBtn.setAttribute('aria-label', 'Mettre à jour');
          saveTaskBtn.setAttribute('data-ui-tooltip', 'Mettre à jour');
          const saveTaskIcon = saveTaskBtn.querySelector('.taskmda-action-icon, .material-symbols-outlined');
          if (saveTaskIcon) saveTaskIcon.textContent = 'save';
          const saveTaskLabel = saveTaskBtn.querySelector('.taskmda-action-label');
          if (saveTaskLabel) saveTaskLabel.textContent = 'Mettre à jour';
        }
        if (standaloneModeInput) standaloneModeInput.value = normalizeSharingMode(task.sharingMode, 'private');
        if (taskThemeInput) taskThemeInput.value = task.theme || '';
        syncThemePickerSelectionFromInput('task-theme-known', 'task-theme');
        if (taskGroupInput) {
          if (task.groupId) {
            taskGroupInput.value = task.groupId;
          } else if (task.groupName) {
            const wanted = normalizeCatalogKey(task.groupName);
            const option = Array.from(taskGroupInput.options || [])
              .find(opt => String(opt.value || '').startsWith('global:') && normalizeCatalogKey(opt.dataset.groupName || '') === wanted);
            if (option) {
              taskGroupInput.value = option.value;
            } else {
              taskGroupInput.value = '';
            }
          } else {
            taskGroupInput.value = '';
          }
        }
        if (taskFeatureInput) {
          taskFeatureInput.value = String(task.featureId || '').trim();
        }
        // Charger la configuration de récurrence si elle existe
        if (window.TaskMDARecurrenceUI?.populateRecurrenceForm) {
          window.TaskMDARecurrenceUI.populateRecurrenceForm(task.recurring);
        }
        if (!standaloneTaskMode) {
          refreshTaskGroupSelectionPreview(
            currentProjectState,
            effectiveSelectedAssigneeValues
          );
        }
      } else {
        editingTaskId = null;
        editingStandaloneTaskId = null;
        const defaultStatus = normalizeTaskStatusForCreate(pendingTaskStatusPrefill || 'todo');
        pendingTaskStatusPrefill = null;
        document.getElementById('task-title').value = '';
        setProjectDescriptionEditorContent('task-description-editor', 'task-description', '');
        document.getElementById('task-assignee-manual').value = '';
        document.getElementById('task-request-date').value = toYmd(new Date());
        populateTaskDeadlineForm(null);
        document.getElementById('task-status').value = defaultStatus;
        document.getElementById('task-urgency').value = 'medium';
        document.getElementById('task-subtasks').value = '';
        document.getElementById('task-files').value = '';
        const taskEditorImageInput = document.getElementById('task-description-image-input');
        if (taskEditorImageInput) taskEditorImageInput.value = '';
        document.getElementById('task-share-docs').checked = true;
        const saveTaskBtn = document.getElementById('btn-save-task');
        if (saveTaskBtn) {
          saveTaskBtn.setAttribute('data-action-kind', 'create');
          saveTaskBtn.setAttribute('data-action-label', 'Créer');
          saveTaskBtn.setAttribute('aria-label', 'Créer');
          saveTaskBtn.setAttribute('data-ui-tooltip', 'Créer');
          const saveTaskIcon = saveTaskBtn.querySelector('.taskmda-action-icon, .material-symbols-outlined');
          if (saveTaskIcon) saveTaskIcon.textContent = 'add_circle';
          const saveTaskLabel = saveTaskBtn.querySelector('.taskmda-action-label');
          if (saveTaskLabel) saveTaskLabel.textContent = 'Créer';
        }
        if (standaloneModeInput) standaloneModeInput.value = 'private';
        if (taskThemeInput) taskThemeInput.value = (currentProjectState?.themes || [])[0] || '';
        syncThemePickerSelectionFromInput('task-theme-known', 'task-theme');
        if (taskGroupInput) taskGroupInput.value = '';
        if (taskFeatureInput) taskFeatureInput.value = '';
        // Réinitialiser la configuration de récurrence
        if (window.TaskMDARecurrenceUI?.resetRecurrenceForm) {
          window.TaskMDARecurrenceUI.resetRecurrenceForm();
        }
        if (!standaloneTaskMode) {
          refreshTaskGroupSelectionPreview(currentProjectState, effectiveSelectedAssigneeValues);
        }
      }
    }

    async function renderProjectSequentialNav(currentId) {
      const navWrap = document.getElementById('project-sequential-nav');
      const prevBtn = document.getElementById('btn-project-prev');
      const nextBtn = document.getElementById('btn-project-next');
      const prevLabel = document.getElementById('project-prev-label');
      const nextLabel = document.getElementById('project-next-label');
      if (!navWrap || !prevBtn || !nextBtn || !prevLabel || !nextLabel) return;

      const projects = await getAllProjects();
      const list = (projects || []).filter(p => p && p.projectId);
      const idx = list.findIndex(p => p.projectId === currentId);
      if (idx < 0 || list.length <= 1) {
        navWrap.classList.add('hidden');
        return;
      }

      const prev = idx > 0 ? list[idx - 1] : null;
      const next = idx < list.length - 1 ? list[idx + 1] : null;

      prevLabel.textContent = prev ? `Précédent: ${prev.name || 'Projet'}` : 'Aucun projet précédent';
      nextLabel.textContent = next ? `Suivant: ${next.name || 'Projet'}` : 'Aucun projet suivant';
      prevBtn.disabled = !prev;
      nextBtn.disabled = !next;
      prevBtn.onclick = prev ? (() => showProjectDetail(prev.projectId)) : null;
      nextBtn.onclick = next ? (() => showProjectDetail(next.projectId)) : null;
      navWrap.classList.remove('hidden');
    }

    function setProjectDocsUploadCollapsed(collapsed) {
      const body = document.getElementById('project-docs-upload-body');
      const toggleBtn = document.getElementById('btn-toggle-project-docs-upload');
      const toggleIcon = document.getElementById('project-docs-upload-toggle-icon');
      if (!body || !toggleBtn || !toggleIcon) return;
      const shouldCollapse = Boolean(collapsed);
      projectDocsUploadCollapsed = shouldCollapse;
      body.classList.toggle('hidden', shouldCollapse);
      toggleBtn.setAttribute('aria-expanded', shouldCollapse ? 'false' : 'true');
      toggleBtn.title = shouldCollapse ? 'Développer' : 'Replier';
      toggleIcon.textContent = shouldCollapse ? 'expand_more' : 'expand_less';
    }

    function renderProjectDescription(descriptionText = '') {
      const descEl = document.getElementById('project-description-display');
      const toggleBtn = document.getElementById('btn-toggle-project-description');
      if (!descEl || !toggleBtn) return;

      const html = sanitizeRichTextHtmlPreserve(descriptionText || '');
      descEl.innerHTML = html || '<p>&nbsp;</p>';

      const plain = (descEl.textContent || '').trim();
      const hasMedia = descEl.querySelector('img, iframe, video, embed, object') !== null;
      const isDescriptionEmpty = !plain && !hasMedia;
      const showInlineEmptyZone = isDescriptionEmpty && !!currentProjectInlineCanEdit;
      descEl.classList.toggle('project-description-empty', isDescriptionEmpty);
      descEl.classList.remove('is-collapsed');

      if (isDescriptionEmpty) {
        descEl.classList.toggle('hidden', !showInlineEmptyZone);
        toggleBtn.classList.add('hidden');
        return;
      }

      descEl.classList.toggle('hidden', !projectDescriptionExpanded);
      toggleBtn.classList.remove('hidden');
      toggleBtn.textContent = projectDescriptionExpanded ? 'Masquer la description' : 'Afficher la description';
    }

    function resetProjectInlineEditingState() {
      for (const timer of projectInlineDebounceTimers.values()) clearTimeout(timer);
      for (const timer of projectInlineFinalizeTimers.values()) clearTimeout(timer);
      projectInlineDebounceTimers.clear();
      projectInlineFinalizeTimers.clear();
      projectInlineLastSavedValues.clear();
    }

    function normalizeProjectInlineFieldValue(field, rawValue) {
      const value = rawValue === null || rawValue === undefined ? '' : String(rawValue);
      if (field === 'title') return value.trim();
      if (field === 'description') return sanitizeRichTextHtmlPreserve(value || '');
      return value.trim();
    }

    function decorateProjectInlineEditableElement(el, field) {
      if (!el) return;
      el.dataset.inlineProjectField = field;
      el.classList.toggle('task-detail-inline-editable', !!currentProjectInlineCanEdit);
      if (currentProjectInlineCanEdit) {
        el.setAttribute('title', 'Cliquer pour modifier');
        el.setAttribute('tabindex', '0');
        el.setAttribute('role', 'button');
      } else {
        el.removeAttribute('title');
        el.removeAttribute('tabindex');
        el.removeAttribute('role');
      }
    }

    function refreshProjectInlineDisplay(field, value) {
      if (field === 'title') {
        const titleEl = document.getElementById('project-title');
        if (titleEl) {
          titleEl.textContent = String(value || '').trim() || 'Projet';
          decorateProjectInlineEditableElement(titleEl, 'title');
        }
        return;
      }
      if (field === 'description') {
        renderProjectDescription(value || '');
        const descEl = document.getElementById('project-description-display');
        decorateProjectInlineEditableElement(descEl, 'description');
      }
    }

    async function persistProjectInlineField(projectId, field, rawValue, options = {}) {
      const normalizedValue = normalizeProjectInlineFieldValue(field, rawValue);
      const saveKey = `${projectId}::${field}`;
      const signature = `${field}::${normalizedValue}`;
      if (!options.force && projectInlineLastSavedValues.get(saveKey) === signature) return normalizedValue;
      const state = await getProjectState(projectId);
      if (!state?.project || !canEditProjectMeta(state)) return normalizedValue;

      let changes = null;
      if (field === 'title') {
        if (!normalizedValue) return normalizedValue;
        changes = { name: normalizedValue };
      } else if (field === 'description') {
        changes = { description: normalizedValue };
      } else {
        return normalizedValue;
      }

      const event = createEvent(
        EventTypes.UPDATE_PROJECT,
        projectId,
        currentUser.userId,
        { changes }
      );
      await publishEvent(event);
      if (sharedFolderHandle) { void syncProjectEventsToSharedSpace(projectId, [event]); }

      if (currentProjectState?.project && currentProjectState.project.projectId === projectId) {
        currentProjectState = {
          ...currentProjectState,
          project: {
            ...currentProjectState.project,
            ...changes
          }
        };
      }

      projectInlineLastSavedValues.set(saveKey, signature);
      return normalizedValue;
    }

    async function scheduleProjectInlineSave(field, rawValue, options = {}) {
      const projectId = String(currentProjectId || '').trim();
      if (!projectId) return;
      const normalizedValue = normalizeProjectInlineFieldValue(field, rawValue);
      if (projectInlineDebounceTimers.has(field)) {
        clearTimeout(projectInlineDebounceTimers.get(field));
      }
      projectInlineDebounceTimers.set(field, setTimeout(() => {
        setInlineSaveIndicator('project-inline', 'saving');
        runWithoutGlobalLoading(() => persistProjectInlineField(projectId, field, normalizedValue))
          .then(() => setInlineSaveIndicator('project-inline', 'saved'))
          .catch((error) => {
            setInlineSaveIndicator('project-inline', 'error');
            console.error('project inline save failed', error);
          });
      }, options.immediate ? 0 : 220));
      if (projectInlineFinalizeTimers.has(field)) {
        clearTimeout(projectInlineFinalizeTimers.get(field));
      }
      projectInlineFinalizeTimers.set(field, setTimeout(() => {
        setInlineSaveIndicator('project-inline', 'saving');
        runWithoutGlobalLoading(() => persistProjectInlineField(projectId, field, normalizedValue, { force: true }))
          .then(() => setInlineSaveIndicator('project-inline', 'saved'))
          .catch((error) => {
            setInlineSaveIndicator('project-inline', 'error');
            console.error('project inline finalize save failed', error);
          });
      }, 900));
    }

    function startProjectInlineEdit(triggerEl) {
      if (!currentProjectInlineCanEdit || !triggerEl || triggerEl.dataset.inlineEditing === '1') return;
      const field = String(triggerEl.dataset.inlineProjectField || '').trim();
      if (!field) return;
      const stateProject = currentProjectState?.project || {};
      const startValue = field === 'title'
        ? String(stateProject.name || '')
        : String(stateProject.description || '');

      triggerEl.dataset.inlineEditing = '1';
      triggerEl.classList.add('is-inline-editing');
      triggerEl.innerHTML = '';
      const wrap = document.createElement('span');
      wrap.className = 'task-detail-inline-editor-wrap task-detail-inline-block';
      triggerEl.appendChild(wrap);

      let done = false;
      const finish = async (nextValue, commit) => {
        if (done) return;
        done = true;
        triggerEl.dataset.inlineEditing = '0';
        triggerEl.classList.remove('is-inline-editing');

        if (field === 'title') {
          const safeValue = String(nextValue || '').trim() || String(startValue || 'Projet');
          if (commit) {
            if (currentProjectState?.project) currentProjectState.project.name = safeValue;
            await scheduleProjectInlineSave('title', safeValue, { immediate: true });
          } else if (currentProjectState?.project) {
            currentProjectState.project.name = String(startValue || '');
          }
          refreshProjectInlineDisplay('title', safeValue);
          return;
        }

        if (commit) {
          if (currentProjectState?.project) currentProjectState.project.description = String(nextValue || '');
          await scheduleProjectInlineSave('description', String(nextValue || ''), { immediate: true });
          refreshProjectInlineDisplay('description', String(nextValue || ''));
        } else {
          if (currentProjectState?.project) currentProjectState.project.description = String(startValue || '');
          refreshProjectInlineDisplay('description', String(startValue || ''));
        }
      };

      if (field === 'description' && window.Quill && typeof ensureProjectDescriptionQuillEditor === 'function') {
        const editorId = `project-detail-inline-desc-${uuidv4()}`;
        const host = document.createElement('div');
        host.id = editorId;
        host.className = 'task-detail-inline-quill-host';
        wrap.appendChild(host);
        const quill = ensureProjectDescriptionQuillEditor(editorId);
        if (!quill) {
          const fallback = document.createElement('textarea');
          fallback.rows = 8;
          fallback.className = 'task-detail-inline-input task-detail-inline-textarea';
          fallback.value = getProjectDescriptionPlainText(startValue || '');
          wrap.appendChild(fallback);
          fallback.addEventListener('input', () => {
            const html = plainTextToRichHtml(fallback.value || '');
            if (currentProjectState?.project) currentProjectState.project.description = html;
            scheduleProjectInlineSave('description', html).catch((error) => {
              console.error('project inline fallback autosave failed', error);
            });
          });
          fallback.addEventListener('blur', async () => {
            const html = plainTextToRichHtml(fallback.value || '');
            await finish(html, true);
          });
          fallback.addEventListener('keydown', async (event) => {
            if (event.key === 'Escape') {
              event.preventDefault();
              await finish(startValue, false);
            }
          });
          requestAnimationFrame(() => fallback.focus());
          return;
        }

        const safeHtml = sanitizeProjectDescriptionHtml(startValue || '');
        quill.clipboard.dangerouslyPasteHTML(safeHtml || '<p><br></p>');
        quill.on('text-change', () => {
          const html = String(quill.root?.innerHTML || '').trim();
          if (currentProjectState?.project) currentProjectState.project.description = html;
          scheduleProjectInlineSave('description', html).catch((error) => {
            console.error('project inline quill autosave failed', error);
          });
        });
        const root = quill.root;
        let interactingWithToolbar = false;
        const toolbar = wrap.querySelector('.ql-toolbar');
        if (toolbar) {
          const markToolbarInteraction = () => {
            interactingWithToolbar = true;
            setTimeout(() => {
              interactingWithToolbar = false;
            }, 0);
          };
          toolbar.addEventListener('pointerdown', markToolbarInteraction);
          toolbar.addEventListener('mousedown', markToolbarInteraction);
        }
        root.addEventListener('keydown', async (event) => {
          if (event.key === 'Escape') {
            event.preventDefault();
            await finish(startValue, false);
          }
        });
        wrap.addEventListener('focusout', async (event) => {
          if (interactingWithToolbar) return;
          if (wrap.contains(event.relatedTarget)) return;
          const active = document.activeElement;
          if (active instanceof Element && wrap.contains(active)) return;
          const html = String(quill.root?.innerHTML || '').trim();
          await finish(html, true);
        });
        requestAnimationFrame(() => root.focus());
        return;
      }

      const input = document.createElement('input');
      input.type = 'text';
      input.className = 'task-detail-inline-input';
      input.value = startValue || '';
      wrap.appendChild(input);
      input.addEventListener('input', () => {
        if (currentProjectState?.project) currentProjectState.project.name = String(input.value || '').trim();
        scheduleProjectInlineSave('title', input.value).catch((error) => {
          console.error('project inline title autosave failed', error);
        });
      });
      input.addEventListener('blur', async () => {
        await finish(input.value, true);
      });
      input.addEventListener('keydown', async (event) => {
        if (event.key === 'Escape') {
          event.preventDefault();
          await finish(startValue, false);
          return;
        }
        if (event.key === 'Enter') {
          event.preventDefault();
          input.blur();
        }
      });
      requestAnimationFrame(() => {
        input.focus();
        input.select();
      });
    }

    function initProjectInlineEditing(canEdit = false) {
      currentProjectInlineCanEdit = !!canEdit;
      renderProjectDescription(currentProjectState?.project?.description || '');
      const titleEl = document.getElementById('project-title');
      const descEl = document.getElementById('project-description-display');
      decorateProjectInlineEditableElement(titleEl, 'title');
      decorateProjectInlineEditableElement(descEl, 'description');

      const panel = document.getElementById('project-overview-panel');
      if (!panel || panel.dataset.inlineProjectEditorBound === '1') return;
      panel.dataset.inlineProjectEditorBound = '1';
      panel.addEventListener('click', (event) => {
        const rawTarget = event.target;
        const clickTarget = rawTarget instanceof Element ? rawTarget : null;
        if (clickTarget?.closest('a[data-inline-ignore], a[href], button')) return;
        const trigger = clickTarget?.closest('[data-inline-project-field]');
        if (!trigger) return;
        if (trigger.querySelector('.task-detail-inline-editor-wrap')) return;
        startProjectInlineEdit(trigger);
      });
      panel.addEventListener('keydown', (event) => {
        const target = event.target instanceof Element ? event.target : null;
        const trigger = target?.closest('[data-inline-project-field]');
        if (!trigger) return;
        if (event.key !== 'Enter' && event.key !== ' ') return;
        if (shouldIgnoreInlineActivationKeydown(target, trigger)) return;
        event.preventDefault();
        startProjectInlineEdit(trigger);
      });
    }

    async function showProjectDetail(projectId, options = {}) {
      const isSameProjectContext = workspaceMode === 'project' && currentProjectId === projectId;
      const shouldResetScroll = options.resetScroll === true
        || (!isSameProjectContext && options.resetScroll !== false);
      if (shouldResetScroll) {
        resetWorkspaceScrollTop();
      }
      workspaceMode = 'project';
      applyWorkspaceWidthMode();
      const previousProjectId = currentProjectId;
      currentProjectId = projectId;
      if (previousProjectId !== projectId) {
        projectDetailMode = 'work';
        projectDescriptionExpanded = false;
        projectSettingsTab = 'members';
        editingProjectNoteId = '';
        projectNotesFocusNoteId = '';
        closeProjectNoteEditor();
      }
      tasksPage = 1;
      archivedTasksPage = 1;
      const state = await getProjectState(projectId);
      closeMobileSidebar();

      if (!state || !state.project) {
        showToast('Acces refuse ou projet introuvable');
        showDashboard();
        return;
      }
      if (state.project.deletedAt) {
        showToast('❌ Ce projet a été supprimé');
        showDashboard();
        return;
      }
      rememberLastAccessedProjectId(projectId);
      await refreshKnownUsersCache();
      const notesSearchInput = document.getElementById('project-notes-search');
      const notesFilterSelect = document.getElementById('project-notes-filter');
      if (notesSearchInput) notesSearchInput.value = projectNotesSearchQuery;
      if (notesFilterSelect) notesFilterSelect.value = projectNotesFilterMode;

      // Hide dashboard, show detail
      document.getElementById('global-hub')?.classList.add('hidden');
      document.getElementById('projects-list').classList.add('hidden');
      document.getElementById('dashboard-head')?.classList.add('hidden');
      document.getElementById('dashboard-title')?.classList.add('hidden');
      setDashboardContextCaption('');
      document.getElementById('dashboard-stats')?.classList.add('hidden');
      document.getElementById('dashboard-quick-actions')?.classList.add('hidden');
      document.getElementById('project-detail').classList.remove('hidden');

      // Update project info
      document.getElementById('project-title').textContent = state.project.name;
      renderProjectDescription(state.project.description || '');
      const projectCreatedLabel = state.project.createdAt ? new Date(state.project.createdAt).toLocaleDateString('fr-FR') : 'Non définie';
      const projectDeadlineLabel = formatProjectDeadline(state.project);
      const projectDateMeta = projectDeadlineLabel !== 'Non définie'
        ? `${projectCreatedLabel} • Échéance: ${projectDeadlineLabel}`
        : projectCreatedLabel;
      document.getElementById('project-date').textContent = projectDateMeta;
      const projectMembersCountEl = document.getElementById('project-members-count');
      const projectMembersIconEl = document.getElementById('project-members-icon');
      if (projectMembersCountEl) {
        projectMembersCountEl.innerHTML = renderProjectMembersSummary(state, 3);
      }
      if (projectMembersIconEl) {
        const memberIds = new Set((state?.members || [])
          .map((member) => String(member?.userId || '').trim())
          .filter(Boolean));
        const hasCreatedByFallback = !memberIds.size && String(state?.project?.createdBy || '').trim();
        const displayedMembersCount = memberIds.size + (hasCreatedByFallback ? 1 : 0);
        projectMembersIconEl.classList.toggle('hidden', displayedMembersCount > 0);
      }
      const projectOverviewBadgesEl = document.getElementById('project-overview-badges');
      if (projectOverviewBadgesEl) {
        const isPrivate = String(state.project.sharingMode || '') === 'private';
        const sharingBadge = isPrivate
          ? '<span class="workspace-chip workspace-chip-private">PRIVE</span>'
          : '<span class="workspace-chip workspace-chip-shared">PARTAGE</span>';
        const priority = normalizeProjectPriority(state.project.priority);
        const priorityBadge = `<span class="workspace-chip ${getProjectPriorityChipClass(priority)}">${getProjectPriorityLabel(priority)}</span>`;
        const status = String(state.project.status || 'en-cours');
        const statusBadge = status === 'urgent'
          ? '<span class="workspace-chip workspace-chip-status-urgent">Urgent</span>'
          : status === 'termine'
            ? '<span class="workspace-chip workspace-chip-status-termine">Termine</span>'
            : status === 'planifie'
              ? '<span class="workspace-chip workspace-chip-status-planifie">Planifie</span>'
              : '<span class="workspace-chip workspace-chip-status-active">En cours</span>';
        projectOverviewBadgesEl.innerHTML = `${sharingBadge}${priorityBadge}${statusBadge}`;
      }
      const visibleTasks = (state.tasks || []).filter(t => !t.archivedAt);
      document.getElementById('project-kpi-tasks').textContent = String(visibleTasks.length);
      document.getElementById('project-kpi-done').textContent = String(visibleTasks.filter(t => t.status === 'termine').length);
      document.getElementById('project-kpi-messages').textContent = String((state.messages || []).length);
      await renderProjectRgpdImpactCard(state.project);
      bindProjectKpiActions();
      await renderProjectSequentialNav(projectId);
      await renderProjectMembers(state);
      await renderProjectUserGroups(state);
      renderProjectPermissionMatrix(state);
      renderProjectInvitations(state);
      await renderProjectGroups(state);
      renderProjectThemes(state);
      renderProjectHierarchy(state);
      await syncProjectTaxonomyToGlobal(state);
      refreshTaskMetadataOptions(state);
      syncProjectThemeFilterAssist(state);
      refreshProjectHierarchyTaskFilters(state);
      refreshProjectDocumentTaskOptions(state);
      await refreshTaskAssigneeOptionsMulti(state);
      const btnEditProject = document.getElementById('btn-edit-project');
      const btnMarkProjectDone = document.getElementById('btn-mark-project-done');
      const btnDeleteProject = document.getElementById('btn-delete-project');
      const canEditProjectOverviewInline = canEditProjectMeta(state);
      if (btnEditProject) {
        const allowed = canEditProjectOverviewInline;
        btnEditProject.disabled = !allowed;
        btnEditProject.classList.toggle('opacity-50', !allowed);
        btnEditProject.title = allowed ? '' : 'Réservé aux Propriétaires/Managers';
      }
      if (btnDeleteProject) {
        const allowed = canDeleteProjectMeta(state);
        btnDeleteProject.disabled = !allowed;
        btnDeleteProject.classList.toggle('opacity-50', !allowed);
        btnDeleteProject.title = allowed ? '' : 'Réservé au Propriétaire';
      }
      if (btnMarkProjectDone) {
        const isDone = String(state.project?.status || '') === 'termine';
        btnMarkProjectDone.classList.toggle('hidden', isDone);
        if (!isDone) {
          const allowed = canEditProjectOverviewInline;
          btnMarkProjectDone.disabled = !allowed;
          btnMarkProjectDone.classList.toggle('opacity-50', !allowed);
          btnMarkProjectDone.title = allowed ? '' : 'Réservé aux Propriétaires/Managers';
        }
      }
      const projectLockWarning = document.getElementById('project-lock-warning');
      if (projectLockWarning) {
        const lock = getProjectResourceLock(state, LOCK_SCOPE_PROJECT, projectId);
        if (lock && String(lock.ownerUserId || '') !== String(currentUser?.userId || '')) {
          projectLockWarning.textContent = `${formatLockOwner(lock)} modifie les informations du projet en ce moment. Les actions destructives sont temporairement bloquees.`;
          projectLockWarning.classList.remove('hidden');
        } else {
          projectLockWarning.textContent = '';
          projectLockWarning.classList.add('hidden');
        }
      }

      // Gérer l'affichage des boutons archiver/restaurer
      const btnArchive = document.getElementById('btn-archive-project');
      const btnRestore = document.getElementById('btn-restore-project');

      if (btnArchive && btnRestore) {
        const isArchived = !!state.project.archivedAt;
        btnArchive.classList.toggle('hidden', isArchived);
        btnRestore.classList.toggle('hidden', !isArchived);
      }

      currentProjectState = state;
      initProjectInlineEditing(canEditProjectOverviewInline);
      applyProjectOverviewCollapsedState();
      const canSendChat = canSendProjectMessage(state);
      const btnSendMessage = document.getElementById('btn-send-message');
      const messageInput = document.getElementById('message-input');
      const messageFiles = document.getElementById('message-files');
      const btnToggleEmojiPicker = document.getElementById('btn-toggle-emoji-picker');
      const btnToggleMessageFiles = document.getElementById('btn-toggle-message-files');
      const btnAddProjectDocs = document.getElementById('btn-add-project-documents');
      const projectDocFilesInput = document.getElementById('project-doc-files');
      const projectDocTaskLinks = document.getElementById('project-doc-task-links');
      const projectDocThemeInput = document.getElementById('project-doc-theme');
      const projectDocThemeKnown = document.getElementById('project-doc-theme-known');
      const projectDocModeInput = document.getElementById('project-doc-mode');
      if (btnSendMessage) {
        btnSendMessage.disabled = !canSendChat;
        btnSendMessage.classList.toggle('opacity-50', !canSendChat);
        btnSendMessage.title = canSendChat ? '' : 'Réservé aux membres du projet';
      }
      if (messageInput) {
        if ('disabled' in messageInput) messageInput.disabled = !canSendChat;
        if (messageInput.isContentEditable || messageInput.getAttribute('contenteditable') !== null) {
          messageInput.setAttribute('contenteditable', canSendChat ? 'true' : 'false');
          messageInput.setAttribute('aria-disabled', canSendChat ? 'false' : 'true');
        }
        setDiscussionInputPlaceholder(messageInput, canSendChat ? 'Tapez votre message...' : 'Lecture seule (droits insuffisants)');
      }
      if (messageFiles) {
        messageFiles.disabled = !canSendChat;
      }
      if (!canSendChat) {
        toggleProjectMessageFilesPanel(false);
      }
      if (btnToggleEmojiPicker) {
        btnToggleEmojiPicker.disabled = !canSendChat;
        btnToggleEmojiPicker.classList.toggle('opacity-50', !canSendChat);
      }
      if (btnToggleMessageFiles) {
        btnToggleMessageFiles.disabled = !canSendChat;
        btnToggleMessageFiles.classList.toggle('opacity-50', !canSendChat);
      }
      if (btnAddProjectDocs) {
        btnAddProjectDocs.disabled = !canSendChat;
        btnAddProjectDocs.classList.toggle('opacity-50', !canSendChat);
        btnAddProjectDocs.title = canSendChat ? '' : 'Réservé aux membres du projet';
      }
      if (projectDocFilesInput) projectDocFilesInput.disabled = !canSendChat;
      if (projectDocTaskLinks) projectDocTaskLinks.disabled = !canSendChat || (projectDocTaskLinks.options?.length || 0) === 0;
      if (projectDocThemeInput) projectDocThemeInput.disabled = !canSendChat;
      if (projectDocThemeKnown) projectDocThemeKnown.disabled = !canSendChat;
      if (projectDocModeInput) {
        projectDocModeInput.disabled = !canSendChat;
        const defaultProjectDocMode = normalizeSharingMode(state.project?.sharingMode, 'private');
        if (!String(projectDocModeInput.value || '').trim()) {
          projectDocModeInput.value = defaultProjectDocMode;
        }
      }
      refreshProjectDocumentThemePicker(state);
      renderTasks(visibleTasks);
      renderArchivedTasks(state.tasks || []);
      renderKanban(visibleTasks);
      renderGantt(visibleTasks);
      renderTimeline(visibleTasks);
      renderCalendar(visibleTasks);
      renderDocuments(state);
      renderProjectNotes(state);
      renderMessages(state.messages);
      const events = await getProjectEvents(projectId);
      currentProjectEvents = events;
      await renderActivity(events);
      applyProjectSubnavLayout();
      syncProjectWorkFocusButton();
      setProjectDetailMode(projectDetailMode);
      setProjectView(activeProjectView);
      syncProjectWorkCommandbarVisibility(activeProjectView);
      applyLiveSearchFilter();
    }

    function resolveProjectIdInput(projectId, fallbackId = currentProjectId) {
      if (isValidIdbKey(projectId)) return projectId;
      if (projectId && typeof projectId === 'object' && 'preventDefault' in projectId) {
        return fallbackId;
      }
      return fallbackId;
    }

    async function openEditProjectModal(projectId = currentProjectId, fromDashboard = false) {
      projectId = resolveProjectIdInput(projectId, currentProjectId);
      if (!projectId) return;
      const state = await getProjectState(projectId);
      if (!state?.project || state.project.deletedAt) return;
      if (!canEditProjectMeta(state)) {
        showToast('Action non autorisee');
        return;
      }
      const lockResult = await acquireProjectResourceLock(projectId, LOCK_SCOPE_PROJECT, projectId, { scope: 'project-meta' });
      if (!lockResult.ok) {
        showToast(buildLockBlockedMessage(lockResult.lock, "Projet en cours d'edition"));
        return;
      }
      activeProjectEditLock = {
        projectId,
        resourceType: LOCK_SCOPE_PROJECT,
        resourceId: projectId,
        lockId: lockResult.lockId
      };
      updateEditLockBadges();
      currentProjectId = projectId;
      currentProjectState = state;
      editProjectFromDashboard = fromDashboard === true;
      document.getElementById('edit-project-name').value = state.project.name || '';
      setProjectDescriptionEditorContent('edit-project-description-editor', 'edit-project-description', state.project.description || '');
      const editImageInput = document.getElementById('edit-project-description-image-input');
      if (editImageInput) editImageInput.value = '';
      const editProjectDocInput = document.getElementById('edit-project-doc-files');
      if (editProjectDocInput) editProjectDocInput.value = '';
      updateEditProjectDocFilesSummary();
      document.getElementById('edit-project-status').value = state.project.status || 'en-cours';
      document.getElementById('edit-project-priority').value = normalizeProjectPriority(state.project.priority);
      populateProjectDeadlineForm('edit-project', state.project);
      document.getElementById('edit-project-read-access').value = normalizeProjectReadAccess(
        state.project.readAccess,
        normalizeSharingMode(state.project.sharingMode, 'private') === 'private' ? 'private' : 'members'
      ) === 'public' ? 'public' : 'private';
      const editSharingMode = normalizeSharingMode(state.project.sharingMode, 'private');
      updateProjectEditSharingUi(editSharingMode);
      const editPassphraseInput = document.getElementById('edit-project-passphrase');
      if (editPassphraseInput) editPassphraseInput.value = '';
      await populateProjectGroupPresetOptions('edit-project-group-presets', (state.groups || []).map(g => g.name));
      document.getElementById('modal-edit-project').classList.remove('hidden');
      document.getElementById('edit-project-name').focus();
    }

    async function openEditProjectModalFromDashboard(projectId) {
      await openEditProjectModal(projectId, true);
    }

    async function quickAddTaskToProject(projectId) {
      projectId = resolveProjectIdInput(projectId, currentProjectId);
      if (!projectId) return;
      await showProjectDetail(projectId, { resetScroll: true });
      if (!currentProjectState?.project || !canCreateTaskInProject(currentProjectState)) {
        showToast('Creation de tache non autorisee sur ce projet');
        return;
      }
      standaloneTaskMode = false;
      openTaskModal();
    }

    async function saveProjectEdits() {
      if (!currentProjectId) return;
      try {
      const state = await getProjectState(currentProjectId);
      if (!state?.project || !canEditProjectMeta(state)) {
        showToast('Action non autorisee');
        return;
      }
      const name = (document.getElementById('edit-project-name').value || '').trim();
      if (!name) {
        showToast('Le nom du projet est requis');
        return;
      }
      const previousSharingMode = normalizeSharingMode(state.project?.sharingMode, 'private');
      const nextSharingMode = String(document.getElementById('edit-project-sharing-mode-select')?.value || '').trim() === 'shared'
        ? 'shared'
        : 'private';
      const modePassphrase = String(document.getElementById('edit-project-passphrase')?.value || '').trim();
      const projectDeadline = readProjectDeadlineFromForm('edit-project');
      const changes = {
        name,
        description: getProjectDescriptionHtmlForStorage('edit-project-description-editor', 'edit-project-description'),
        status: document.getElementById('edit-project-status').value || 'en-cours',
        priority: normalizeProjectPriority(document.getElementById('edit-project-priority')?.value || 'normale'),
        deadlineMode: projectDeadline.deadlineMode,
        deadlineDate: projectDeadline.deadlineDate,
        deadlineMonth: projectDeadline.deadlineMonth,
        deadlineYear: projectDeadline.deadlineYear,
        deadlineStart: projectDeadline.deadlineStart,
        deadlineEnd: projectDeadline.deadlineEnd,
        deadlineAt: projectDeadline.deadlineAt,
        readAccess: (document.getElementById('edit-project-read-access')?.value || 'private') === 'public' ? 'public' : 'private',
        sharingMode: nextSharingMode,
        joinPassphrase: nextSharingMode === 'shared'
          ? (modePassphrase || state.project?.joinPassphrase || null)
          : null
      };
      let sharedKeyHex = null;
      const switchedToShared = previousSharingMode !== 'shared' && nextSharingMode === 'shared';
      if (nextSharingMode === 'shared') {
        let sharedKeyData = await getDecrypted('sharedKeys', currentProjectId, 'projectId');
        if (!sharedKeyData?.sharedKey) {
          const sharedKey = modePassphrase
            ? await window.TaskMDACrypto.deriveSharedKeyFromPassphrase(modePassphrase, currentProjectId)
            : await window.TaskMDACrypto.generateSharedKey();
          sharedKeyHex = await window.TaskMDACrypto.exportSharedKey(sharedKey);
          sharedKeyData = {
            projectId: currentProjectId,
            sharedKey: sharedKeyHex,
            passphrase: modePassphrase || null,
            createdAt: Date.now()
          };
          await putEncrypted('sharedKeys', sharedKeyData, 'projectId');
        } else {
          sharedKeyHex = String(sharedKeyData.sharedKey || '').trim() || null;
        }
      }
      const selectedGlobalGroups = readSelectedGlobalGroups('edit-project-group-presets');
      const editProjectDocuments = await readEditProjectDocumentFiles({
        projectId: currentProjectId,
        scope: 'project',
        rubric: 'project-edit-upload',
        theme: changes.name || state?.project?.name || 'General'
      });
      const existingGroupKeys = new Set((state.groups || []).map(g => normalizeCatalogKey(g.name)));

      const event = createEvent(
        EventTypes.UPDATE_PROJECT,
        currentProjectId,
        currentUser.userId,
        { changes }
      );
      const sharedSyncEvents = [event];
      await publishEvent(event);
      const refreshedState = await getProjectState(currentProjectId, { ignoreAccessCheck: true });
      await syncDescriptionImagesAsProjectDocs(currentProjectId, refreshedState, changes.description);
      let addedGroupsCount = 0;
      let addedDocsCount = 0;
      for (const group of selectedGlobalGroups) {
        const groupKey = normalizeCatalogKey(group.name);
        if (!groupKey || existingGroupKeys.has(groupKey)) continue;
        existingGroupKeys.add(groupKey);
        const addGroupEvent = createEvent(
          EventTypes.CREATE_GROUP,
          currentProjectId,
          currentUser.userId,
          { groupId: uuidv4(), name: group.name, description: group.description || '' }
        );
        await publishEvent(addGroupEvent);
        sharedSyncEvents.push(addGroupEvent);
        addedGroupsCount += 1;
      }
      for (const file of editProjectDocuments) {
        const addDocEvent = createEvent(
          EventTypes.CREATE_DOCUMENT,
          currentProjectId,
          currentUser.userId,
          {
            ...file,
            linkedTaskIds: [],
            notes: 'Document ajoute lors de la modification du projet',
            origin: 'project-edit-upload'
          }
        );
        await publishEvent(addDocEvent);
        sharedSyncEvents.push(addDocEvent);
        addedDocsCount += 1;
      }
      if (sharedFolderHandle && nextSharingMode === 'shared') {
        if (switchedToShared) {
          const allProjectEvents = await getProjectEvents(currentProjectId);
          void syncProjectBootstrapToSharedSpace(currentProjectId, sharedKeyHex, allProjectEvents);
        } else {
          void syncProjectEventsToSharedSpace(currentProjectId, sharedSyncEvents, { ensureRegistered: true });
        }
      }
      await releaseActiveProjectEditLock();
      document.getElementById('modal-edit-project').classList.add('hidden');
      const editProjectDocInput = document.getElementById('edit-project-doc-files');
      if (editProjectDocInput) editProjectDocInput.value = '';
      const editPassphraseInput = document.getElementById('edit-project-passphrase');
      if (editPassphraseInput) editPassphraseInput.value = '';
      updateEditProjectDocFilesSummary();
      showToast('Projet mis à jour');
      if (addedGroupsCount > 0) {
        addNotification('Groupe', `${addedGroupsCount} groupe(s) global(aux) associe(s) au projet`, currentProjectId);
      }
      if (addedDocsCount > 0) {
        addNotification('Document', `${addedDocsCount} document(s) ajoute(s) au projet`, currentProjectId);
      }
      addNotification('Projet', 'Informations projet mises à jour', currentProjectId);
      if (editProjectFromDashboard) {
        editProjectFromDashboard = false;
        await refreshStats();
        await renderProjects();
        applyLiveSearchFilter();
        return;
      }
      editProjectFromDashboard = false;
      await showProjectDetail(currentProjectId);
      await refreshStats();
      await renderProjects();
      } catch (error) {
        console.error('Error saving project edits:', error);
        showToast('Erreur lors de la mise a jour du projet');
      }
    }

    async function deleteCurrentProject(projectId = currentProjectId, fromDashboard = false) {
      projectId = resolveProjectIdInput(projectId, currentProjectId);
      if (!projectId) return;
      const state = await getProjectState(projectId);
      if (!state?.project || !canDeleteProjectMeta(state)) {
        showToast('Action non autorisee');
        return;
      }
      if (!ensureProjectResourceUnlockedForAction(state, LOCK_SCOPE_PROJECT, projectId, 'Suppression du projet').ok) {
        return;
      }
      currentProjectId = projectId;
      currentProjectState = state;
      const pname = state?.project?.name || 'ce projet';
      if (!confirm(`Supprimer définitivement ${pname} ?`)) return;

      const event = createEvent(
        EventTypes.DELETE_PROJECT,
        currentProjectId,
        currentUser.userId,
        { reason: 'manual_delete' }
      );
      await publishEvent(event);
      if (sharedFolderHandle && state.project?.sharingMode === 'shared') {
        void syncProjectEventsToSharedSpace(currentProjectId, [event], { ensureRegistered: true });
      }
      addNotification('Projet', 'Projet supprimé', projectId);
      showToast('Projet supprimé');
      if (fromDashboard || workspaceMode === 'dashboard') {
        currentProjectId = null;
        currentProjectState = null;
        await refreshStats();
        await renderProjects();
        applyLiveSearchFilter();
        return;
      }
      showDashboard();
      await refreshStats();
      await renderProjects();
    }

    async function deleteProjectFromDashboard(projectId) {
      await deleteCurrentProject(projectId, true);
    }

    async function markProjectDoneFromDashboard(projectId) {
      const targetProjectId = resolveProjectIdInput(projectId, null);
      if (!targetProjectId) return;
      const state = await getProjectState(targetProjectId);
      if (!state?.project || !canEditProjectMeta(state)) {
        showToast('Action non autorisee');
        return;
      }
      if (!ensureProjectResourceUnlockedForAction(state, LOCK_SCOPE_PROJECT, targetProjectId, 'Mise a jour projet').ok) {
        return;
      }
      if (String(state.project.status || 'en-cours') === 'termine') {
        showToast('Projet déjà réalisé');
        return;
      }

      const event = createEvent(
        EventTypes.UPDATE_PROJECT,
        targetProjectId,
        currentUser.userId,
        { changes: { status: 'termine' } }
      );
      await publishEvent(event);
      if (sharedFolderHandle && state.project?.sharingMode === 'shared') {
        void syncProjectEventsToSharedSpace(targetProjectId, [event], { ensureRegistered: true });
      }
      showToast('✅ Projet marqué comme réalisé');
      addNotification('Projet', 'Projet marqué comme réalisé', targetProjectId);

      if (currentProjectId === targetProjectId && workspaceMode === 'project') {
        await showProjectDetail(targetProjectId);
      }
      await refreshStats();
      await renderProjects();
      applyLiveSearchFilter();
    }

    async function sendProjectStatusEmail(doneOnly = false) {
      if (!currentProjectId) return;
      const state = await getProjectState(currentProjectId);
      if (!state?.project) return;
      const tasks = state.tasks || [];
      const done = tasks.filter(t => t.status === 'termine').length;
      const inProgress = tasks.filter(t => t.status === 'en-cours').length;
      const todo = tasks.filter(t => (t.status || 'todo') === 'todo').length;
      const recipients = await collectProjectRecipientEmails(state, { includeProjectAssignees: true });
      const subject = doneOnly
        ? `[NEXUS MDA] Projet achevé: ${state.project.name}`
        : `[NEXUS MDA] Point statut projet: ${state.project.name}`;
      const body = doneOnly
        ? [
            `Bonjour,`,
            '',
            `Le projet "${state.project.name}" est déclaré achevé.`,
            '',
            `Synthèse finale:`,
            `- Tâches totales: ${tasks.length}`,
            `- Terminées: ${done}`,
            '',
            `Date de clôture: ${new Date().toLocaleDateString('fr-FR')}`,
            `Responsable: ${currentUser?.name || 'N/A'}`
          ].join('\n')
        : [
            `Bonjour,`,
            '',
            `Point de situation pour le projet "${state.project.name}":`,
            '',
            `- Tâches à faire: ${todo}`,
            `- Tâches en cours: ${inProgress}`,
            `- Tâches terminées: ${done}`,
            '',
            `Statut projet: ${state.project.status || 'en-cours'}`,
            `Date du point: ${new Date().toLocaleDateString('fr-FR')}`,
            '',
            `Cordialement,`,
            `${currentUser?.name || 'Equipe projet'}`
          ].join('\n');
      openMailto({ to: recipients, subject, body });
    }

    // ====================================================================
    // FONCTIONS D'ARCHIVAGE DE PROJETS
    // ====================================================================

    /**
     * Archive un projet
     */
    async function archiveProject(projectId) {
      if (!projectId) return false;

      const confirmed = window.confirm('Archiver ce projet ?\n\nLe projet sera masqué de la liste principale mais restera accessible dans les archives.');
      if (!confirmed) return false;

      const state = await getDecrypted('localState', projectId, 'projectId');
      if (!state || !state.project) {
        showToast('❌ Projet introuvable');
        return false;
      }

      state.project.archivedAt = Date.now();
      state.project.archivedBy = currentUser?.userId || null;

      await putEncrypted('localState', state, 'projectId');

      showToast('✅ Projet archivé avec succès');

      // Si on est sur la page de détail du projet, retourner à la liste
      if (workspaceMode === 'project' && currentProjectId === projectId) {
        showDashboard();
      } else {
        // Recharger la liste des projets
        await renderProjects();
      }

      return true;
    }

    /**
     * Restaure un projet archivé
     */
    async function restoreProject(projectId) {
      if (!projectId) return false;

      const confirmed = window.confirm('Restaurer ce projet ?\n\nLe projet redeviendra visible dans la liste principale.');
      if (!confirmed) return false;

      const state = await getDecrypted('localState', projectId, 'projectId');
      if (!state || !state.project) {
        showToast('❌ Projet introuvable');
        return false;
      }

      delete state.project.archivedAt;
      delete state.project.archivedBy;

      await putEncrypted('localState', state, 'projectId');

      showToast('✅ Projet restauré avec succès');

      // Si on est sur la page de détail du projet, recharger
      if (workspaceMode === 'project' && currentProjectId === projectId) {
        await showProjectDetail(projectId);
      } else {
        // Recharger la liste des projets
        if (projectsViewMode === 'archives') {
          await renderProjectsArchives();
        } else {
          await renderProjects();
        }
      }

      return true;
    }

    /**
     * Affiche la section des projets archivés
     */
    async function renderProjectsArchives() {
      const section = document.getElementById('projects-archives-section');
      const container = document.getElementById('projects-archives-container');
      const emptyState = document.getElementById('projects-archives-empty');
      const countEl = document.getElementById('projects-archives-count');
      const projectsList = document.getElementById('projects-list');
      const projectsListHead = document.getElementById('projects-list-head');
      const projectsContainer = document.getElementById('projects-container');
      const carousel = document.getElementById('projects-carousel');
      const newsSection = document.getElementById('dashboard-news');
      const paginationContainer = document.getElementById('projects-pagination');
      const filterCount = document.getElementById('projects-filter-count');
      const filterRow = document.getElementById('projects-filter-row');

      if (!section || !container) return;

      // Conserver le conteneur racine visible: la section archives est imbriquée dedans.
      if (projectsList) projectsList.classList.remove('hidden');
      if (projectsListHead) projectsListHead.classList.add('hidden');
      if (projectsContainer) projectsContainer.classList.add('hidden');
      if (carousel) carousel.classList.add('hidden');
      if (newsSection) newsSection.classList.add('hidden');
      if (paginationContainer) paginationContainer.classList.add('hidden');
      if (filterCount) filterCount.classList.add('hidden');
      if (filterRow) filterRow.classList.add('hidden');

      // Afficher la section archives
      section.classList.remove('hidden');

      // Récupérer tous les projets archivés
      const allStates = await getAllDecrypted('localState', 'projectId') || [];
      const archivedProjects = allStates
        .filter(s => s && s.project && s.project.archivedAt && !s.project.deletedAt)
        .map(s => s.project);

      // Mettre à jour le compteur
      if (countEl) {
        const count = archivedProjects.length;
        countEl.textContent = `${count} projet${count !== 1 ? 's' : ''} archivé${count !== 1 ? 's' : ''}`;
      }

      if (archivedProjects.length === 0) {
        container.innerHTML = '';
        if (emptyState) emptyState.classList.remove('hidden');
        return;
      }

      if (emptyState) emptyState.classList.add('hidden');

      // Trier par date d'archivage (plus récents en premier)
      archivedProjects.sort((a, b) => (b.archivedAt || 0) - (a.archivedAt || 0));

      // Récupérer l'état de chaque projet
      const stateByProjectId = new Map();
      for (const project of archivedProjects) {
        const state = await getProjectState(project.projectId);
        if (state) {
          stateByProjectId.set(project.projectId, state);
        }
      }

      // Générer le HTML
      container.innerHTML = archivedProjects.map(project => {
        const state = stateByProjectId.get(project.projectId);
        const isPrivate = project.sharingMode === 'private';
        const icon = isPrivate ? 'lock' : 'groups';
        const badge = isPrivate
          ? '<span class="workspace-chip workspace-chip-private">PRIVE</span>'
          : '<span class="workspace-chip workspace-chip-shared">PARTAGE</span>';

        const visibleTasks = (state?.tasks || []).filter(t => !t.archivedAt);
        const completedTasks = visibleTasks.filter(t => t.status === 'termine');
        const progress = visibleTasks.length > 0
          ? Math.round((completedTasks.length / visibleTasks.length) * 100)
          : 0;
        const progressClass = progress === 100 ? 'bg-emerald-500' : 'bg-primary';
        const progressStyle = `width: ${progress}%`;

        const archivedDate = new Date(project.archivedAt).toLocaleDateString('fr-FR');

        // Participants
        const memberIds = new Set((state?.members || [])
          .map((member) => String(member?.userId || '').trim())
          .filter(Boolean));
        const hasCreatedByFallback = !memberIds.size && String(project?.createdBy || '').trim();
        const displayedMembersCount = memberIds.size + (hasCreatedByFallback ? 1 : 0);
        const participantsHtml = displayedMembersCount > 0
          ? `<span class="material-symbols-outlined text-[18px]">group</span>`
          : '';
        const creatorTooltip = displayedMembersCount > 0
          ? `${displayedMembersCount} membre${displayedMembersCount > 1 ? 's' : ''}`
          : 'Aucun membre';

        return `
          <div class="project-card workspace-card-shell rounded-xl border transition-all cursor-pointer" data-project-id="${escapeHtml(project.projectId)}" onclick="showProjectDetail('${escapeHtml(project.projectId)}')">
            <div class="flex items-start justify-between gap-2 mb-2">
              <div class="flex items-center gap-2">
                <span class="material-symbols-outlined text-slate-400">${icon}</span>
                ${badge}
                <span class="inline-flex items-center gap-1 text-[10px] px-2 py-1 rounded-full font-semibold bg-amber-100 text-amber-700">
                  <span class="material-symbols-outlined text-[12px]">archive</span>
                  <span>Archivé le ${escapeHtml(archivedDate)}</span>
                </span>
              </div>
              <button class="card-quick-btn card-quick-btn-success" onclick="event.stopPropagation(); restoreProject('${escapeHtml(project.projectId)}')" title="Restaurer le projet">
                <span class="material-symbols-outlined">unarchive</span>
              </button>
            </div>
            <h3 class="workspace-card-title text-lg font-bold text-gray-900 mb-2">${escapeHtml(project.name)}</h3>
            <div class="flex items-center justify-between gap-2">
              <div class="flex items-center gap-2 text-sm text-gray-500">
                <span class="material-symbols-outlined text-lg">calendar_today</span>
                <span>${new Date(project.createdAt).toLocaleDateString('fr-FR')}</span>
              </div>
              <div class="flex items-center gap-2">
                <span title="${escapeHtml(creatorTooltip)}" aria-label="${escapeHtml(creatorTooltip)}">${participantsHtml}</span>
                <span class="text-[11px] font-semibold text-slate-500">${isPrivate ? 'Visibilité privée' : 'Visibilité collaborative'}</span>
              </div>
            </div>
            <div class="mt-4 h-1.5 w-full bg-slate-100 rounded-full overflow-hidden">
              <div class="h-full rounded-full ${progressClass}" style="${progressStyle}"></div>
            </div>
            <div class="mt-2 text-[11px] font-semibold text-slate-500 uppercase tracking-wide">${progress}% complété</div>
          </div>
        `;
      }).join('');
    }

    /**
     * Initialise les event listeners pour l'archivage
     */
    function initProjectArchives() {
      // Boutons de vue
      const gridBtn = document.getElementById('projects-view-grid');
      const listBtn = document.getElementById('projects-view-list');
      const archivesBtn = document.getElementById('projects-view-archives');

      if (gridBtn) {
        gridBtn.addEventListener('click', () => setProjectsViewMode('grid'));
      }

      if (listBtn) {
        listBtn.addEventListener('click', () => setProjectsViewMode('list'));
      }

      if (archivesBtn) {
        archivesBtn.addEventListener('click', () => setProjectsViewMode('archives'));
      }

      // Boutons d'archivage/restauration dans la vue détail
      const btnArchive = document.getElementById('btn-archive-project');
      const btnRestore = document.getElementById('btn-restore-project');

      if (btnArchive) {
        btnArchive.addEventListener('click', async () => {
          if (currentProjectId) {
            await archiveProject(currentProjectId);
          }
        });
      }

      if (btnRestore) {
        btnRestore.addEventListener('click', async () => {
          if (currentProjectId) {
            await restoreProject(currentProjectId);
          }
        });
      }
    }

    const TASK_EMAIL_TEMPLATE_STORAGE_KEY = 'taskmda_task_email_template_pref';

    function normalizeTaskEmailTemplate(value) {
      const key = String(value || '').trim().toLowerCase();
      if (key === 'demande' || key === 'relance' || key === 'conclusion') return key;
      return 'auto';
    }

    function getSavedTaskEmailTemplatePreference() {
      return normalizeTaskEmailTemplate(localStorage.getItem(TASK_EMAIL_TEMPLATE_STORAGE_KEY) || 'auto');
    }

    function saveTaskEmailTemplatePreference(value) {
      const normalized = normalizeTaskEmailTemplate(value);
      if (normalized === 'auto') {
        localStorage.removeItem(TASK_EMAIL_TEMPLATE_STORAGE_KEY);
        return;
      }
      localStorage.setItem(TASK_EMAIL_TEMPLATE_STORAGE_KEY, normalized);
    }

    function resolveTaskEmailTemplate(task, requestedTemplate = 'auto') {
      const requested = normalizeTaskEmailTemplate(requestedTemplate);
      if (requested !== 'auto') return requested;

      const status = String(task?.status || 'todo').trim().toLowerCase();
      const closedStatuses = new Set(['termine', 'done', 'approved']);
      if (closedStatuses.has(status)) return 'conclusion';

      const dueInfo = getTaskDueStatus(task || {});
      const relanceStatuses = new Set(['en-cours', 'in_progress', 'suspendu', 'blocked', 'ready_for_review']);
      if (dueInfo.isOverdue || relanceStatuses.has(status)) return 'relance';

      return 'demande';
    }

    function buildTaskEmailPayload(task, template, options = {}) {
      const selectedTemplate = normalizeTaskEmailTemplate(template) === 'auto'
        ? resolveTaskEmailTemplate(task, 'auto')
        : normalizeTaskEmailTemplate(template);
      const sourceProjectName = String(options.sourceProjectName || 'Hors projet');
      const statusLabel = getTaskStatusMeta(task?.status || 'todo')?.label || 'A faire';
      const urgencyLabel = getTaskUrgencyMeta(task?.urgency || 'medium')?.label || 'Normale';
      const assigneeLabel = String(options.assigneeLabel || 'Aucun responsable');
      const groupLabel = String(options.groupLabel || 'Aucun groupe');
      const taskTitle = String(task?.title || 'Tache');
      const theme = String(task?.theme || 'Non renseignee');
      const dueDate = formatTaskDeadline(task || {});
      const dateNow = new Date().toLocaleDateString('fr-FR');
      const taskDescription = String(task?.description || 'Aucune description');

      if (selectedTemplate === 'conclusion') {
        return {
          subject: `[NEXUS MDA] Conclusion - Tache: ${taskTitle}`,
          body: [
            'Bonjour,',
            '',
            `La tache "${taskTitle}" est consideree comme conclue.`,
            '',
            'Synthese:',
            `- Projet: ${sourceProjectName}`,
            `- Statut final: ${statusLabel}`,
            `- Urgence: ${urgencyLabel}`,
            `- Thematique: ${theme}`,
            `- Groupe: ${groupLabel}`,
            `- Responsable: ${assigneeLabel}`,
            `- Date de conclusion: ${dateNow}`,
            '',
            `Description de reference: ${taskDescription}`,
            '',
            'Merci pour votre contribution.',
            `${currentUser?.name || 'Equipe projet'}`
          ].join('\n')
        };
      }

      if (selectedTemplate === 'relance') {
        return {
          subject: `[NEXUS MDA] Relance - Tache: ${taskTitle}`,
          body: [
            'Bonjour,',
            '',
            `Relance concernant la tache "${taskTitle}".`,
            '',
            'Rappel de contexte:',
            `- Projet: ${sourceProjectName}`,
            `- Statut actuel: ${statusLabel}`,
            `- Urgence: ${urgencyLabel}`,
            `- Date limite: ${dueDate}`,
            `- Responsable: ${assigneeLabel}`,
            '',
            'Merci de partager un retour sur:',
            '- avancement actuel,',
            '- points bloquants,',
            '- date cible de finalisation.',
            '',
            `Description de reference: ${taskDescription}`,
            '',
            'Merci d avance,',
            `${currentUser?.name || 'Equipe projet'}`
          ].join('\n')
        };
      }

      return {
        subject: `[NEXUS MDA] Demande d informations complementaires - Tache: ${taskTitle}`,
        body: [
          'Bonjour,',
          '',
          `Dans le cadre de la tache "${taskTitle}", merci de partager les informations complementaires necessaires.`,
          '',
          'Contexte:',
          `- Projet: ${sourceProjectName}`,
          `- Statut: ${statusLabel}`,
          `- Urgence: ${urgencyLabel}`,
          `- Thematique: ${theme}`,
          `- Groupe: ${groupLabel}`,
          `- Responsable: ${assigneeLabel}`,
          `- Date limite: ${dueDate}`,
          '',
          'Elements attendus:',
          '- [A preciser]',
          '',
          `Description de reference: ${taskDescription}`,
          '',
          'Merci par avance,',
          `${currentUser?.name || 'Equipe projet'}`
        ].join('\n')
      };
    }

    async function collectStandaloneTaskRecipientEmails(task) {
      if (!task) return [];
      const recipients = new Set();
      const users = await getAllDecrypted('users', 'userId');
      const directoryUsers = await getAllDecrypted('directoryUsers', 'userId');
      const emailByUserId = new Map();
      (directoryUsers || []).forEach((user) => {
        const id = String(user?.userId || '').trim();
        const email = String(user?.email || '').trim().toLowerCase();
        if (id && isValidEmailAddress(email)) emailByUserId.set(id, email);
      });
      (users || []).forEach((user) => {
        const id = String(user?.userId || '').trim();
        const email = String(user?.email || '').trim().toLowerCase();
        if (id && isValidEmailAddress(email)) emailByUserId.set(id, email);
      });
      getTaskAssigneeEntries(task, null).forEach((entry) => {
        const directEmail = String(entry?.email || '').trim().toLowerCase();
        if (isValidEmailAddress(directEmail)) recipients.add(directEmail);
        const mapped = emailByUserId.get(String(entry?.userId || '').trim());
        if (mapped) recipients.add(mapped);
        const parsed = parseAssigneeToken(entry?.name || '');
        if (isValidEmailAddress(parsed?.email || '')) {
          recipients.add(String(parsed.email).toLowerCase());
        }
      });
      return Array.from(recipients);
    }

    async function sendTaskEmail(taskId, template = 'auto') {
      if (!currentProjectId || !taskId) return;
      const state = await getProjectState(currentProjectId);
      if (!state?.project) return;
      const task = (state.tasks || []).find(t => t.taskId === taskId);
      if (!task) return;
      const recipients = await collectProjectRecipientEmails(state, { task });
      const payload = buildTaskEmailPayload(task, template, {
        sourceProjectName: state.project?.name || 'Projet',
        assigneeLabel: getTaskAssigneeName(task, state) || 'Aucun responsable',
        groupLabel: getTaskGroupName(task, state) || task.groupName || 'Aucun groupe'
      });
      openMailto({ to: recipients, subject: payload.subject, body: payload.body });
    }

    async function sendTaskEmailByRef(taskRef, template = 'auto') {
      const resolved = await resolveGlobalTaskFromRef(taskRef);
      if (!resolved?.task) {
        showToast('Tache introuvable');
        return;
      }
      const task = resolved.task;
      const state = resolved.sourceType === 'project' ? resolved.state : null;
      const recipients = state
        ? await collectProjectRecipientEmails(state, { task })
        : await collectStandaloneTaskRecipientEmails(task);
      const payload = buildTaskEmailPayload(task, template, {
        sourceProjectName: state?.project?.name || 'Hors projet',
        assigneeLabel: getTaskAssigneeName(task, state) || 'Aucun responsable',
        groupLabel: getTaskGroupName(task, state) || task.groupName || 'Aucun groupe'
      });
      openMailto({ to: recipients, subject: payload.subject, body: payload.body });
    }

    function setDashboardContextCaption(text = '') {
      const captionEl = document.getElementById('dashboard-context-caption');
      if (!captionEl) return;
      const nextText = String(text || '').trim();
      if (!nextText) {
        captionEl.textContent = '';
        captionEl.classList.add('hidden');
        return;
      }
      captionEl.textContent = nextText;
      captionEl.classList.remove('hidden');
    }

    function showDashboard() {
      resetWorkspaceScrollTop();
      closeMobileSidebar();
      clearProjectWorkFocusState();
      resetProjectInlineEditingState();
      workspaceMode = 'dashboard';
      applyWorkspaceWidthMode();
      projectsPage = 1;
      document.getElementById('project-detail').classList.add('hidden');
      document.getElementById('global-hub')?.classList.add('hidden');
      document.getElementById('projects-list').classList.remove('hidden');
      document.getElementById('dashboard-head')?.classList.remove('dashboard-head-projects');
      document.getElementById('dashboard-head')?.classList.remove('hidden');
      document.getElementById('dashboard-title')?.classList.add('hidden');
      if (document.getElementById('dashboard-title')) {
        document.getElementById('dashboard-title').textContent = 'Tableau de bord';
      }
      setDashboardContextCaption('');
      document.querySelector('.dashboard-bento')?.classList.remove('no-margin-for-global-tasks');
      document.getElementById('dashboard-stats')?.classList.remove('hidden');
      document.getElementById('dashboard-quick-actions')?.classList.remove('hidden');
      currentProjectId = null;
      currentProjectState = null;
      editingMessageId = null;
      editingMessageDraft = '';
      setActiveSidebarNav('dashboard');
      refreshStats();
      renderProjects();
      applyLiveSearchFilter();
    }

    async function showProjectsWorkspace() {
      resetWorkspaceScrollTop();
      closeMobileSidebar();
      clearProjectWorkFocusState();
      resetProjectInlineEditingState();
      workspaceMode = 'dashboard';
      applyWorkspaceWidthMode();
      projectsPage = 1;
      document.getElementById('project-detail').classList.add('hidden');
      document.getElementById('global-hub')?.classList.add('hidden');
      document.getElementById('projects-list').classList.remove('hidden');
      document.getElementById('dashboard-head')?.classList.add('dashboard-head-projects');
      document.getElementById('dashboard-head')?.classList.remove('hidden');
      document.getElementById('dashboard-title')?.classList.remove('hidden');
      if (document.getElementById('dashboard-title')) {
        document.getElementById('dashboard-title').textContent = 'Vue Projets';
      }
      setDashboardContextCaption('Tous les projets accessibles (privés assignés + publics).');
      document.querySelector('.dashboard-bento')?.classList.add('no-margin-for-global-tasks');
      document.getElementById('dashboard-stats')?.classList.add('hidden');
      document.getElementById('dashboard-quick-actions')?.classList.add('hidden');
      currentProjectId = null;
      currentProjectState = null;
      editingMessageId = null;
      editingMessageDraft = '';
      setActiveSidebarNav('projects');
      await renderProjects();
      applyLiveSearchFilter();
    }

    function triggerWorkspaceRevealAnimation(elementIds = []) {
      (Array.isArray(elementIds) ? elementIds : []).forEach((id) => {
        const el = document.getElementById(String(id || '').trim());
        if (!el || el.classList.contains('hidden')) return;
        el.classList.remove('workspace-reveal-enter');
        // Force reflow so animation can replay on repeated switches.
        void el.offsetWidth;
        el.classList.add('workspace-reveal-enter');
        setTimeout(() => {
          el.classList.remove('workspace-reveal-enter');
        }, 150);
      });
    }

    async function getAllProjectStates() {
      const states = await getAllDecrypted('localState', 'projectId');
      const validStates = (states || [])
        .filter(s => s && s.project && !s.project.deletedAt);
      const accessibleStates = validStates.filter(s => hasProjectAccess(s));
      return accessibleStates.length > 0 ? accessibleStates : validStates;
    }

    async function getGlobalTasksList() {
      const states = await getAllProjectStates();
      const fromProjects = [];
      states.forEach(state => {
        (state.tasks || []).forEach(task => {
          fromProjects.push({
            ...task,
            sourceType: 'project',
            sourceProjectId: state.project.projectId,
            sourceProjectName: state.project.name,
            theme: task.theme || state.project.name,
            sharingMode: state.project.sharingMode || 'shared'
          });
        });
      });

      const standalone = await getAllDecrypted('globalTasks', 'id');
      const fromStandalone = (standalone || []).map(item => ({
        ...item,
        sourceType: 'standalone',
        sourceProjectId: null,
        sourceProjectName: 'Hors projet',
        theme: item.theme || 'Général',
        sharingMode: item.sharingMode || 'private'
      }));

      return [...fromProjects, ...fromStandalone].sort((a, b) => (b.createdAt || 0) - (a.createdAt || 0));
    }

    async function getGlobalDocumentsList() {
      const states = await getAllProjectStates();
      const docs = [];
      states.forEach(state => {
        const isPublicProject = normalizeProjectReadAccess(
          state?.project?.readAccess,
          normalizeSharingMode(state?.project?.sharingMode, 'private') === 'private' ? 'private' : 'members'
        ) === 'public';
        if (!isPublicProject) return;

        (state.tasks || []).forEach(task => {
          (task.attachments || []).forEach((file, attachmentIndex) => {
            if (file.shareToDocs !== false) {
              docs.push({
                id: `${state.project.projectId}:${task.taskId}:${attachmentIndex}`,
                name: file.name,
                type: file.type,
                size: file.size,
                data: file.data,
                theme: task.theme || state.project.name || 'Projet',
                sourceProjectName: state.project.name,
                sourceProjectId: state.project.projectId,
                taskId: task.taskId,
                attachmentIndex,
                sourceType: 'project',
                sharingMode: state.project.sharingMode || 'shared',
                createdAt: task.updatedAt || task.createdAt || state.project.createdAt || 0
              });
            }
          });
        });

        (state.documents || []).forEach((doc) => {
          docs.push({
            id: `${state.project.projectId}:project-doc:${doc.docId}`,
            name: doc.name,
            type: doc.type,
            size: doc.size,
            data: doc.data,
            storageMode: doc.storageMode || '',
            storageProvider: doc.storageProvider || '',
            storagePath: doc.storagePath || '',
            storedAt: Number(doc.storedAt || 0) || null,
            theme: doc.theme || state.project.name || 'Projet',
            sourceProjectName: state.project.name,
            sourceProjectId: state.project.projectId,
            docId: doc.docId,
            linkedTaskIds: Array.isArray(doc.linkedTaskIds) ? [...doc.linkedTaskIds] : [],
            linkedNoteIds: Array.isArray(doc.linkedNoteIds) ? [...doc.linkedNoteIds] : [],
            sourceType: 'project-doc',
            sharingMode: normalizeSharingMode(doc.sharingMode, normalizeSharingMode(state.project.sharingMode, 'shared')),
            notes: doc.notes || '',
            createdAt: doc.uploadedAt || doc.createdAt || state.project.createdAt || 0,
            origin: doc.origin || ''
          });
        });
      });

      const standaloneDocs = await getAllDecrypted('globalDocs', 'id');
      (standaloneDocs || []).forEach(doc => {
        docs.push({
          ...doc,
          sourceProjectName: 'Hors projet',
          sharingMode: doc.sharingMode || 'private',
          sourceType: 'standalone'
        });
      });

      return docs.sort((a, b) => (b.createdAt || 0) - (a.createdAt || 0));
    }

    async function renderGlobalTasks() {
      const container = document.getElementById('global-tasks-container');
      const paginationContainer = document.getElementById('global-tasks-pagination');
      if (!container) return;
      updateTaskCardsLayoutLabel('global-task-layout-label', 0);
      if (paginationContainer) paginationContainer.innerHTML = '';
      updateGlobalTasksViewButtons();
      const all = await getGlobalTasksList();
      syncGlobalThemeFilterAssist(all);
      const allProjectStates = await getAllProjectStates();
      const stateByProjectId = new Map(allProjectStates.map(s => [s.project?.projectId, s]));

      const query = `${globalSearchQuery} ${document.getElementById('global-task-search')?.value || ''}`.trim();
      const status = document.getElementById('global-task-status')?.value || 'all';
      const assigneeKind = String(document.getElementById('global-task-assignee-kind')?.value || 'all').trim();
      const theme = document.getElementById('global-task-theme-known')?.value || '';
      const urgencies = getSelectedGlobalTaskUrgencySet();

      let filtered = all.filter(task => matchesQuery([
        task.title,
        task.description,
        task.sourceProjectName,
        task.theme,
        getTaskAssigneeName(task, stateByProjectId.get(task.sourceProjectId)),
        sharingModeLabel(task.sharingMode)
      ], query));
      if (status !== 'all') filtered = filtered.filter(task => (task.status || 'todo') === status);
      if (assigneeKind !== 'all') filtered = filtered.filter(task => matchesTaskAssigneeKindFilter(task, stateByProjectId.get(task.sourceProjectId), assigneeKind));
      if (theme.trim()) filtered = filtered.filter(task => matchesQuery([task.theme], theme));
      filtered = filtered.filter(task => urgencies.has(getTaskUrgencyMeta(task.urgency).key));
      const mode = ['cards', 'list', 'kanban', 'timeline', 'calendar', 'archives'].includes(globalTasksViewMode) ? globalTasksViewMode : 'cards';
      if (mode !== 'kanban') detachGlobalKanbanInfiniteScroll();
      if (mode === 'calendar') {
        toggleGlobalTasksInlineCalendar(true);
        await renderGlobalCalendar();
        updateGlobalTasksViewButtons();
        if (paginationContainer) paginationContainer.classList.add('hidden');
        return;
      }
      if (mode === 'archives') {
        toggleGlobalTasksInlineCalendar(false);
        if (paginationContainer) paginationContainer.classList.remove('hidden');
        renderGlobalArchivedTasks(all, stateByProjectId, container);
        return;
      }

      filtered = filtered.filter(task => !task.archivedAt);
      updateTaskCardsLayoutLabel('global-task-layout-label', filtered.length);
      toggleGlobalTasksInlineCalendar(false);
      if (paginationContainer) paginationContainer.classList.toggle('hidden', mode === 'kanban' || mode === 'timeline');

      if (filtered.length === 0) {
        detachGlobalKanbanInfiniteScroll();
        container.innerHTML = buildWorkspaceEmptyState({
          icon: 'assignment',
          title: 'Aucune tâche trouvée',
          text: 'Ajustez les filtres ou créez une nouvelle tâche transverse.',
          ctaLabel: 'Créer une tâche',
          ctaOnclick: "document.getElementById('btn-global-add-task')?.click()"
        });
        return;
      }

      if (mode !== 'cards') {
        const prepared = filtered.map(task => {
          const taskRef = buildGlobalTaskRef(task);
          let canEdit = task.sourceType === 'standalone';
          let canDelete = task.sourceType === 'standalone';
          let canArchive = task.sourceType === 'standalone';
          if (task.sourceType === 'project') {
            const projectState = stateByProjectId.get(task.sourceProjectId);
            canEdit = canEditTaskInProject(task, projectState);
            canDelete = canDeleteTaskInProject(task, projectState);
            canArchive = canEditTaskInProject(task, projectState);
          }
          const dueTs = getTaskEffectiveDueTimestamp(task);
          return {
            ...task,
            _taskRef: taskRef,
            _canEdit: canEdit,
            _canDelete: canDelete,
            _canArchive: canArchive,
            _canMarkDone: task.sourceType === 'standalone'
              ? true
              : canChangeTaskStatus(task, stateByProjectId.get(task.sourceProjectId)),
            _statusKey: task.status || 'todo',
            _assigneeName: getTaskAssigneeName(task, stateByProjectId.get(task.sourceProjectId)) || 'Aucun responsable',
            _assigneeInlineHtml: buildTaskAssigneeInlineHtml(task, stateByProjectId.get(task.sourceProjectId)),
            _dueTs: Number.isFinite(dueTs) ? dueTs : Number.POSITIVE_INFINITY
          };
        });
        const taskActions = (task) => `
          ${(task._statusKey !== 'termine' && task._canMarkDone) ? `<button onclick="event.stopPropagation(); markGlobalTaskDone('${task._taskRef}')" class="task-action-btn task-action-btn-subtle" data-action-kind="success">Réalisé</button>` : ''}
          ${task._canEdit ? `<button onclick="event.stopPropagation(); editGlobalTask('${task._taskRef}')" class="task-action-btn task-action-btn-subtle">Modifier</button>` : ''}
          ${task._canEdit ? `<button onclick="event.stopPropagation(); convertTaskToProject('${task._taskRef}')" class="task-action-btn task-action-btn-subtle">Convertir</button>` : ''}
          <button onclick="event.stopPropagation(); sendTaskEmailByRef('${task._taskRef}', 'auto')" class="task-action-btn task-action-btn-subtle"><span class="material-symbols-outlined">mail</span> Email</button>
          ${task._canArchive ? `<button onclick="event.stopPropagation(); archiveGlobalTask('${task._taskRef}')" class="task-action-btn task-action-btn-subtle task-action-btn-warn">Archiver</button>` : ''}
          ${task._canDelete ? `<button onclick="event.stopPropagation(); deleteGlobalTask('${task._taskRef}')" class="task-action-btn task-action-btn-subtle task-action-btn-danger">Supprimer</button>` : ''}
        `;
        const isTaskBulkSelectable = (task) => globalTasksBulkSelectionMode && task._canDelete;
        const isTaskBulkSelected = (task) => selectedGlobalTaskRefsForBulkDelete.has(task._taskRef);
        const getTaskOpenHandler = (task) => isTaskBulkSelectable(task)
          ? `toggleGlobalTaskBulkSelection('${task._taskRef}')`
          : `openGlobalTaskDetails('${task._taskRef}')`;
        const renderTaskBulkCheckbox = (task) => {
          if (!globalTasksBulkSelectionMode) return '';
          return `
            <label class="taskmda-bulk-checkbox-wrap" onclick="event.stopPropagation()">
              <input type="checkbox" class="taskmda-bulk-checkbox-input" data-task-ref="${escapeHtml(task._taskRef)}" ${isTaskBulkSelected(task) ? 'checked' : ''} ${task._canDelete ? '' : 'disabled'} onchange="toggleGlobalTaskBulkSelection('${task._taskRef}', this.checked)" aria-label="Sélectionner la tâche ${escapeHtml(task.title || '')}">
              <span class="taskmda-bulk-checkbox-label">Sélection</span>
            </label>
          `;
        };
        const taskCard = (task) => `
          <div class="global-task-card global-task-card-modern task-completion-fx-anchor ${getTaskUrgencyMeta(task.urgency).accentClass} rounded-xl border border-slate-200 bg-white p-4 cursor-grab active:cursor-grabbing ${isTaskBulkSelected(task) ? 'is-bulk-selected' : ''}" data-task-entity-id="${escapeHtml(String(task.taskId || task.id || ''))}" data-task-source-type="${escapeHtml(String(task.sourceType || 'project'))}" data-task-project-id="${escapeHtml(String(task.sourceProjectId || ''))}" draggable="true" ondragstart="startGlobalKanbanDrag(event, '${task._taskRef}')" onclick="${getTaskOpenHandler(task)}" role="button" tabindex="0">
            <div class="task-card-badge-row flex items-center justify-between gap-2 mb-1">
              <div class="task-card-badge-left flex items-center gap-2 min-w-0">
                <span class="${getTaskUrgencyMeta(task.urgency).chipClass}">${getTaskUrgencyMeta(task.urgency).label}</span>
              </div>
              <div class="task-card-badge-right flex items-center justify-end gap-1 shrink-0">
                ${renderTaskBulkCheckbox(task)}
                ${buildTaskRecurrenceBadgeHtml(task)}
                ${sharingModeBadge(task.sharingMode)}
                <span class="${getTaskStatusMeta(task._statusKey).chipClass}">${getTaskStatusMeta(task._statusKey).label}</span>
              </div>
            </div>
            <div>
              <h4 class="font-bold text-slate-800">${escapeHtml(task.title || 'Tache')}</h4>
              <p class="text-xs text-slate-500 mt-1">${escapeHtml(task.sourceProjectName || 'Hors projet')} - ${escapeHtml(task.theme || 'General')}</p>
              ${buildTaskHierarchyChipsHtml(task, stateByProjectId.get(task.sourceProjectId)) ? `<p class="mt-1">${buildTaskHierarchyChipsHtml(task, stateByProjectId.get(task.sourceProjectId))}</p>` : ''}
            </div>
            <p class="text-sm text-slate-600 mt-2">${escapeHtml(task.description || '')}</p>
            ${buildSubtaskProgressHtml(task, true)}
            <div class="mt-2 text-xs text-slate-500 flex flex-wrap gap-3">
              <span>Demande: ${formatDate(task.requestDate)}</span>
              <span>Date limite: ${formatTaskDeadline(task)}</span>
              <span class="inline-flex items-center gap-1.5">Responsable: ${task._assigneeInlineHtml}</span>
            </div>
            <div class="task-hover-actions mt-3 flex flex-wrap gap-2 text-xs">${taskActions(task)}</div>
          </div>
        `;
        if (mode === 'list') {
          const pagination = paginateItems(prepared, globalTasksPage, paginationConfig.globalTasksPerPage);
          globalTasksPage = pagination.currentPage;
          container.className = 'space-y-3';
          container.innerHTML = `
            <div class="rounded-xl border border-slate-200 bg-white overflow-x-auto">
              <table class="min-w-full text-sm">
                <thead>
                  <tr class="text-left text-slate-500 border-b border-slate-200">
                    ${globalTasksBulkSelectionMode ? '<th class="px-3 py-2 font-semibold">Sélection</th>' : ''}
                    <th class="px-3 py-2 font-semibold">Tache</th>
                    <th class="px-3 py-2 font-semibold">Projet</th>
                    <th class="px-3 py-2 font-semibold">Statut</th>
                    <th class="px-3 py-2 font-semibold">Date limite</th>
                    <th class="px-3 py-2 font-semibold">Responsable</th>
                    <th class="px-3 py-2 font-semibold">Actions</th>
                  </tr>
                </thead>
                <tbody>
                  ${pagination.pageItems.map(task => `
                    <tr class="border-b border-slate-100 align-top cursor-pointer hover:bg-slate-50 ${isTaskBulkSelected(task) ? 'is-bulk-selected' : ''}" onclick="${getTaskOpenHandler(task)}">
                      ${globalTasksBulkSelectionMode ? `<td class="px-3 py-2" onclick="event.stopPropagation()">${renderTaskBulkCheckbox(task)}</td>` : ''}
                      <td class="px-3 py-2">
                        <p class="font-semibold text-slate-800">${escapeHtml(task.title || 'Tache')}</p>
                        <div class="flex flex-wrap items-center gap-1 mt-1">${buildTaskRecurrenceBadgeHtml(task)}</div>
                        <p class="text-xs text-slate-500">${escapeHtml(task.theme || 'General')}</p>
                        ${buildSubtaskProgressHtml(task, true)}
                      </td>
                      <td class="px-3 py-2 text-slate-600">${escapeHtml(task.sourceProjectName || 'Hors projet')}</td>
                      <td class="px-3 py-2 text-slate-600"><span class="${getTaskStatusMeta(task._statusKey).chipClass}">${getTaskStatusMeta(task._statusKey).label}</span></td>
                      <td class="px-3 py-2 text-slate-600">${formatTaskDeadline(task)}</td>
                      <td class="px-3 py-2 text-slate-600"><span class="inline-flex items-center gap-1.5">${task._assigneeInlineHtml}</span></td>
                      <td class="px-3 py-2" onclick="event.stopPropagation()"><div class="flex flex-wrap gap-1 text-xs">${taskActions(task)}</div></td>
                    </tr>
                  `).join('')}
                </tbody>
              </table>
            </div>
          `;
          renderPagination('global-tasks-pagination', pagination, 'setGlobalTasksPage', 'taches');
          return;
        }
        if (mode === 'kanban') {
          container.className = 'global-kanban-board grid grid-cols-1 lg:grid-cols-4 gap-4';
          const cols = [
            { key: 'todo', label: 'A faire' },
            { key: 'en-cours', label: 'En cours' },
            { key: 'suspendu', label: 'Suspendu' },
            { key: 'termine', label: 'Termine' }
          ];
          const taskCardKanban = (task) => `
            <div class="global-task-card global-task-card-modern global-kanban-card kanban-card task-completion-fx-anchor ${getTaskUrgencyMeta(task.urgency).accentClass} rounded-xl border border-slate-200 bg-white p-3 cursor-grab active:cursor-grabbing ${isTaskBulkSelected(task) ? 'is-bulk-selected' : ''}" data-task-entity-id="${escapeHtml(String(task.taskId || task.id || ''))}" data-task-source-type="${escapeHtml(String(task.sourceType || 'project'))}" data-task-project-id="${escapeHtml(String(task.sourceProjectId || ''))}" draggable="true" ondragstart="startGlobalKanbanDrag(event, '${task._taskRef}')" onclick="${getTaskOpenHandler(task)}" role="button" tabindex="0">
              <div class="mb-2 flex items-center justify-between gap-2">
                <span class="${getTaskUrgencyMeta(task.urgency).chipClass}">${getTaskUrgencyMeta(task.urgency).label}</span>
                ${renderTaskBulkCheckbox(task)}
                <span class="${getTaskStatusMeta(task._statusKey).chipClass}">${getTaskStatusMeta(task._statusKey).label}</span>
              </div>
              ${buildTaskRecurrenceBadgeHtml(task)}
              <h4 class="font-semibold text-slate-900 text-[1.04rem] leading-tight mb-1">${escapeHtml(task.title || 'Tache')}</h4>
              <p class="text-xs text-slate-500 mb-2">${escapeHtml(task.sourceProjectName || 'Hors projet')} • ${escapeHtml(task.theme || 'General')}</p>
              ${buildTaskHierarchyChipsHtml(task, stateByProjectId.get(task.sourceProjectId)) ? `<p class="mb-2">${buildTaskHierarchyChipsHtml(task, stateByProjectId.get(task.sourceProjectId))}</p>` : ''}
              <p class="text-sm text-slate-700 global-kanban-desc mb-2">${escapeHtml(task.description || '')}</p>
              ${buildSubtaskProgressHtml(task, true)}
              <div class="mt-2 text-xs text-slate-600 flex items-center justify-between gap-2">
                <span class="truncate inline-flex items-center gap-1.5">${task._assigneeInlineHtml}</span>
                <span class="whitespace-nowrap">${formatTaskDeadline(task)}</span>
              </div>
              <div class="task-hover-actions mt-2 flex flex-wrap gap-1 text-xs">${taskActions(task)}</div>
            </div>
          `;
          const buildKanbanPager = (colKey, pagination) => {
            if (pagination.totalPages <= 1) {
              return `<p class="text-[11px] text-slate-500">${pagination.totalItems} carte(s)</p>`;
            }
            const prevDisabled = pagination.currentPage <= 1;
            const nextDisabled = pagination.currentPage >= pagination.totalPages;
            return `
              <div class="flex items-center justify-between gap-2 text-[11px] text-slate-500">
                <button
                  type="button"
                  class="px-2 py-1 rounded border border-slate-300 ${prevDisabled ? 'opacity-50 cursor-not-allowed' : 'hover:bg-slate-100'}"
                  ${prevDisabled ? 'disabled' : `onclick="event.stopPropagation(); setGlobalKanbanPage('${colKey}', ${pagination.currentPage - 1})"`}
                >Prec.</button>
                <span>${pagination.start + 1}-${pagination.end} / ${pagination.totalItems}</span>
                <button
                  type="button"
                  class="px-2 py-1 rounded border border-slate-300 ${nextDisabled ? 'opacity-50 cursor-not-allowed' : 'hover:bg-slate-100'}"
                  ${nextDisabled ? 'disabled' : `onclick="event.stopPropagation(); setGlobalKanbanPage('${colKey}', ${pagination.currentPage + 1})"`}
                >Suiv.</button>
              </div>
            `;
          };
          container.innerHTML = cols.map(col => {
            const items = prepared.filter(task => task._statusKey === col.key);
            const pagination = paginateItems(items, globalKanbanPageByStatus[col.key] || 1, GLOBAL_TASK_KANBAN_PAGE_SIZE);
            globalKanbanPageByStatus[col.key] = pagination.currentPage;
            const colCards = pagination.totalItems > 0
              ? pagination.pageItems.map(taskCardKanban).join('')
              : '<p class="text-xs text-slate-400 py-2">Aucune tâche</p>';
            return `
              <div class="global-kanban-col rounded-xl border border-slate-200 bg-slate-50 p-3" data-col="${col.key}" ondragover="allowKanbanDrop(event)" ondrop="dropGlobalKanbanTask(event, '${col.key}')">
                <div class="global-kanban-col-head flex items-center justify-between mb-2">
                  <div class="flex items-center gap-2">
                    <h4 class="text-sm font-bold text-slate-800">${col.label}</h4>
                    <span class="global-kanban-col-count text-xs">${items.length}</span>
                  </div>
                  <button
                    type="button"
                    class="kanban-col-add-btn global-kanban-col-add-btn taskmda-create-cta"
                    data-action-kind="create"
                    data-action-label="Ajouter une tâche hors projet"
                    data-ui-tooltip="Ajouter une tâche hors projet"
                    aria-label="Ajouter une tâche hors projet dans ${escapeHtml(col.label)}"
                    onclick="event.stopPropagation(); openGlobalTaskCreateModalWithStatus('${col.key}')"
                  >
                    <span class="material-symbols-outlined taskmda-action-icon" aria-hidden="true">add</span>
                    <span class="taskmda-action-label">Ajouter</span>
                  </button>
                </div>
                <div id="global-kanban-items-${col.key}" class="global-kanban-items space-y-2 pr-1" data-col-key="${col.key}">
                  ${colCards}
                </div>
                <div class="mt-2">${buildKanbanPager(col.key, pagination)}</div>
              </div>
            `;
          }).join('');
          detachGlobalKanbanInfiniteScroll();
          return;
        }
        container.className = 'space-y-4';
        const withDate = prepared.filter(task => Number.isFinite(task._dueTs)).sort((a, b) => a._dueTs - b._dueTs);
        const withoutDate = prepared.filter(task => !Number.isFinite(task._dueTs));
        const now = new Date();
        const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate()).getTime();
        const todayEnd = todayStart + (24 * 60 * 60 * 1000) - 1;
        const groups = [
          { key: 'overdue', label: 'En retard', items: withDate.filter(task => task._dueTs < todayStart) },
          { key: 'today', label: 'Aujourd hui', items: withDate.filter(task => task._dueTs >= todayStart && task._dueTs <= todayEnd) },
          { key: 'upcoming', label: 'A venir', items: withDate.filter(task => task._dueTs > todayEnd) },
          { key: 'nodue', label: 'Sans echeance', items: withoutDate }
        ];
        const displayMode = globalTimelineDisplayMode === 'list' ? 'list' : 'columns';
        const modeBtnClass = (target) => `px-3 py-1.5 rounded-lg text-xs font-semibold ${displayMode === target ? 'bg-primary text-white' : 'bg-slate-100 text-slate-700'}`;

        if (displayMode === 'columns') {
          container.innerHTML = `
            <div class="flex items-center justify-between gap-2">
              <p class="text-xs font-semibold uppercase tracking-wide text-slate-500">Timeline</p>
              <div class="inline-flex items-center gap-2">
                <button id="global-timeline-mode-columns" type="button" class="${modeBtnClass('columns')}">Vue 4 colonnes</button>
                <button id="global-timeline-mode-list" type="button" class="${modeBtnClass('list')}">Vue liste</button>
              </div>
            </div>
            <div class="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-3">
              ${groups.map((group) => {
                const initial = Math.min(group.items.length, GLOBAL_TIMELINE_INITIAL_BATCH);
                return `
                  <div class="rounded-xl border border-slate-200 bg-white p-3">
                    <div class="flex items-center justify-between mb-2">
                      <h4 class="font-bold text-slate-800 text-sm">${group.label}</h4>
                      <span class="text-xs text-slate-500">${group.items.length}</span>
                    </div>
                    <div id="global-timeline-col-items-${group.key}" class="space-y-2 pr-1" data-rendered="${initial}">
                      ${initial > 0 ? group.items.slice(0, initial).map(taskCard).join('') : '<p class="text-xs text-slate-400 py-2">Aucune tâche</p>'}
                    </div>
                    <div class="mt-2 flex items-center justify-between gap-2">
                      <p class="text-[11px] text-slate-500"><span id="global-timeline-col-count-${group.key}">${initial}</span> / ${group.items.length}</p>
                      <button id="global-timeline-col-more-${group.key}" type="button" class="px-2 py-1 rounded-lg border border-slate-300 bg-white text-slate-700 text-xs font-semibold ${initial >= group.items.length ? 'hidden' : ''}">Charger plus</button>
                    </div>
                  </div>
                `;
              }).join('')}
            </div>
          `;

          const bindLazyColumn = (group) => {
            const listEl = document.getElementById(`global-timeline-col-items-${group.key}`);
            const btnMore = document.getElementById(`global-timeline-col-more-${group.key}`);
            const countEl = document.getElementById(`global-timeline-col-count-${group.key}`);
            if (!listEl) return;
            const items = group.items || [];
            const update = (rendered) => {
              if (countEl) countEl.textContent = String(rendered);
              if (btnMore) btnMore.classList.toggle('hidden', rendered >= items.length);
            };
            const loadNext = () => {
              const rendered = Number.parseInt(listEl.dataset.rendered || '0', 10) || 0;
              if (rendered >= items.length) {
                update(items.length);
                return;
              }
              const next = Math.min(items.length, rendered + GLOBAL_TIMELINE_BATCH_SIZE);
              const chunk = items.slice(rendered, next);
              listEl.insertAdjacentHTML('beforeend', chunk.map(taskCard).join(''));
              listEl.dataset.rendered = String(next);
              update(next);
            };
            btnMore?.addEventListener('click', loadNext);
          };
          groups.forEach(bindLazyColumn);
        } else {
          container.innerHTML = `
            <div class="flex items-center justify-between gap-2">
              <p class="text-xs font-semibold uppercase tracking-wide text-slate-500">Timeline</p>
              <div class="inline-flex items-center gap-2">
                <button id="global-timeline-mode-columns" type="button" class="${modeBtnClass('columns')}">Vue 4 colonnes</button>
                <button id="global-timeline-mode-list" type="button" class="${modeBtnClass('list')}">Vue liste</button>
              </div>
            </div>
            <div class="space-y-3">
              ${groups.map((group) => {
                const expanded = Boolean(globalTimelineExpandedGroups[group.key]);
                const initial = expanded ? Math.min(group.items.length, GLOBAL_TIMELINE_INITIAL_BATCH) : 0;
                return `
                  <div class="rounded-xl border border-slate-200 bg-white p-3">
                    <button id="global-timeline-list-toggle-${group.key}" type="button" class="w-full flex items-center justify-between text-left">
                      <span class="font-bold text-slate-800">${group.label}</span>
                      <span class="inline-flex items-center gap-2 text-xs text-slate-500"><span>${group.items.length}</span><span id="global-timeline-toggle-symbol-${group.key}" class="text-base leading-none">${expanded ? '-' : '+'}</span></span>
                    </button>
                    <div id="global-timeline-list-body-${group.key}" class="${expanded ? 'mt-2' : 'hidden mt-2'}">
                      <div id="global-timeline-list-items-${group.key}" class="space-y-2 pr-1" data-rendered="${initial}">
                        ${expanded ? (initial > 0 ? group.items.slice(0, initial).map(taskCard).join('') : '<p class="text-xs text-slate-400 py-2">Aucune tâche</p>') : ''}
                      </div>
                      <div class="mt-2 flex items-center justify-between gap-2">
                        <p class="text-[11px] text-slate-500"><span id="global-timeline-list-count-${group.key}">${initial}</span> / ${group.items.length}</p>
                        <button id="global-timeline-list-more-${group.key}" type="button" class="px-2 py-1 rounded-lg border border-slate-300 bg-white text-slate-700 text-xs font-semibold ${(expanded && initial < group.items.length) ? '' : 'hidden'}">Charger plus</button>
                      </div>
                    </div>
                  </div>
                `;
              }).join('')}
            </div>
          `;

          const bindLazyList = (group) => {
            const bodyEl = document.getElementById(`global-timeline-list-body-${group.key}`);
            const listEl = document.getElementById(`global-timeline-list-items-${group.key}`);
            const countEl = document.getElementById(`global-timeline-list-count-${group.key}`);
            const btnMore = document.getElementById(`global-timeline-list-more-${group.key}`);
            const btnToggle = document.getElementById(`global-timeline-list-toggle-${group.key}`);
            const symbolEl = document.getElementById(`global-timeline-toggle-symbol-${group.key}`);
            if (!bodyEl || !listEl || !btnToggle) return;
            const items = group.items || [];
            const update = (rendered) => {
              if (countEl) countEl.textContent = String(rendered);
              if (btnMore) btnMore.classList.toggle('hidden', rendered >= items.length || bodyEl.classList.contains('hidden'));
            };
            const renderIfNeeded = () => {
              const rendered = Number.parseInt(listEl.dataset.rendered || '0', 10) || 0;
              if (rendered > 0 || items.length === 0) return;
              const initial = Math.min(items.length, GLOBAL_TIMELINE_INITIAL_BATCH);
              listEl.innerHTML = items.slice(0, initial).map(taskCard).join('');
              listEl.dataset.rendered = String(initial);
              update(initial);
            };
            const loadNext = () => {
              const rendered = Number.parseInt(listEl.dataset.rendered || '0', 10) || 0;
              if (rendered >= items.length) {
                update(items.length);
                return;
              }
              const next = Math.min(items.length, rendered + GLOBAL_TIMELINE_BATCH_SIZE);
              listEl.insertAdjacentHTML('beforeend', items.slice(rendered, next).map(taskCard).join(''));
              listEl.dataset.rendered = String(next);
              update(next);
            };
            btnToggle.addEventListener('click', () => {
              const willExpand = bodyEl.classList.contains('hidden');
              bodyEl.classList.toggle('hidden', !willExpand);
              globalTimelineExpandedGroups[group.key] = willExpand;
              if (symbolEl) symbolEl.textContent = willExpand ? '-' : '+';
              if (willExpand) {
                renderIfNeeded();
                update(Number.parseInt(listEl.dataset.rendered || '0', 10) || 0);
              } else {
                update(Number.parseInt(listEl.dataset.rendered || '0', 10) || 0);
              }
            });
            btnMore?.addEventListener('click', loadNext);
            if (!bodyEl.classList.contains('hidden')) {
              renderIfNeeded();
              update(Number.parseInt(listEl.dataset.rendered || '0', 10) || 0);
            }
          };
          groups.forEach(bindLazyList);
        }

        document.getElementById('global-timeline-mode-columns')?.addEventListener('click', () => {
          if (globalTimelineDisplayMode === 'columns') return;
          globalTimelineDisplayMode = 'columns';
          localStorage.setItem('taskmda_global_timeline_mode', globalTimelineDisplayMode);
          renderGlobalTasks();
        });
        document.getElementById('global-timeline-mode-list')?.addEventListener('click', () => {
          if (globalTimelineDisplayMode === 'list') return;
          globalTimelineDisplayMode = 'list';
          localStorage.setItem('taskmda_global_timeline_mode', globalTimelineDisplayMode);
          renderGlobalTasks();
        });
        return;
      }

      // Trier les tâches avant pagination pour éviter les inversions entre pages
      const itemsWithStatus = filtered.map(task => {
        const dueStatus = getTaskDueStatus(task);
        return {
        task,
          dueStatus,
          focusScore: getTaskFocusPriority(task, dueStatus),
          dueSortTs: getTaskEffectiveDueTimestamp(task)
        };
      });
      
      const sortedItems = itemsWithStatus.sort((a, b) => {
        if (dashboardSortMode === 'focus') {
          return b.focusScore - a.focusScore;
        } else {
          // Chronologique : Date limite asc, puis Priorité desc
          const timeA = Number.isFinite(a.dueSortTs) ? a.dueSortTs : Number.POSITIVE_INFINITY;
          const timeB = Number.isFinite(b.dueSortTs) ? b.dueSortTs : Number.POSITIVE_INFINITY;
          if (timeA !== timeB) return timeA - timeB;
          return b.focusScore - a.focusScore;
        }
      });

      const pagination = paginateItems(sortedItems, globalTasksPage, getGlobalTaskCardsPerPage());
      globalTasksPage = pagination.currentPage;
      
      container.className = `global-task-grid cols-${globalTaskCardsColumns}`;
      const showGlobalTaskCardDescription = globalTaskCardsColumns === 1;
      container.innerHTML = pagination.pageItems.map(({ task, dueStatus, focusScore }) => {
        const taskRef = buildGlobalTaskRef(task);
        let canEdit = task.sourceType === 'standalone';
        let canDelete = task.sourceType === 'standalone';
        let canArchive = task.sourceType === 'standalone';
        if (task.sourceType === 'project') {
          const projectState = stateByProjectId.get(task.sourceProjectId);
          canEdit = canEditTaskInProject(task, projectState);
          canDelete = canDeleteTaskInProject(task, projectState);
          canArchive = canEditTaskInProject(task, projectState);
        }
        const canMarkDone = task.sourceType === 'standalone'
          ? true
          : canChangeTaskStatus(task, stateByProjectId.get(task.sourceProjectId));
        
        // Déterminer la classe CSS pour mettre en évidence
        let cardBgClass = 'bg-white';
        let cardAccentClass = getTaskUrgencyMeta(task.urgency).accentClass;
        let ringClass = '';
        let focusClass = focusScore >= 500 ? 'is-focus-priority' : '';
        
        if (dueStatus.isOverdue) {
          cardBgClass = 'is-overdue-card';
          cardAccentClass = 'border-l-4 border-l-red-600';
          ringClass = 'ring-2 ring-offset-1 ring-red-400';
        } else if (dueStatus.isDueToday) {
          cardBgClass = 'bg-yellow-50';
          cardAccentClass = 'border-l-4 border-l-yellow-500';
          ringClass = 'ring-2 ring-offset-1 ring-yellow-400';
        }
        
        // Déclencher une notification pour les tâches à l'échéance aujourd'hui
        if (dueStatus.isDueToday && !task._notifiedToday) {
          const assigneeName = getTaskAssigneeName(task, stateByProjectId.get(task.sourceProjectId)) || 'Aucun responsable';
          addNotification(
            "Tâche à l'échéance",
            `${task.title} - Assisté par ${assigneeName}`,
            task.sourceProjectId,
            {
              targetType: 'task',
              targetId: taskRef,
              targetView: 'cards',
              linkLabel: 'Ouvrir la tâche'
            }
          );
          task._notifiedToday = true; // Marquer pour éviter les doublons
        }
        const isBulkSelectable = globalTasksBulkSelectionMode && canDelete;
        const isSelectedForBulkDelete = selectedGlobalTaskRefsForBulkDelete.has(taskRef);
        const cardClickHandler = isBulkSelectable
          ? `toggleGlobalTaskBulkSelection('${taskRef}')`
          : `openGlobalTaskDetails('${taskRef}')`;
        
        return `
        <div class="global-task-card global-task-card-modern task-completion-fx-anchor ${cardAccentClass} ${focusClass} rounded-xl border border-slate-200 ${cardBgClass} p-4 cursor-pointer ${ringClass} ${isSelectedForBulkDelete ? 'is-bulk-selected' : ''}" data-task-entity-id="${escapeHtml(String(task.taskId || task.id || ''))}" data-task-source-type="${escapeHtml(String(task.sourceType || 'project'))}" data-task-project-id="${escapeHtml(String(task.sourceProjectId || ''))}" onclick="${cardClickHandler}" role="button" tabindex="0">
          <div class="task-card-badge-row flex items-center justify-between gap-2 mb-1">
            <div class="task-card-badge-left flex items-center gap-2 min-w-0">
              ${dueStatus.isOverdue ? '<span class="px-2 py-1 rounded-lg bg-red-200 text-red-800 text-xs font-bold">⚠️ EN RETARD</span>' : ''}
              ${dueStatus.isDueToday ? '<span class="px-2 py-1 rounded-lg bg-yellow-200 text-yellow-800 text-xs font-bold">AUJOURD\'HUI</span>' : ''}
              <span class="${getTaskUrgencyMeta(task.urgency).chipClass}">${getTaskUrgencyMeta(task.urgency).label}</span>
            </div>
            <div class="task-card-badge-right flex items-center justify-end gap-1 shrink-0">
              ${globalTasksBulkSelectionMode ? `
                <label class="taskmda-bulk-checkbox-wrap" onclick="event.stopPropagation()">
                  <input type="checkbox" class="taskmda-bulk-checkbox-input" data-task-ref="${escapeHtml(taskRef)}" ${isSelectedForBulkDelete ? 'checked' : ''} ${canDelete ? '' : 'disabled'} onchange="toggleGlobalTaskBulkSelection('${taskRef}', this.checked)" aria-label="Sélectionner la tâche ${escapeHtml(task.title || '')}">
                  <span class="taskmda-bulk-checkbox-label">Sélection</span>
                </label>
              ` : ''}
              ${buildTaskRecurrenceBadgeHtml(task)}
              ${sharingModeBadge(task.sharingMode)}
              <span class="${getTaskStatusMeta(task.status).chipClass}">${getTaskStatusMeta(task.status).label}</span>
            </div>
          </div>
          <div>
            <h4 class="font-bold text-slate-800">${escapeHtml(task.title || 'Tâche')}</h4>
            <p class="text-xs text-slate-500 mt-1">${escapeHtml(task.sourceProjectName || 'Hors projet')} • ${escapeHtml(task.theme || 'Général')}</p>
            ${buildTaskHierarchyChipsHtml(task, stateByProjectId.get(task.sourceProjectId)) ? `<p class="mt-1">${buildTaskHierarchyChipsHtml(task, stateByProjectId.get(task.sourceProjectId))}</p>` : ''}
          </div>
          ${showGlobalTaskCardDescription ? `<p class="text-sm text-slate-600 mt-2">${escapeHtml(task.description || '')}</p>` : ''}
          ${buildTaskProgressBarHtml(task)}
          ${buildSubtaskProgressHtml(task, true)}
          <div class="mt-2 text-xs text-slate-500 flex flex-wrap gap-3">
            <span>Demande: ${formatDate(task.requestDate)}</span>
            <span>Date limite: ${formatTaskDeadline(task)}</span>
            <span class="inline-flex items-center gap-1.5">Responsable: ${buildTaskAssigneeInlineHtml(task, stateByProjectId.get(task.sourceProjectId))}</span>
          </div>
          <div class="task-hover-actions mt-3 flex flex-wrap gap-2 text-xs">
            ${(task.status || 'todo') !== 'termine' && canMarkDone ? `<button onclick="event.stopPropagation(); markGlobalTaskDone('${taskRef}')" class="task-action-btn task-action-btn-subtle" data-action-kind="success">Réalisé</button>` : ''}
            ${canEdit ? `<button onclick="event.stopPropagation(); editGlobalTask('${taskRef}')" class="task-action-btn task-action-btn-subtle">Modifier</button>` : ''}
            ${canEdit ? `<button onclick="event.stopPropagation(); convertTaskToProject('${taskRef}')" class="task-action-btn task-action-btn-subtle">Convertir</button>` : ''}
            <button onclick="event.stopPropagation(); sendTaskEmailByRef('${taskRef}', 'auto')" class="task-action-btn task-action-btn-subtle"><span class="material-symbols-outlined">mail</span> Email</button>
            ${canArchive ? `<button onclick="event.stopPropagation(); archiveGlobalTask('${taskRef}')" class="task-action-btn task-action-btn-subtle task-action-btn-warn">Archiver</button>` : ''}
            ${canDelete ? `<button onclick="event.stopPropagation(); deleteGlobalTask('${taskRef}')" class="task-action-btn task-action-btn-subtle task-action-btn-danger">Supprimer</button>` : ''}
          </div>
        </div>
      `;
      }).join('');
      renderPagination('global-tasks-pagination', pagination, 'setGlobalTasksPage', 'taches');
    }

    function renderGlobalArchivedTasks(allTasks, stateByProjectId, targetContainer) {
      const container = targetContainer || document.getElementById('global-tasks-container');
      const paginationContainer = document.getElementById('global-tasks-pagination');
      if (!container) return;

      const query = `${globalSearchQuery} ${document.getElementById('global-task-search')?.value || ''}`.trim();
      const status = String(document.getElementById('global-task-status')?.value || 'all').trim();
      const assigneeKind = String(document.getElementById('global-task-assignee-kind')?.value || 'all').trim();
      const theme = String(document.getElementById('global-task-theme-known')?.value || '').trim();
      const urgencies = getSelectedGlobalTaskUrgencySet();
      let archived = (allTasks || []).filter(task => task?.archivedAt);
      archived = archived.filter(task => matchesQuery([
        task.title,
        task.description,
        task.sourceProjectName,
        task.theme,
        getTaskAssigneeName(task, stateByProjectId?.get(task.sourceProjectId)),
        sharingModeLabel(task.sharingMode)
      ], query));
      if (status !== 'all') archived = archived.filter(task => (task.status || 'todo') === status);
      if (assigneeKind !== 'all') archived = archived.filter(task => matchesTaskAssigneeKindFilter(task, stateByProjectId?.get(task.sourceProjectId), assigneeKind));
      if (theme) archived = archived.filter(task => matchesQuery([task.theme], theme));
      archived = archived.filter(task => urgencies.has(getTaskUrgencyMeta(task.urgency).key));
      archived.sort((a, b) => (b.archivedAt || 0) - (a.archivedAt || 0));

      if (archived.length === 0) {
        container.className = 'space-y-3';
        container.innerHTML = '<p class="text-slate-500 text-center py-8">Aucune tâche archivée</p>';
        if (paginationContainer) paginationContainer.innerHTML = '';
        return;
      }

      const pagination = paginateItems(archived, globalArchivedTasksPage, paginationConfig.globalTasksPerPage);
      globalArchivedTasksPage = pagination.currentPage;
      container.className = 'space-y-2';
      container.innerHTML = pagination.pageItems.map((task) => {
        const taskRef = buildGlobalTaskRef(task);
        let canEdit = task.sourceType === 'standalone';
        let canDelete = task.sourceType === 'standalone';
        if (task.sourceType === 'project') {
          const projectState = stateByProjectId?.get(task.sourceProjectId);
          canEdit = canEditTaskInProject(task, projectState);
          canDelete = canDeleteTaskInProject(task, projectState);
        }
        return `
          <div class="rounded-lg border border-slate-200 bg-white p-3">
            <div class="flex items-start justify-between gap-3">
              <div>
                <p class="text-sm font-semibold text-slate-800">${escapeHtml(task.title || 'Tache')}</p>
                <p class="text-xs text-slate-500 mt-1">${escapeHtml(task.sourceProjectName || 'Hors projet')} - ${escapeHtml(task.theme || 'General')}</p>
                <p class="text-xs text-slate-500 mt-1">Archivee le ${task.archivedAt ? new Date(task.archivedAt).toLocaleString('fr-FR') : '-'}</p>
              </div>
              <div class="flex items-center gap-2 text-xs">
                ${canEdit ? `<button onclick="restoreGlobalTask('${taskRef}')" class="task-action-btn" data-action-kind="unarchive">Restaurer</button>` : ''}
                ${canDelete ? `<button onclick="deleteGlobalTask('${taskRef}')" class="task-action-btn task-action-btn-danger" data-action-kind="danger">Supprimer</button>` : ''}
              </div>
            </div>
          </div>
        `;
      }).join('');
    }

    const renderGlobalTasksBase = renderGlobalTasks;
    renderGlobalTasks = async function renderGlobalTasksWithEmptyState() {
      await renderGlobalTasksBase();
      const container = document.getElementById('global-tasks-container');
      if (!container) return;
      if (globalTasksViewMode === 'calendar' || globalTasksViewMode === 'archives') return;
      const paginationContainer = document.getElementById('global-tasks-pagination');

      const all = await getGlobalTasksList();
      const query = `${globalSearchQuery} ${document.getElementById('global-task-search')?.value || ''}`.trim();
      const status = document.getElementById('global-task-status')?.value || 'all';
      const assigneeKind = String(document.getElementById('global-task-assignee-kind')?.value || 'all').trim();
      const theme = document.getElementById('global-task-theme-known')?.value || '';
      const urgencies = getSelectedGlobalTaskUrgencySet();

      let filtered = all.filter(task => matchesQuery([
        task.title,
        task.description,
        task.sourceProjectName,
        task.theme,
        sharingModeLabel(task.sharingMode)
      ], query));
      if (status !== 'all') filtered = filtered.filter(task => (task.status || 'todo') === status);
      if (assigneeKind !== 'all') filtered = filtered.filter(task => matchesTaskAssigneeKindFilter(task, null, assigneeKind));
      if (theme.trim()) filtered = filtered.filter(task => matchesQuery([task.theme], theme));
      filtered = filtered.filter(task => urgencies.has(getTaskUrgencyMeta(task.urgency).key));
      filtered = filtered.filter(task => !task.archivedAt);

      if (all.length === 0 && filtered.length === 0) {
        container.className = 'space-y-3';
        container.innerHTML = `
          <button
            type="button"
            class="tasks-empty-state"
            onclick="document.getElementById('btn-global-add-task')?.click()"
            aria-label="Créer une nouvelle tâche hors projet"
          >
            <span class="tasks-empty-icon material-symbols-outlined">add</span>
            <span class="tasks-empty-title">Créer une première tâche</span>
            <span class="tasks-empty-subtitle">Ajoutez une tâche solo ou collaborative pour démarrer votre pilotage transverse.</span>
          </button>
        `;
        if (paginationContainer) paginationContainer.innerHTML = '';
      }
      flushTaskCompletionFxQueue();
    };

    async function renderGlobalCalendar() {
      initGlobalCalendarPinnedThemesState();
      setGlobalCalendarControlsExpanded(globalCalendarControlsExpanded, { skipPersist: true });
      const container = document.getElementById('global-calendar-container');
      const monthInput = document.getElementById('global-calendar-month');
      const monthLabel = document.getElementById('global-calendar-month-label');
      const listWrap = document.getElementById('global-calendar-list-wrap');
      const gridWrap = document.getElementById('global-calendar-grid-wrap');
      const yearWrap = document.getElementById('global-calendar-year-wrap');
      const grid = document.getElementById('global-calendar-grid');
      const dayDetails = document.getElementById('global-calendar-day-details');
      const yearGrid = document.getElementById('global-calendar-year-grid');
      const yearDetails = document.getElementById('global-calendar-year-details');
      const periodHint = document.getElementById('global-calendar-period-hint');
      const btnViewList = document.getElementById('global-calendar-view-list');
      const btnViewGrid = document.getElementById('global-calendar-view-grid');
      const btnViewYear = document.getElementById('global-calendar-view-year');
      if (!container || !monthInput || !listWrap || !gridWrap || !yearWrap || !grid || !dayDetails || !yearGrid || !yearDetails) return;

      if (monthInput.options.length === 0) {
        const base = new Date();
        const options = [];
        for (let offset = -60; offset <= 60; offset++) {
          const d = new Date(base.getFullYear(), base.getMonth() + offset, 1);
          const value = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
          const label = d.toLocaleDateString('fr-FR', { month: 'long', year: 'numeric' });
          options.push(`<option value="${value}">${label}</option>`);
        }
        monthInput.innerHTML = options.join('');
        monthInput.value = `${base.getFullYear()}-${String(base.getMonth() + 1).padStart(2, '0')}`;
      }

      const all = await getGlobalTasksList();
      const q = `${globalSearchQuery} ${document.getElementById('global-calendar-search')?.value || ''}`.trim();
      let month = monthInput.value || toYmd(new Date()).slice(0, 7);
      if (!/^\d{4}-\d{2}$/.test(String(month))) {
        const now = new Date();
        month = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
        monthInput.value = month;
      }

      const isList = globalCalendarViewMode === 'list';
      const isGrid = globalCalendarViewMode === 'grid';
      const isYear = globalCalendarViewMode === 'year';
      const selectedYear = Number(String(month).slice(0, 4));
      if (monthLabel) {
        const [yy, mm] = String(month).split('-');
        const d = new Date(Number(yy), Number(mm) - 1, 1);
        monthLabel.textContent = isYear
          ? d.toLocaleDateString('fr-FR', { year: 'numeric' })
          : d.toLocaleDateString('fr-FR', { month: 'long', year: 'numeric' });
      }
      if (periodHint) {
        periodHint.textContent = isYear
          ? 'Année affichée'
          : 'Période affichée';
      }

      const standaloneItems = await getAllDecrypted('globalCalendarItems', 'id');
      const taskEntries = all
        .filter(task => task.dueDate && !task.archivedAt)
        .map(task => ({
          entryType: 'task',
          taskRef: buildGlobalTaskRef(task),
          date: taskDueDateKey(task),
          title: task.title || 'Tache',
          description: task.description || '',
          theme: task.theme || 'General',
          source: task.sourceProjectName || 'Hors projet',
          sharingMode: task.sharingMode || (task.sourceType === 'standalone' ? 'private' : 'shared'),
          sortDate: new Date(task.dueDate).getTime()
        }));
      const infoEntries = (standaloneItems || []).map(item => ({
        entryType: 'info',
        id: item.id,
        date: getCalendarItemStartDate(item),
        startDate: getCalendarItemStartDate(item),
        endDate: getCalendarItemEndDate(item),
        startTime: getCalendarItemStartTime(item),
        endTime: getCalendarItemEndTime(item),
        title: item.title || 'Information',
        description: item.notes || '',
        theme: item.theme || 'General',
        source: 'Hors projet',
        sharingMode: item.sharingMode || 'private',
        archivedAt: item.archivedAt || null,
        sortDate: getCalendarItemStartDate(item) ? (parseCalendarYmdToDate(getCalendarItemStartDate(item))?.getTime() || 0) : 0
      }));

      const allEntries = [...taskEntries, ...infoEntries].filter((entry) => !entry.archivedAt);
      const availableThemes = allEntries.map((entry) => normalizeCalendarThemeName(entry.theme));
      renderGlobalCalendarThemePins(availableThemes);
      const checkedThemeKeys = new Set(globalCalendarPinnedThemeChecks.map(normalizeCalendarThemeKey));

      const mixed = allEntries
        .filter(entry => (
          isYear
            ? (
              entry.entryType === 'info'
                ? doesCalendarRangeOverlapYear(entry.startDate, entry.endDate, selectedYear)
                : String(entry.date || '').startsWith(`${selectedYear}-`)
            )
            : (
              entry.entryType === 'info'
                ? doesCalendarRangeOverlapMonth(entry.startDate, entry.endDate, month)
                : String(entry.date || '').startsWith(month)
            )
        ))
        .filter((entry) => {
          if (checkedThemeKeys.size === 0) return true;
          return checkedThemeKeys.has(normalizeCalendarThemeKey(entry.theme));
        })
        .filter(entry => matchesQuery([
          entry.title,
          entry.description,
          entry.theme,
          entry.source,
          sharingModeLabel(entry.sharingMode),
          entry.entryType === 'info' ? buildCalendarItemDateLabel(entry) : formatDate(entry.date)
        ], q))
        .sort((a, b) => a.sortDate - b.sortDate);

      const isSharedEntry = (entry) => normalizeSharingMode(entry?.sharingMode, 'private') === 'shared';
      const getEntryOpenAction = (entry) => {
        if (entry?.entryType === 'task' && entry?.taskRef) {
          return `openGlobalTaskDetails('${entry.taskRef}')`;
        }
        if (entry?.entryType === 'info' && entry?.id) {
          return `openStandaloneCalendarDetails('${entry.id}')`;
        }
        return '';
      };

      listWrap.classList.toggle('hidden', !isList);
      gridWrap.classList.toggle('hidden', !isGrid);
      yearWrap.classList.toggle('hidden', !isYear);
      if (btnViewList && btnViewGrid && btnViewYear) {
        btnViewList.classList.toggle('view-tab-active', isList);
        btnViewGrid.classList.toggle('view-tab-active', isGrid);
        btnViewYear.classList.toggle('view-tab-active', isYear);
      }

      if ((isList || isYear) && mixed.length === 0) {
        container.innerHTML = buildWorkspaceEmptyState({
          icon: 'calendar_month',
          title: 'Aucune échéance pour ces critères',
          text: 'Ajoutez une information hors projet ou élargissez vos filtres.',
          ctaLabel: 'Ajouter une information',
          ctaOnclick: 'openGlobalCalendarItemModal()'
        });
        yearGrid.innerHTML = '';
        yearDetails.innerHTML = '';
        return;
      }

      if (isGrid) {
        const [yearStr, monthStr] = month.split('-');
        let year = Number(yearStr);
        let monthIndex = Number(monthStr) - 1;
        if (!Number.isFinite(year) || !Number.isFinite(monthIndex) || monthIndex < 0 || monthIndex > 11) {
          const fallback = new Date();
          year = fallback.getFullYear();
          monthIndex = fallback.getMonth();
          month = `${year}-${String(monthIndex + 1).padStart(2, '0')}`;
          monthInput.value = month;
        }
        const firstDay = new Date(year, monthIndex, 1);
        const startOffset = (firstDay.getDay() + 6) % 7;
        const daysInMonth = new Date(year, monthIndex + 1, 0).getDate();
        if (!Number.isFinite(daysInMonth) || daysInMonth <= 0) {
          grid.innerHTML = '<div class="col-span-7 text-center text-sm text-slate-500 py-4">Mois invalide, réinitialisation appliquée.</div>';
          dayDetails.innerHTML = '';
          return;
        }

        const todayKey = toYmd(new Date());
        const monthPrefix = `${year}-${String(monthIndex + 1).padStart(2, '0')}`;
        const entriesByDay = new Map();

        mixed.forEach(entry => {
          if (entry.entryType === 'info') {
            const keys = getCalendarRangeDayKeysInMonth(entry.startDate, entry.endDate, month);
            keys.forEach((key) => {
              if (!entriesByDay.has(key)) entriesByDay.set(key, []);
              entriesByDay.get(key).push(entry);
            });
            return;
          }
          const key = String(entry.date || '');
          if (!entriesByDay.has(key)) entriesByDay.set(key, []);
          entriesByDay.get(key).push(entry);
        });

        if (!globalCalendarSelectedDay || !String(globalCalendarSelectedDay).startsWith(monthPrefix)) {
          globalCalendarSelectedDay = todayKey.startsWith(monthPrefix)
            ? todayKey
            : `${monthPrefix}-01`;
        }

        const dayHeaders = ['Lun', 'Mar', 'Mer', 'Jeu', 'Ven', 'Sam', 'Dim']
          .map(label => `<div class="calendar-day-header">${label}</div>`)
          .join('');
        const blanks = Array.from({ length: startOffset }).map(() => '<div></div>').join('');
        const dayCells = Array.from({ length: daysInMonth }).map((_, idx) => {
          const day = idx + 1;
          const dayKey = `${monthPrefix}-${String(day).padStart(2, '0')}`;
          const dayEntries = entriesByDay.get(dayKey) || [];
          const sharedCount = dayEntries.filter(isSharedEntry).length;
          const privateCount = Math.max(0, dayEntries.length - sharedCount);
          const modeClass = sharedCount > 0 && privateCount === 0
            ? 'global-cal-day-mode-shared'
            : privateCount > 0 && sharedCount === 0
              ? 'global-cal-day-mode-private'
              : (sharedCount > 0 && privateCount > 0 ? 'global-cal-day-mode-mixed' : '');
          const isToday = dayKey === todayKey;
          const isSelected = dayKey === globalCalendarSelectedDay;
          return `
            <div class="global-cal-day min-h-[72px] rounded-lg border p-1 text-left ${modeClass} ${isSelected ? 'global-cal-day-selected' : ''} ${isToday ? 'global-cal-day-today' : ''}" data-day="${dayKey}" role="button" tabindex="0" aria-label="Jour ${day} du calendrier">
              <div class="global-cal-day-number ${isToday ? 'global-cal-day-number-today' : ''}">${day}</div>
              <button type="button" class="global-cal-day-add" data-day="${dayKey}" aria-label="Ajouter une info hors projet le ${dayKey}">
                <span class="material-symbols-outlined">add</span>
              </button>
              <div class="mt-1 space-y-1">
                ${(dayEntries || []).slice(0, 2).map(item => `<div class="calendar-day-item ${isSharedEntry(item) ? 'calendar-day-item-shared' : 'calendar-day-item-private'}">${escapeHtml(item.title || '')}</div>`).join('')}
                ${dayEntries.length > 2 ? `<div class="calendar-day-more">+${dayEntries.length - 2}</div>` : ''}
              </div>
              ${(sharedCount + privateCount) > 0 ? `
                <div class="mt-1 flex items-center gap-1 text-[9px]">
                  ${sharedCount > 0 ? `<span class="calendar-mini-chip calendar-mini-chip-shared">Collab ${sharedCount}</span>` : ''}
                  ${privateCount > 0 ? `<span class="calendar-mini-chip calendar-mini-chip-private">Privée ${privateCount}</span>` : ''}
                </div>
              ` : ''}
            </div>
          `;
        }).join('');

        grid.innerHTML = `${dayHeaders}${blanks}${dayCells}`;
        grid.querySelectorAll('.global-cal-day').forEach(dayCell => {
          const selectDay = () => {
            globalCalendarSelectedDay = dayCell.getAttribute('data-day');
            renderGlobalCalendar();
          };
          dayCell.addEventListener('click', selectDay);
          dayCell.addEventListener('keydown', (event) => {
            if (event.key === 'Enter' || event.key === ' ') {
              event.preventDefault();
              selectDay();
            }
          });
        });

        grid.querySelectorAll('.global-cal-day-add').forEach(addButton => {
          addButton.addEventListener('click', (event) => {
            event.preventDefault();
            event.stopPropagation();
            const dayKey = String(addButton.getAttribute('data-day') || '');
            if (!dayKey) return;
            globalCalendarSelectedDay = dayKey;
            openGlobalCalendarItemModal(dayKey);
          });
        });

        const selectedEntries = entriesByDay.get(globalCalendarSelectedDay) || [];
        if (selectedEntries.length === 0) {
          dayDetails.innerHTML = buildWorkspaceEmptyState({
            icon: 'event_busy',
            title: `Aucun élément le ${formatDate(globalCalendarSelectedDay)}`,
            text: 'Cette journée est libre pour le moment.',
            compact: true
          });
          return;
        }

        dayDetails.innerHTML = selectedEntries.map(entry => `
          <div class="calendar-detail-card ${isSharedEntry(entry) ? 'calendar-detail-card-shared' : 'calendar-detail-card-private'} ${getEntryOpenAction(entry) ? 'cursor-pointer' : ''}" ${getEntryOpenAction(entry) ? `onclick="${getEntryOpenAction(entry)}" role="button" tabindex="0" onkeydown="if(event.key==='Enter'||event.key===' '){event.preventDefault();${getEntryOpenAction(entry)};}"` : ''}>
            <div class="flex items-center justify-between gap-2">
              <p class="font-semibold text-slate-800">${escapeHtml(entry.title || 'Element')}</p>
              <span class="inline-flex text-[10px] px-2 py-1 rounded-full font-semibold ${isSharedEntry(entry) ? 'calendar-chip-shared' : 'calendar-chip-private'}">${isSharedEntry(entry) ? 'Collaborative' : 'Privée'}</span>
            </div>
            <p class="text-xs text-slate-500 mt-1">${escapeHtml(entry.source || 'Hors projet')} - ${escapeHtml(entry.theme || 'Général')}</p>
            <p class="text-xs text-slate-500 mt-1">${escapeHtml(entry.entryType === 'info' ? buildCalendarItemDateLabel(entry) : formatDate(entry.date))}</p>
            <p class="text-sm text-slate-600 mt-1">${escapeHtml(entry.description || '')}</p>
            ${entry.entryType === 'info' && entry.id ? `
              <div class="mt-2 flex flex-wrap gap-2 text-xs">
                <button onclick="event.stopPropagation(); editStandaloneCalendarItem('${entry.id}')" class="workspace-action-inline">Modifier</button>
                <button onclick="event.stopPropagation(); archiveStandaloneCalendarItem('${entry.id}')" class="workspace-action-inline">Archiver</button>
                <button onclick="event.stopPropagation(); deleteStandaloneCalendarItem('${entry.id}')" class="workspace-action-inline">Supprimer</button>
              </div>
            ` : ''}
          </div>
        `).join('');
        return;
      }

      if (isYear) {
        const monthEntries = Array.from({ length: 12 }, (_, idx) => ({
          monthKey: `${selectedYear}-${String(idx + 1).padStart(2, '0')}`,
          label: new Date(selectedYear, idx, 1).toLocaleDateString('fr-FR', { month: 'long', year: 'numeric' }),
          entries: []
        }));
        const mapByMonth = new Map(monthEntries.map((bucket) => [bucket.monthKey, bucket]));

        mixed.forEach((entry) => {
          if (entry.entryType === 'info') {
            for (let idx = 0; idx < 12; idx++) {
              const monthKey = `${selectedYear}-${String(idx + 1).padStart(2, '0')}`;
              if (doesCalendarRangeOverlapMonth(entry.startDate, entry.endDate, monthKey)) {
                mapByMonth.get(monthKey)?.entries.push(entry);
              }
            }
            return;
          }
          const dueKey = String(entry.date || '').slice(0, 7);
          mapByMonth.get(dueKey)?.entries.push(entry);
        });

        monthEntries.forEach((bucket) => {
          bucket.entries.sort((a, b) => a.sortDate - b.sortDate);
        });

        const now = new Date();
        const nowMonthKey = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
        const firstMonthWithItems = monthEntries.find((bucket) => bucket.entries.length > 0)?.monthKey || `${selectedYear}-01`;
        if (!globalCalendarSelectedMonth || !String(globalCalendarSelectedMonth).startsWith(`${selectedYear}-`)) {
          globalCalendarSelectedMonth = nowMonthKey.startsWith(`${selectedYear}-`) ? nowMonthKey : firstMonthWithItems;
        }

        yearGrid.innerHTML = monthEntries.map((bucket) => {
          const sharedCount = bucket.entries.filter(isSharedEntry).length;
          const privateCount = Math.max(0, bucket.entries.length - sharedCount);
          const isCurrent = bucket.monthKey === nowMonthKey;
          const isSelected = bucket.monthKey === globalCalendarSelectedMonth;
          return `
            <div class="global-calendar-year-month ${isSelected ? 'global-calendar-year-month-selected' : ''} ${isCurrent ? 'global-calendar-year-month-current' : ''}" data-year-month="${bucket.monthKey}" role="button" tabindex="0" aria-label="Mois ${escapeHtml(bucket.label)}">
              <div class="flex items-center justify-between gap-2">
                <p class="font-semibold text-slate-800 capitalize">${escapeHtml(bucket.label)}</p>
                <span class="text-xs text-slate-500">${bucket.entries.length}</span>
              </div>
              <div class="mt-2 space-y-1">
                ${(bucket.entries || []).slice(0, 3).map((entry) => `<div class="calendar-day-item ${isSharedEntry(entry) ? 'calendar-day-item-shared' : 'calendar-day-item-private'}">${escapeHtml(entry.title || '')}</div>`).join('')}
                ${bucket.entries.length > 3 ? `<div class="calendar-day-more">+${bucket.entries.length - 3}</div>` : ''}
              </div>
              <div class="mt-2 flex items-center gap-1 text-[10px]">
                ${sharedCount > 0 ? `<span class="calendar-mini-chip calendar-mini-chip-shared">Collab ${sharedCount}</span>` : ''}
                ${privateCount > 0 ? `<span class="calendar-mini-chip calendar-mini-chip-private">Privée ${privateCount}</span>` : ''}
              </div>
            </div>
          `;
        }).join('');

        yearGrid.querySelectorAll('.global-calendar-year-month').forEach((monthCell) => {
          const openMonth = () => {
            const monthKey = String(monthCell.getAttribute('data-year-month') || '');
            if (!monthKey) return;
            ensureGlobalCalendarMonthOption(monthInput, Number(monthKey.slice(0, 4)), Number(monthKey.slice(5, 7)) - 1);
            globalCalendarViewMode = resolveViewWithLock('globalCalendar', 'grid', 'grid');
            globalCalendarSelectedDay = null;
            globalCalendarSelectedMonth = monthKey;
            renderGlobalCalendar();
          };
          monthCell.addEventListener('click', openMonth);
          monthCell.addEventListener('keydown', (event) => {
            if (event.key === 'Enter' || event.key === ' ') {
              event.preventDefault();
              openMonth();
            }
          });
        });

        const selectedMonthEntries = monthEntries.find((bucket) => bucket.monthKey === globalCalendarSelectedMonth)?.entries || [];
        if (selectedMonthEntries.length === 0) {
          yearDetails.innerHTML = buildWorkspaceEmptyState({
            icon: 'event_busy',
            title: `Aucun élément en ${new Date(`${globalCalendarSelectedMonth || `${selectedYear}-01`}-01`).toLocaleDateString('fr-FR', { month: 'long', year: 'numeric' })}`,
            text: 'Sélectionnez un autre mois ou ajoutez une information.',
            compact: true
          });
          return;
        }

        yearDetails.innerHTML = selectedMonthEntries.map(entry => `
          <div class="calendar-detail-card ${isSharedEntry(entry) ? 'calendar-detail-card-shared' : 'calendar-detail-card-private'} ${getEntryOpenAction(entry) ? 'cursor-pointer' : ''}" ${getEntryOpenAction(entry) ? `onclick="${getEntryOpenAction(entry)}" role="button" tabindex="0" onkeydown="if(event.key==='Enter'||event.key===' '){event.preventDefault();${getEntryOpenAction(entry)};}"` : ''}>
            <div class="flex items-center justify-between gap-2">
              <p class="font-semibold text-slate-800">${escapeHtml(entry.title || 'Element')}</p>
              <span class="inline-flex text-[10px] px-2 py-1 rounded-full font-semibold ${isSharedEntry(entry) ? 'calendar-chip-shared' : 'calendar-chip-private'}">${isSharedEntry(entry) ? 'Collaborative' : 'Privée'}</span>
            </div>
            <p class="text-xs text-slate-500 mt-1">${escapeHtml(entry.source || 'Hors projet')} - ${escapeHtml(entry.theme || 'Général')}</p>
            <p class="text-xs text-slate-500 mt-1">${escapeHtml(entry.entryType === 'info' ? buildCalendarItemDateLabel(entry) : formatDate(entry.date))}</p>
            <p class="text-sm text-slate-600 mt-1">${escapeHtml(entry.description || '')}</p>
          </div>
        `).join('');
        return;
      }

      container.innerHTML = mixed.map(entry => `
        <div class="calendar-entry-card ${isSharedEntry(entry) ? 'calendar-entry-card-shared' : 'calendar-entry-card-private'} ${getEntryOpenAction(entry) ? 'cursor-pointer' : ''}" ${getEntryOpenAction(entry) ? `onclick="${getEntryOpenAction(entry)}" role="button" tabindex="0" onkeydown="if(event.key==='Enter'||event.key===' '){event.preventDefault();${getEntryOpenAction(entry)};}"` : ''}>
          <div class="flex items-center justify-between gap-2">
            <h4 class="font-semibold text-slate-800">${escapeHtml(entry.title || 'Element')}</h4>
            <span class="text-xs text-slate-500">${escapeHtml(entry.entryType === 'info' ? buildCalendarItemDateLabel(entry) : formatDate(entry.date))}</span>
          </div>
          <p class="text-xs text-slate-500 mt-1">${escapeHtml(entry.source || 'Hors projet')} - ${escapeHtml(entry.theme || 'Général')}</p>
          <p class="text-sm text-slate-600 mt-1">${escapeHtml(entry.description || '')}</p>
          <div class="mt-2 flex flex-wrap gap-1">
            <span class="inline-flex text-[10px] px-2 py-1 rounded-full ${entry.entryType === 'task' ? 'calendar-chip-task' : 'calendar-chip-info'} font-semibold">
              ${entry.entryType === 'task' ? 'Date limite tâche' : 'Info hors projet'}
            </span>
            <span class="inline-flex text-[10px] px-2 py-1 rounded-full font-semibold ${isSharedEntry(entry) ? 'calendar-chip-shared' : 'calendar-chip-private'}">${isSharedEntry(entry) ? 'Collaborative' : 'Privée'}</span>
          </div>
          ${entry.entryType === 'info' && entry.id ? `
            <div class="mt-2 flex flex-wrap gap-2 text-xs">
              <button onclick="event.stopPropagation(); editStandaloneCalendarItem('${entry.id}')" class="workspace-action-inline">Modifier</button>
              <button onclick="event.stopPropagation(); archiveStandaloneCalendarItem('${entry.id}')" class="workspace-action-inline">Archiver</button>
              <button onclick="event.stopPropagation(); deleteStandaloneCalendarItem('${entry.id}')" class="workspace-action-inline">Supprimer</button>
            </div>
          ` : ''}
        </div>
      `).join('');
      return;
    }

    async function renderGlobalCalendarDelegated() {
      if (globalCalendarRuntime?.renderGlobalCalendar) {
        await globalCalendarRuntime.renderGlobalCalendar();
        return;
      }
      await renderGlobalCalendar();
    }

    async function renderGlobalNotesDelegated() {
      if (globalNotesRuntime?.renderGlobalNotes) {
        await globalNotesRuntime.renderGlobalNotes();
        return;
      }
      await renderGlobalNotes();
    }

    function ensureGlobalCalendarMonthOption(monthInput, year, monthIndex) {
      const value = `${year}-${String(monthIndex + 1).padStart(2, '0')}`;
      if (!monthInput.querySelector(`option[value="${value}"]`)) {
        const opt = document.createElement('option');
        opt.value = value;
        opt.textContent = new Date(year, monthIndex, 1).toLocaleDateString('fr-FR', { month: 'long', year: 'numeric' });
        monthInput.appendChild(opt);
      }
      monthInput.value = value;
    }

    function shiftGlobalCalendarMonth(offset) {
      const monthInput = document.getElementById('global-calendar-month');
      if (!monthInput) return;
      const step = globalCalendarViewMode === 'year' ? 12 : 1;
      const current = monthInput.value && /^\d{4}-\d{2}$/.test(monthInput.value)
        ? monthInput.value
        : toYmd(new Date()).slice(0, 7);
      const [y, m] = current.split('-');
      const d = new Date(Number(y), Number(m) - 1 + (Number(offset || 0) * step), 1);
      ensureGlobalCalendarMonthOption(monthInput, d.getFullYear(), d.getMonth());
      globalCalendarSelectedDay = null;
      if (globalCalendarViewMode === 'year') globalCalendarSelectedMonth = null;
      renderGlobalCalendar();
    }

    async function editGlobalTask(taskRef) {
      const resolved = await resolveGlobalTaskFromRef(taskRef);
      if (!resolved?.task) return;
      if (resolved.sourceType === 'standalone') {
        standaloneTaskMode = true;
        openTaskModal({ ...resolved.task, taskId: null });
        editingStandaloneTaskId = resolved.task.id;
        return;
      }
      if (!canEditTaskInProject(resolved.task, resolved.state)) {
        showToast('Action non autorisee');
        return;
      }
      await showProjectDetail(resolved.projectId);
      await editTask(resolved.task.taskId);
    }

    async function archiveGlobalTask(taskRef) {
      const resolved = await resolveGlobalTaskFromRef(taskRef);
      if (!resolved?.task) return;
      if (resolved.sourceType === 'standalone') {
        if (normalizeTaskStatusValue(resolved.task.status) !== 'termine') {
          queueTaskCompletionFx({
            sourceType: 'standalone',
            id: resolved.task.id
          });
        }
        await putEncrypted('globalTasks', {
          ...resolved.task,
          status: 'termine',
          completedAt: Number(resolved.task?.completedAt || Date.now()) || Date.now(),
          archivedAt: Date.now(),
          updatedAt: Date.now()
        }, 'id');
        showToast('Tâche archivée');
        await renderGlobalTasks();
        await refreshStats();
        return;
      }
      if (!canEditTaskInProject(resolved.task, resolved.state)) {
        showToast('Action non autorisee');
        return;
      }
      if (!ensureProjectResourceUnlockedForAction(resolved.state, LOCK_SCOPE_TASK, resolved.task.taskId, 'Archivage').ok) {
        return;
      }
      const event = createEvent(
        EventTypes.UPDATE_TASK,
        resolved.projectId,
        currentUser.userId,
        {
          taskId: resolved.task.taskId,
          changes: { status: 'termine', completedAt: Date.now(), archivedAt: Date.now() }
        }
      );
      await publishEvent(event);
      if (sharedFolderHandle) void syncProjectEventsToSharedSpace(resolved.projectId, [event]);
      showToast('Tâche archivée');
      if (workspaceMode === 'global') {
        await renderGlobalTasks();
        await refreshStats();
      } else {
        await showProjectDetail(resolved.projectId);
      }
    }

    async function restoreGlobalTask(taskRef) {
      const resolved = await resolveGlobalTaskFromRef(taskRef);
      if (!resolved?.task) return;
      if (resolved.sourceType === 'standalone') {
        await putEncrypted('globalTasks', {
          ...resolved.task,
          archivedAt: null,
          updatedAt: Date.now()
        }, 'id');
        showToast('Tache restauree');
        await renderGlobalTasks();
        await refreshStats();
        return;
      }
      if (!canEditTaskInProject(resolved.task, resolved.state)) {
        showToast('Action non autorisee');
        return;
      }
      const event = createEvent(
        EventTypes.UPDATE_TASK,
        resolved.projectId,
        currentUser.userId,
        { taskId: resolved.task.taskId, changes: { archivedAt: null } }
      );
      await publishEvent(event);
      if (sharedFolderHandle) void syncProjectEventsToSharedSpace(resolved.projectId, [event]);
      showToast('Tache restauree');
      if (workspaceMode === 'global') {
        await renderGlobalTasks();
        await refreshStats();
      } else {
        await showProjectDetail(resolved.projectId);
      }
    }

    async function deleteGlobalTask(taskRef) {
      const resolved = await resolveGlobalTaskFromRef(taskRef);
      if (!resolved?.task) return;
      if (resolved.sourceType === 'standalone') {
        if (!confirm('Supprimer cette tache hors projet ?')) return;
        const db = getDatabase();
        await deleteFromStore('globalTasks', resolved.task.id);
        showToast('Tache supprimee');
        await renderGlobalTasks();
        await refreshStats();
        return;
      }
      if (!canDeleteTaskInProject(resolved.task, resolved.state)) {
        showToast('Action non autorisee');
        return;
      }
      if (!ensureProjectResourceUnlockedForAction(resolved.state, LOCK_SCOPE_TASK, resolved.task.taskId, 'Suppression').ok) {
        return;
      }
      if (!confirm('Supprimer cette tache ?')) return;
      const event = createEvent(
        EventTypes.DELETE_TASK,
        resolved.projectId,
        currentUser.userId,
        { taskId: resolved.task.taskId }
      );
      await publishEvent(event);
      if (sharedFolderHandle) void syncProjectEventsToSharedSpace(resolved.projectId, [event]);
      showToast('Tache supprimee');
      if (workspaceMode === 'global') {
        await renderGlobalTasks();
        await refreshStats();
      } else {
        await showProjectDetail(resolved.projectId);
      }
    }

    async function markGlobalTaskDone(taskRef) {
      const updated = await updateGlobalTaskStatusFromRef(taskRef, 'termine');
      if (!updated) return;
      showToast('✅ Tâche marquée comme réalisée');
      if (workspaceMode === 'global') {
        await renderGlobalTasks();
        await refreshStats();
      } else {
        const resolved = await resolveGlobalTaskFromRef(taskRef);
        if (resolved?.projectId) {
          await showProjectDetail(resolved.projectId);
        }
      }
    }

    window.editGlobalTask = editGlobalTask;
    window.markGlobalTaskDone = markGlobalTaskDone;
    window.markProjectDoneFromDashboard = markProjectDoneFromDashboard;
    window.archiveGlobalTask = archiveGlobalTask;
    window.restoreGlobalTask = restoreGlobalTask;
    window.deleteGlobalTask = deleteGlobalTask;
    window.toggleGlobalTaskBulkSelection = toggleGlobalTaskBulkSelection;
    window.convertTaskToProject = convertTaskToProject;
    window.openGlobalTaskDetails = openGlobalTaskDetails;
    window.openProjectTaskDetails = openProjectTaskDetails;
    window.removeAttachment = removeAttachment;
    window.openProjectTaskCreateModalWithStatus = openProjectTaskCreateModalWithStatus;
    window.openGlobalTaskCreateModalWithStatus = openGlobalTaskCreateModalWithStatus;
    window.closeGlobalTaskDetails = closeGlobalTaskDetails;
    window.openProjectNoteEditor = openProjectNoteEditor;
    window.setProjectNotesThemeFilter = setProjectNotesThemeFilter;
    window.openProjectNoteReadModal = openProjectNoteReadModal;
    window.toggleProjectNotePinned = toggleProjectNotePinned;
    window.toggleProjectNoteFeedPublish = toggleProjectNoteFeedPublish;
    window.convertProjectNoteToTask = convertProjectNoteToTask;
    window.archiveProjectNote = archiveProjectNote;
    window.restoreProjectNote = restoreProjectNote;
    window.deleteProjectNote = deleteProjectNote;

    function normalizeCalendarDetailInlineFieldValue(field, value) {
      const raw = String(value ?? '').trim();
      if (field === 'title') return raw;
      if (field === 'description') return String(value ?? '').trim();
      if (field === 'date') return /^\d{4}-\d{2}-\d{2}$/.test(raw) ? raw : '';
      if (field === 'theme') return raw || 'General';
      if (field === 'sharingMode') return normalizeSharingMode(raw || 'private', 'private');
      return raw;
    }

    async function ensureCalendarDetailInlineLock(itemId) {
      const id = String(itemId || '').trim();
      if (!id) return false;
      if (activeCalendarEditLock?.itemId === id && activeCalendarEditLock?.lockId) return true;
      if (activeCalendarEditLock?.itemId && activeCalendarEditLock.itemId !== id) {
        await releaseCalendarItemLock(activeCalendarEditLock.itemId, activeCalendarEditLock.lockId || '');
        activeCalendarEditLock = null;
      }
      const lockResult = await acquireCalendarItemLock(id);
      if (!lockResult.ok) {
        showToast(buildLockBlockedMessage(lockResult.lock, 'Information calendrier en cours de modification'));
        return false;
      }
      activeCalendarEditLock = { itemId: id, lockId: lockResult.lockId || '' };
      return true;
    }

    function refreshCalendarDetailInlineDisplay(field, value) {
      const normalizedValue = normalizeCalendarDetailInlineFieldValue(field, value);
      if (field === 'title') {
        const el = document.getElementById('calendar-info-detail-title');
        if (el) el.textContent = normalizedValue || 'Information';
        return;
      }
      if (field === 'description') {
        const el = document.getElementById('calendar-info-detail-description');
        if (el) el.textContent = normalizedValue || 'Aucune description.';
        return;
      }
      if (field === 'date') {
        const el = document.getElementById('calendar-info-detail-date');
        if (el) {
          const source = {
            ...(currentCalendarInfoDetailItem || {}),
            date: normalizedValue || '',
            startDate: normalizedValue || '',
            endDate: normalizedValue || ''
          };
          el.textContent = buildCalendarItemDateLabel(source);
        }
        return;
      }
      if (field === 'theme') {
        const el = document.getElementById('calendar-info-detail-theme');
        if (el) el.textContent = normalizedValue || 'General';
        const subtitleEl = document.getElementById('calendar-info-detail-subtitle');
        if (subtitleEl) subtitleEl.textContent = `Hors projet • ${normalizedValue || 'General'}`;
        return;
      }
      if (field === 'sharingMode') {
        const chip = document.getElementById('calendar-info-detail-sharing-chip');
        if (chip) {
          const isShared = normalizeSharingMode(normalizedValue, 'private') === 'shared';
          chip.className = `inline-flex text-[10px] px-2 py-1 rounded-full font-semibold ${isShared ? 'calendar-chip-shared' : 'calendar-chip-private'} task-detail-inline-editable`;
          chip.textContent = isShared ? 'Collaborative' : 'Privée';
          if (currentCalendarInfoDetailCanEdit) {
            chip.setAttribute('title', 'Cliquer pour modifier');
            chip.setAttribute('tabindex', '0');
            chip.setAttribute('role', 'button');
          } else {
            chip.removeAttribute('title');
            chip.removeAttribute('tabindex');
            chip.removeAttribute('role');
          }
        }
      }
    }

    function decorateCalendarDetailEditableElement(el, field) {
      if (!el) return;
      el.dataset.inlineCalendarField = field;
      el.classList.toggle('task-detail-inline-editable', !!currentCalendarInfoDetailCanEdit);
      if (currentCalendarInfoDetailCanEdit) {
        el.setAttribute('title', 'Cliquer pour modifier');
        el.setAttribute('tabindex', '0');
        el.setAttribute('role', 'button');
      } else {
        el.removeAttribute('title');
        el.removeAttribute('tabindex');
        el.removeAttribute('role');
      }
    }

    function initCalendarDetailInlineEditing(canEdit = false) {
      currentCalendarInfoDetailCanEdit = !!canEdit;
      decorateCalendarDetailEditableElement(document.getElementById('calendar-info-detail-title'), 'title');
      decorateCalendarDetailEditableElement(document.getElementById('calendar-info-detail-description'), 'description');
      decorateCalendarDetailEditableElement(document.getElementById('calendar-info-detail-date'), 'date');
      decorateCalendarDetailEditableElement(document.getElementById('calendar-info-detail-theme'), 'theme');
      decorateCalendarDetailEditableElement(document.getElementById('calendar-info-detail-sharing-chip'), 'sharingMode');

      const modal = document.getElementById('modal-calendar-info-details');
      if (!modal || modal.dataset.inlineCalendarEditorBound === '1') return;
      modal.dataset.inlineCalendarEditorBound = '1';
      modal.addEventListener('click', (event) => {
        const clickTarget = event.target instanceof Element ? event.target : null;
        const trigger = clickTarget?.closest('[data-inline-calendar-field]');
        if (!trigger) return;
        if (trigger.querySelector('.task-detail-inline-editor-wrap')) return;
        startCalendarDetailInlineEdit(trigger).catch((error) => console.error('calendar inline edit', error));
      });
      modal.addEventListener('keydown', (event) => {
        const target = event.target instanceof Element ? event.target : null;
        const trigger = target?.closest('[data-inline-calendar-field]');
        if (!trigger) return;
        if (event.key !== 'Enter' && event.key !== ' ') return;
        if (shouldIgnoreInlineActivationKeydown(target, trigger)) return;
        event.preventDefault();
        startCalendarDetailInlineEdit(trigger).catch((error) => console.error('calendar inline edit', error));
      });
    }

    async function persistCalendarDetailInlineField(itemId, field, rawValue, options = {}) {
      const id = String(itemId || '').trim();
      if (!id) return null;
      const normalizedValue = normalizeCalendarDetailInlineFieldValue(field, rawValue);
      const saveKey = `${id}::${field}`;
      const signature = `${field}::${normalizedValue}`;
      if (!options.force && calendarDetailInlineLastSavedValues.get(saveKey) === signature) return normalizedValue;
      if (!(await ensureCalendarDetailInlineLock(id))) return normalizedValue;
      const existing = currentCalendarInfoDetailItem || await getDecrypted('globalCalendarItems', id, 'id');
      if (!existing) return normalizedValue;
      const updated = { ...existing, updatedAt: Date.now() };
      if (field === 'description') updated.notes = normalizedValue;
      else if (field === 'date') {
        updated.date = normalizedValue;
        updated.startDate = normalizedValue;
        updated.endDate = normalizedValue;
      }
      else updated[field] = normalizedValue;
      await putEncrypted('globalCalendarItems', updated, 'id');
      currentCalendarInfoDetailItem = updated;
      calendarDetailInlineLastSavedValues.set(saveKey, signature);
      return normalizedValue;
    }

    async function scheduleCalendarDetailInlineSave(field, rawValue, options = {}) {
      const id = String(currentCalendarInfoDetailId || '').trim();
      if (!id) return;
      const debounceDelay = options.immediate ? 0 : 220;
      if (calendarDetailInlineDebounceTimers.has(field)) {
        clearTimeout(calendarDetailInlineDebounceTimers.get(field));
      }
      calendarDetailInlineDebounceTimers.set(field, setTimeout(() => {
        setInlineSaveIndicator('calendar-detail', 'saving');
        runWithoutGlobalLoading(() => persistCalendarDetailInlineField(id, field, rawValue))
          .then(() => setInlineSaveIndicator('calendar-detail', 'saved'))
          .catch((error) => {
            setInlineSaveIndicator('calendar-detail', 'error');
            console.error('calendar inline save failed', error);
          });
      }, debounceDelay));
      if (calendarDetailInlineFinalizeTimers.has(field)) {
        clearTimeout(calendarDetailInlineFinalizeTimers.get(field));
      }
      calendarDetailInlineFinalizeTimers.set(field, setTimeout(() => {
        setInlineSaveIndicator('calendar-detail', 'saving');
        runWithoutGlobalLoading(() => persistCalendarDetailInlineField(id, field, rawValue, { force: true }))
          .then(() => setInlineSaveIndicator('calendar-detail', 'saved'))
          .catch((error) => {
            setInlineSaveIndicator('calendar-detail', 'error');
            console.error('calendar inline finalize save failed', error);
          });
      }, 900));
    }

    function buildCalendarDetailInlineEditor(field, value) {
      if (field === 'description') {
        const input = document.createElement('textarea');
        input.rows = 5;
        input.className = 'task-detail-inline-input task-detail-inline-textarea';
        input.value = value || '';
        input.placeholder = 'Saisissez une description';
        return input;
      }
      if (field === 'date') {
        const input = document.createElement('input');
        input.type = 'date';
        input.className = 'task-detail-inline-input';
        input.value = value || '';
        return input;
      }
      if (field === 'sharingMode') {
        const select = document.createElement('select');
        select.className = 'task-detail-inline-input task-detail-inline-select';
        [['private', 'Privée'], ['shared', 'Collaborative']].forEach(([v, l]) => {
          const opt = document.createElement('option');
          opt.value = v;
          opt.textContent = l;
          if (v === value) opt.selected = true;
          select.appendChild(opt);
        });
        return select;
      }
      const input = document.createElement('input');
      input.type = 'text';
      input.className = 'task-detail-inline-input';
      input.value = value || '';
      return input;
    }

    async function startCalendarDetailInlineEdit(triggerEl) {
      if (!currentCalendarInfoDetailCanEdit || !triggerEl) return;
      const field = String(triggerEl.dataset.inlineCalendarField || '').trim();
      if (!field || triggerEl.dataset.inlineEditing === '1') return;
      const id = String(currentCalendarInfoDetailId || '').trim();
      if (!id) return;
      const source = currentCalendarInfoDetailItem || await getDecrypted('globalCalendarItems', id, 'id');
      if (!source) return;
      const startValue = normalizeCalendarDetailInlineFieldValue(field, field === 'description' ? source.notes : source[field]);
      const resolvedStartValue = field === 'date'
        ? normalizeCalendarDetailInlineFieldValue('date', source.startDate || source.date || '')
        : startValue;
      triggerEl.dataset.inlineEditing = '1';
      triggerEl.classList.add('is-inline-editing');
      triggerEl.innerHTML = '';
      const wrap = document.createElement('span');
      wrap.className = 'task-detail-inline-editor-wrap task-detail-inline-block';
      const editor = buildCalendarDetailInlineEditor(field, resolvedStartValue);
      wrap.appendChild(editor);
      triggerEl.appendChild(wrap);

      let done = false;
      const finish = async (nextRawValue, commit) => {
        if (done) return;
        done = true;
        const nextValue = normalizeCalendarDetailInlineFieldValue(field, nextRawValue);
        triggerEl.dataset.inlineEditing = '0';
        triggerEl.classList.remove('is-inline-editing');
        if (commit) {
          currentCalendarInfoDetailItem = {
            ...(currentCalendarInfoDetailItem || {}),
            ...(field === 'description' ? { notes: nextValue } : { [field]: nextValue })
          };
          await scheduleCalendarDetailInlineSave(field, nextValue, { immediate: true });
          refreshCalendarDetailInlineDisplay(field, nextValue);
          await renderGlobalCalendar();
        } else {
          refreshCalendarDetailInlineDisplay(field, field === 'description' ? source.notes : source[field]);
        }
      };

      editor.addEventListener('input', async () => {
        const nextValue = editor.value;
        currentCalendarInfoDetailItem = {
          ...(currentCalendarInfoDetailItem || source),
          ...(field === 'description'
            ? { notes: normalizeCalendarDetailInlineFieldValue(field, nextValue) }
            : { [field]: normalizeCalendarDetailInlineFieldValue(field, nextValue) })
        };
        await scheduleCalendarDetailInlineSave(field, nextValue);
      });
      editor.addEventListener('blur', async () => {
        await finish(editor.value, true);
      });
      editor.addEventListener('keydown', async (event) => {
        if (event.key === 'Escape') {
          event.preventDefault();
          await finish(field === 'description' ? source.notes : source[field], false);
          return;
        }
        if (event.key === 'Enter' && field !== 'description') {
          event.preventDefault();
          editor.blur();
        }
      });

      requestAnimationFrame(() => {
        editor.focus();
        if (typeof editor.select === 'function' && field !== 'sharingMode') editor.select();
      });
    }

    async function openStandaloneCalendarDetails(itemId) {
      const id = String(itemId || '').trim();
      if (!id) return;
      const item = await getDecrypted('globalCalendarItems', id, 'id');
      if (!item || item.archivedAt) {
        showToast('Information introuvable');
        return;
      }

      currentCalendarInfoDetailId = id;
      currentCalendarInfoDetailItem = { ...item };
      const modal = document.getElementById('modal-calendar-info-details');
      const titleEl = document.getElementById('calendar-info-detail-title');
      const subtitleEl = document.getElementById('calendar-info-detail-subtitle');
      const badgesEl = document.getElementById('calendar-info-detail-badges');
      const descriptionEl = document.getElementById('calendar-info-detail-description');
      const dateEl = document.getElementById('calendar-info-detail-date');
      const themeEl = document.getElementById('calendar-info-detail-theme');
      if (!modal || !titleEl || !subtitleEl || !badgesEl || !descriptionEl || !dateEl || !themeEl) return;

      titleEl.textContent = item.title || 'Information';
      subtitleEl.textContent = `Hors projet • ${item.theme || 'General'}`;
      descriptionEl.textContent = item.notes || 'Aucune description.';
      dateEl.textContent = buildCalendarItemDateLabel(item);
      themeEl.textContent = item.theme || 'General';
      badgesEl.innerHTML = `
        <span id="calendar-info-detail-type-chip" class="inline-flex text-[10px] px-2 py-1 rounded-full calendar-chip-info font-semibold">Info hors projet</span>
        <span id="calendar-info-detail-sharing-chip" class="inline-flex text-[10px] px-2 py-1 rounded-full font-semibold ${normalizeSharingMode(item.sharingMode, 'private') === 'shared' ? 'calendar-chip-shared' : 'calendar-chip-private'}">${normalizeSharingMode(item.sharingMode, 'private') === 'shared' ? 'Collaborative' : 'Privée'}</span>
      `;
      initCalendarDetailInlineEditing(true);
      refreshCalendarDetailInlineDisplay('title', item.title || '');
      refreshCalendarDetailInlineDisplay('description', item.notes || '');
      refreshCalendarDetailInlineDisplay('date', item.startDate || item.date || '');
      refreshCalendarDetailInlineDisplay('theme', item.theme || 'General');
      refreshCalendarDetailInlineDisplay('sharingMode', normalizeSharingMode(item.sharingMode, 'private'));
      modal.classList.remove('hidden');
    }

    async function closeStandaloneCalendarDetails() {
      for (const timer of calendarDetailInlineDebounceTimers.values()) clearTimeout(timer);
      for (const timer of calendarDetailInlineFinalizeTimers.values()) clearTimeout(timer);
      calendarDetailInlineDebounceTimers.clear();
      calendarDetailInlineFinalizeTimers.clear();
      if (activeCalendarEditLock?.itemId && String(activeCalendarEditLock.itemId) === String(currentCalendarInfoDetailId || '')) {
        await releaseCalendarItemLock(activeCalendarEditLock.itemId, activeCalendarEditLock.lockId || '');
        activeCalendarEditLock = null;
      }
      currentCalendarInfoDetailId = null;
      currentCalendarInfoDetailItem = null;
      document.getElementById('modal-calendar-info-details')?.classList.add('hidden');
    }

